-- Poems batch 23
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3eff07af-a1f2-4f18-8005-6e52e199feaf','送毛仙翁','白居易','唐','唐诗','tang','','[]','仙翁已得道，混迹尋巖泉。',288,'全唐诗/poet.tang.24000.json','["仙翁已得道，混迹尋巖泉。", "肌膚冰雪瑩，衣服雲霞鮮。", "紺髮絲竝緻，齠容花共妍。", "方瞳點玄漆，高步凌非煙。", "幾見桑海變，莫知龜鶴年。", "所憩九清外，所遊五嶽巔。", "軒昊舊爲侶，松喬難比肩。", "每嗟人世人，役役如狂顛。", "孰能脫羈鞅，盡遭名利牽。", "貌隨歲律換，神逐光陰遷。", "惟余負憂譴，顦顇湓江壖。", "衰鬢忽霜白，愁腸如火煎。", "羈旅坐多感，裴回私自憐。", "晴眺五老峰，玉洞多神仙。", "何當憫湮厄，授道安虛孱。", "我師惠然來，論道窮重玄。", "浩蕩八溟闊，志泰心超然。", "形骸既無束，得喪亦都捐。", "豈識椿菌異，那知鵬鷃懸。", "丹華既相付，促景定當延。", "玄功曷可報，感極惟勤拳。", "霓旌不肯駐，又歸武夷川。", "語罷倏然別，孤鶴升遙天。", "賦詩敘明德，永續步虛篇。"]'),
('c1c23701-e5b9-4d09-8f7b-8cbf63fd6bef','達哉樂天行','白居易','唐','唐诗','tang','','[]','達哉達哉白樂天，分司東都十三年。',224,'全唐诗/poet.tang.24000.json','["達哉達哉白樂天，分司東都十三年。", "七旬纔滿冠已挂，半祿未及車先懸。", "或伴遊客春行樂，或隨山僧夜坐禪。", "二年忘却問家事，門庭多草廚少煙。", "庖童朝告鹽米盡，侍婢暮訴衣裳穿。", "妻孥不悅甥姪悶，而我醉臥方陶然。", "起來與爾畫生計，薄產處置有後先。", "先賣南坊十畝園，次賣東都五頃田。", "然後兼賣所居宅，髣髴獲緡二三千。", "半與爾充衣食費，半與吾供酒肉錢。", "吾今已年七十一，眼昏鬚白頭風眩。", "但恐此錢用不盡，即先朝露歸夜泉。", "未歸且住亦不惡，飢餐樂飲安穩眠。", "死生無可無不可，達哉達哉白樂天。"]'),
('ae6e6ceb-d1ef-4306-b28c-77bb13bc09c3','春池閑泛','白居易','唐','唐诗','tang','','[]','綠塘新水平，紅檻小舟輕。',120,'全唐诗/poet.tang.24000.json','["綠塘新水平，紅檻小舟輕。", "解纜隨風去，開襟信意行。", "淺憐清演漾，深愛綠澄泓。", "白撲柳飛絮，紅浮桃落英。", "古文科斗出，新葉剪刀生。", "樹集鶯朋友，雲行雁弟兄。", "飛沈皆適性，酣詠自怡情。", "花助銀杯氣，松添玉軫聲。", "魚跳何事樂，鷗起復誰驚。", "莫唱滄浪曲，無塵可濯纓。"]'),
('08fd04f7-03bc-494c-8133-e2b2fccb8a86','池上寓興二絕 一','白居易','唐','唐诗','tang','','[]','濠梁莊惠謾相爭，未必人情知物情。',32,'全唐诗/poet.tang.24000.json','["濠梁莊惠謾相爭，未必人情知物情。", "獺捕魚來魚躍出，此非魚樂是魚驚。"]'),
('42c58b14-e19a-4a38-8c1f-164c7548cbf0','池上寓興二絕 二','白居易','唐','唐诗','tang','','[]','水淺魚稀白鷺飢，勞心瞪目待魚時。',32,'全唐诗/poet.tang.24000.json','["水淺魚稀白鷺飢，勞心瞪目待魚時。", "外容閑暇中心苦，似是而非誰得知。"]'),
('1e49ae42-d9be-46b1-bfc7-340d8c269f9b','宴後題府中水堂贈盧尹中丞','白居易','唐','唐诗','tang','','[]','水齋歲久漸荒蕪，自媿甘棠無一株。',64,'全唐诗/poet.tang.24000.json','["水齋歲久漸荒蕪，自媿甘棠無一株。", "新酒客來方宴飲，舊堂主在重歡娛。", "莫言楊柳枝空老，直致櫻桃樹已枯。", "從我到君十一尹，相看自置府來無。"]'),
('0179364d-9f50-4a11-92c5-50930a2ab52b','和敏中洛下即事','白居易','唐','唐诗','tang','','[]','昨日池塘春草生，阿連新有好詩成。',64,'全唐诗/poet.tang.24000.json','["昨日池塘春草生，阿連新有好詩成。", "花園到處鶯呼入，驄馬遊時客避行。", "水暖魚多似南國，人稀塵少勝西京。", "洛中佳境應無限，若欲諳知問老兄。"]'),
('f0749174-6ec1-4175-8575-1a3024d7b7e3','送敏中新授戶部員外郎西歸','白居易','唐','唐诗','tang','','[]','千里歸程三伏天，官新身健馬翩翩。',64,'全唐诗/poet.tang.24000.json','["千里歸程三伏天，官新身健馬翩翩。", "行衝赤日加餐飯，上到青雲穩著鞭。", "長慶老郎唯我在，客曹故事望君傳。", "前鴻後雁行難續，相去迢迢二十年。"]'),
('f4865055-1a2e-4f5f-941b-f95be331fbbe','南侍御以石相贈助成水聲因以絕句謝之','白居易','唐','唐诗','tang','','[]','泉石磷磷聲似琴，閑眠靜聽洗塵心。',32,'全唐诗/poet.tang.24000.json','["泉石磷磷聲似琴，閑眠靜聽洗塵心。", "莫輕兩片青苔石，一夜潺湲直萬金。"]'),
('082a6c37-0bac-4c30-a5da-f6a849405a35','閑居自題戲招宿客','白居易','唐','唐诗','tang','','[]','水畔竹林邊，閑居二十年。',96,'全唐诗/poet.tang.24000.json','["水畔竹林邊，閑居二十年。", "健常攜酒出，病即掩門眠。", "解綬收朝佩，褰裳出野船。", "屏除身外物，擺落世間緣。", "報曙窗何早，知秋簟最先。", "微風深樹裏，斜日小樓前。", "渠口添新石，籬根寫亂泉。", "欲招同宿客，誰解愛潺湲。"]'),
('ac8f48dc-3249-4f31-8129-46c3a5d2aaae','李留守相公見過池上汎舟舉酒話及翰林舊事因成四韻以獻之','白居易','唐','唐诗','tang','','[]','引櫂尋池岸，移尊就菊叢。',48,'全唐诗/poet.tang.24000.json','["引櫂尋池岸，移尊就菊叢。", "何言濟川後，相訪釣船中。", "白首故情在，青雲往事空。", "同時六學士，五相一漁翁。"]'),
('5120b00c-fa68-4462-898d-c07ac6667d5a','閏九月九日獨飲','白居易','唐','唐诗','tang','','[]','黃花叢畔綠尊前，猶有些些舊管弦。',48,'全唐诗/poet.tang.24000.json','["黃花叢畔綠尊前，猶有些些舊管弦。", "偶遇閏秋重九日，東籬獨酌一陶然。", "自從九月持齋戒，不醉重陽十五年。"]'),
('4f775eba-91d7-488a-9bb4-262b7c0d4ff9','覽盧子蒙侍御舊詩多與微之唱和感今傷昔因贈子蒙題於卷後','白居易','唐','唐诗','tang','','[]','早聞元九詠君詩，恨與盧君相識遲。',64,'全唐诗/poet.tang.24000.json','["早聞元九詠君詩，恨與盧君相識遲。", "今日逢君開舊卷，卷中多道贈微之。", "相看掩淚情難說，別有傷心事豈知。", "聞道咸陽墳上樹，已抽三丈白楊枝。"]'),
('88a9358c-97e9-4b26-8544-1c8d7a4d95f4','寒亭留客','白居易','唐','唐诗','tang','','[]','今朝閑坐石亭中，爐火銷殘尊又空。',32,'全唐诗/poet.tang.24000.json','["今朝閑坐石亭中，爐火銷殘尊又空。", "冷落若爲留客住，冰池霜竹雪髯翁。"]'),
('33efe50e-e3d2-415a-ae26-40693e54effb','新小灘','白居易','唐','唐诗','tang','','[]','石淺沙平流水寒，水邊斜插一漁竿。',32,'全唐诗/poet.tang.24000.json','["石淺沙平流水寒，水邊斜插一漁竿。", "江南客見生鄉思，道似嚴陵七里灘。"]'),
('20d29545-881f-4df1-8b8c-68c0e53cba63','和李中丞與李給事山居雪夜同宿小酌','白居易','唐','唐诗','tang','','[]','憲府觸邪峩豸角，璅闈駮正犯龍鱗。',64,'全唐诗/poet.tang.24000.json','["憲府觸邪峩豸角，璅闈駮正犯龍鱗。", "那知近地齋居客，忽作深山同宿人。", "一醆寒燈雲外夜，數杯溫酎雪中春。", "林泉莫作多時計，諫獵登封憶舊臣。"]'),
('794aee47-3485-404b-937d-4fe645e25ecc','履道西門二首 一','白居易','唐','唐诗','tang','','[]','履道西門有弊居，池塘竹樹遶君廬。',64,'全唐诗/poet.tang.24000.json','["履道西門有弊居，池塘竹樹遶君廬。", "豪華肥壯雖無分，飽暖安閑即有餘。", "行竈朝香炊早飯，小園春暖掇新蔬。", "夷齊黃綺誇芝蕨，比我盤飧恐不如。"]'),
('2d132492-db5a-4180-9f63-7a1b1aae530b','履道西門二首 二','白居易','唐','唐诗','tang','','[]','履道西門獨掩扉，官休病退客來稀。',64,'全唐诗/poet.tang.24000.json','["履道西門獨掩扉，官休病退客來稀。", "亦知軒冕榮堪戀，其奈田園老合歸。", "跛鼈難隨騏驥足，傷禽莫趁鳳凰飛。", "世間認得身人少，今我雖愚亦庶幾。"]'),
('e8192802-0b10-454a-b2de-cd02f77da156','偶吟','白居易','唐','唐诗','tang','','[]','人生變改故無窮，昔是朝官今野翁。',64,'全唐诗/poet.tang.24000.json','["人生變改故無窮，昔是朝官今野翁。", "久寄形於朱紫內，漸抽身入蕙荷中。", "無情水任方圓器，不繫舟隨去住風。", "猶有鱸魚蓴菜興，來春或擬往江東。"]'),
('6152c59d-4395-44a2-bd16-dc41ae592ec6','雪夜小飲贈夢得','白居易','唐','唐诗','tang','','["\u53d9\u4e8b", "\u5199\u96ea", "\u96ea", "\u996e\u9152"]','同爲懶慢園林客，共對蕭條雨雪天。',64,'全唐诗/poet.tang.24000.json','["同爲懶慢園林客，共對蕭條雨雪天。", "小酌酒巡銷永夜，大開口笑送殘年。", "久將時背成遺老，多被人呼作散仙。", "呼作散仙應有以，曾看東海變桑田。"]'),
('8928077e-9d75-4c1f-8c74-37a87129a364','歲暮夜長病中燈下聞盧尹夜宴以詩戲之且爲來日張本也','白居易','唐','唐诗','tang','','[]','榮鬧興多嫌晝短，衰閑睡少覺明遲。',64,'全唐诗/poet.tang.24000.json','["榮鬧興多嫌晝短，衰閑睡少覺明遲。", "當君秉燭銜杯夜，是我停飱服藥時。", "枕上愁吟堪發病，府中歡笑勝尋醫。", "明朝強出須謀樂，不擬車公更擬誰。"]'),
('c5a3f084-0ca8-4261-ae65-6a94e416c149','病中數會張道士見譏以此荅之','白居易','唐','唐诗','tang','','[]','亦知數出妨將息，不可端居守寂寥。',66,'全唐诗/poet.tang.24000.json','["亦知數出妨將息，不可端居守寂寥。", "病即藥窗眠盡日，興來酒席坐通宵。", "賢人易狎須勤飲，姹女難禁莫慢燒。", "張道士輸白道士，一杯沆[瀣]便逍遙。"]'),
('c2877437-d920-462c-83f6-0dadfd75ddb4','卯飲','白居易','唐','唐诗','tang','','[]','短屏風掩臥牀頭，烏帽青氈白氎裘。',32,'全唐诗/poet.tang.24000.json','["短屏風掩臥牀頭，烏帽青氈白氎裘。", "卯飲一杯眠一覺，世間何事不悠悠。"]'),
('5d8ad939-d581-4971-83b3-160b1486a2b5','寄題餘杭郡樓兼呈裴使君','白居易','唐','唐诗','tang','','["\u897f\u6e56"]','官歷二十政，宦遊三十秋。',72,'全唐诗/poet.tang.24000.json','["官歷二十政，宦遊三十秋。", "江山與風月，最憶是杭州。", "北郭沙堤尾，西湖石岸頭。", "綠觴春送客，紅燭夜迴舟。", "不敢言遺愛，空知念舊遊。", "憑君吟此句，題向望濤樓。"]'),
('a7850e71-638c-44b5-afb9-20711128689a','楊六尚書留太湖石在洛下借置庭中因對舉杯寄贈絕句','白居易','唐','唐诗','tang','','["\u592a\u6e56"]','借君片石意何如，置向庭中慰索居。',32,'全唐诗/poet.tang.24000.json','["借君片石意何如，置向庭中慰索居。", "每就玉山傾一酌，興來如對醉尚書。"]'),
('82df3c38-2c9c-4f49-8b15-eadee48768b0','喜入新年自詠','白居易','唐','唐诗','tang','','[]','白鬚如雪五朝臣，又值新正第七旬。',64,'全唐诗/poet.tang.24000.json','["白鬚如雪五朝臣，又值新正第七旬。", "老過占他藍尾酒，病餘收得到頭身。", "銷磨歲月成高位，比類時流是幸人。", "大曆年中騎竹馬，幾人得見會昌春。"]'),
('6a3040d4-3a16-42cb-b6e7-4e0c3787690e','灘聲','白居易','唐','唐诗','tang','','[]','碧玉班班沙歷歷，清流決決響泠泠。',32,'全唐诗/poet.tang.24000.json','["碧玉班班沙歷歷，清流決決響泠泠。", "自從造得灘聲後，玉管朱弦可要聽。"]'),
('6998855b-5b00-4420-a682-18d61b593a66','題石泉','白居易','唐','唐诗','tang','','[]','殷勤傍石遶泉行，不說何人知我情。',32,'全唐诗/poet.tang.24000.json','["殷勤傍石遶泉行，不說何人知我情。", "漸恐耳聾兼眼闇，聽泉看石不分明。"]'),
('158c5988-604e-43c9-bcc3-e589ac79fe74','送王卿使君赴任蘇州因思花迎新使感舊遊寄題郡中木蘭西院一別','白居易','唐','唐诗','tang','','[]','一別蘇州十八載，時光人事隨年改。',64,'全唐诗/poet.tang.24000.json','["一別蘇州十八載，時光人事隨年改。", "不論竹馬盡成人，亦恐桑田半爲海。", "鶯入故宮含意思，花迎新使生光彩。", "爲報江山風月知，至今白使君猶在。"]'),
('aba83d2f-f177-4102-8284-803165ebba9a','出齋日喜皇甫十早訪','白居易','唐','唐诗','tang','','[]','三旬齋滿欲銜杯，平旦敲門門未開。',32,'全唐诗/poet.tang.24000.json','["三旬齋滿欲銜杯，平旦敲門門未開。", "除却朗之攜一榼，的應不是別人來。"]'),
('2304b84e-e4a1-40df-ab81-71ff5afeab7d','會昌二年春題池西小樓','白居易','唐','唐诗','tang','','[]','花邊春水水邊樓，一坐經今四十秋。',96,'全唐诗/poet.tang.24000.json','["花邊春水水邊樓，一坐經今四十秋。", "望月橋傾三遍換，採蓮船破五迴修。", "園林一半成喬木，鄰里三分作白頭。", "蘇李冥蒙隨燭滅，陳樊漂泊逐萍流。", "雖貧眼下無妨樂，縱病心中不與愁。", "自笑靈光巋然在，春來遊得且須遊。"]'),
('93e0804c-e811-4f25-85d4-d97476cf82b8','酬南洛陽早春見贈','白居易','唐','唐诗','tang','','[]','物華春意尚遲迴，賴有東風晝夜催。',64,'全唐诗/poet.tang.24000.json','["物華春意尚遲迴，賴有東風晝夜催。", "寒縋柳腰收未得，暖熏花口噤初開。", "欲披雲霧聯襟去，先喜瓊琚入袖來。", "久病長齋詩老退，爭禁年少洛陽才。"]'),
('e9e2a973-4bbe-442e-af19-035a46724a81','對新家醖翫自種花','白居易','唐','唐诗','tang','','[]','香麴親看造，芳叢手自栽。',72,'全唐诗/poet.tang.24000.json','["香麴親看造，芳叢手自栽。", "迎春報酒熟，垂老看花開。", "紅蠟半含萼，綠油新醱醅。", "玲瓏五六樹，瀲灩兩三杯。", "恐有狂風起，愁無好客來。", "獨酣還獨語，待取月明迴。"]'),
('e1b3436d-e795-4402-b9a7-e0c379194558','攜酒往朗之莊居同飲','白居易','唐','唐诗','tang','','[]','慵中又少經過處，別後都無勸酒人。',32,'全唐诗/poet.tang.24000.json','["慵中又少經過處，別後都無勸酒人。", "不挈一壺相就醉，若爲將老度殘春。"]'),
('685acda4-7696-4bf9-b447-d44243fb3beb','以詩代書酬慕巢尚書見寄','白居易','唐','唐诗','tang','','[]','書意詩情不偶然，苦云夢想在林泉。',64,'全唐诗/poet.tang.24000.json','["書意詩情不偶然，苦云夢想在林泉。", "願爲愚谷煙霞侶，思結空門香火緣。", "每媿尚書情眷眷，自憐居士病綿綿。", "不知待得心期否，老挍於君六七年。"]'),
('3a6762be-e8e3-4efb-891f-aa24a781036e','春盡日','白居易','唐','唐诗','tang','','[]','芳景銷殘暑氣生，感時思事坐含情。',64,'全唐诗/poet.tang.24000.json','["芳景銷殘暑氣生，感時思事坐含情。", "無人開口共誰語，有酒迴頭還自傾。", "醉對數叢紅芍藥，渴嘗一盌綠昌明。", "春歸似遣鶯留語，好住園林三兩聲。"]'),
('188d655e-92f3-4f2a-8117-ae0509bb6913','招山僧','白居易','唐','唐诗','tang','','[]','能入城中乞食否，莫辭塵土汚袈裟。',32,'全唐诗/poet.tang.24000.json','["能入城中乞食否，莫辭塵土汚袈裟。", "欲知住處東城下，遶竹泉聲是白家。"]'),
('94e8cf97-5869-49d3-abf4-17203db5ff9c','夏日與閑禪師林下避暑','白居易','唐','唐诗','tang','','[]','洛景城西塵土紅，伴僧閑坐竹泉東。',64,'全唐诗/poet.tang.24000.json','["洛景城西塵土紅，伴僧閑坐竹泉東。", "綠蘿潭上不見日，白石灘邊長有風。", "熱惱漸知隨念盡，清涼常願與人同。", "每因毒暑悲親故，多在炎方瘴海中。"]'),
('8e332be3-de5c-40ec-99e0-8e5338727888','題新澗亭兼酬寄朝中親故見贈','白居易','唐','唐诗','tang','','[]','何處披襟風快哉，一亭臨澗四門開。',64,'全唐诗/poet.tang.24000.json','["何處披襟風快哉，一亭臨澗四門開。", "金章紫綬辭腰去，白石清泉就眼來。", "自得所宜還獨樂，各行其志莫相咍。", "禽魚出得池籠後，縱有人呼可更迴。"]'),
('c93da7da-b27e-4303-9fe3-76fcf2d5bebc','病中看經贈諸道侶','白居易','唐','唐诗','tang','','[]','右眼昏花左足風，金箆石水用無功。',64,'全唐诗/poet.tang.24000.json','["右眼昏花左足風，金箆石水用無功。", "不如迴念三乘樂，便得浮生百病空。", "無子同居草庵下，有妻偕老道塲中。", "何煩更請僧爲侶，月上新歸伴病翁。"]'),
('8097d5e2-11b7-460c-92bd-415035fe753c','遊豐樂招提佛光三寺','白居易','唐','唐诗','tang','','[]','竹鞋葵扇白綃巾，林野爲家雲是身。',64,'全唐诗/poet.tang.24000.json','["竹鞋葵扇白綃巾，林野爲家雲是身。", "山寺每遊多寄宿，都城暫出即經旬。", "漢容黃綺爲逋客，堯放巢由作外臣。", "昨日制書臨郡縣，不該愚谷醉鄉人。"]'),
('2f09ea8f-507a-4dcf-ad70-d53af9c71a37','醉中得上都親友書以予停俸多時憂問貧乏偶乘酒興詠而報之','白居易','唐','唐诗','tang','','[]','頭白醉昏昏，狂歌秋復春。',120,'全唐诗/poet.tang.24000.json','["頭白醉昏昏，狂歌秋復春。", "一生躭酒客，五度棄官人。", "異世陶元亮，前生劉伯倫。", "臥將琴作枕，行以鍤隨身。", "歲要衣三對，年支穀一囷。", "園葵烹佐飯，林葉掃添薪。", "沒齒甘蔬食，搖頭謝縉紳。", "自能拋爵祿，終不惱交親。", "但得杯中淥，從生甑上塵。", "煩君問生計，憂醒不憂貧。"]'),
('f0cb09d2-3358-44e5-be2e-726af69ef62a','池畔逐涼','白居易','唐','唐诗','tang','','[]','風清泉冷竹修修，三伏炎天涼似秋。',64,'全唐诗/poet.tang.24000.json','["風清泉冷竹修修，三伏炎天涼似秋。", "黃犬引迎騎馬客，青衣扶下釣魚舟。", "衰容自覺宜閑坐，蹇步誰能更遠遊。", "料得此身終老處，只應林下與灘頭。"]'),
('4d3fe026-11a9-4d6b-9bf3-bbe49276b374','池鶴八絕句 雞贈鶴','白居易','唐','唐诗','tang','','[]','一聲警露君能薄，五德司晨我用多。',32,'全唐诗/poet.tang.24000.json','["一聲警露君能薄，五德司晨我用多。", "不會悠悠時俗士，重君輕我意如何。"]'),
('0999cda8-ebab-4382-a8c7-c49af103fecc','池鶴八絕句 鶴荅雞','白居易','唐','唐诗','tang','','[]','爾爭伉儷泥中鬬，吾整羽儀松上栖。',32,'全唐诗/poet.tang.24000.json','["爾爭伉儷泥中鬬，吾整羽儀松上栖。", "不可遣他天下眼，却輕野鶴重家雞。"]'),
('b711aeea-80d7-49a6-9e92-d1b89d5ce540','池鶴八絕句 烏贈鶴','白居易','唐','唐诗','tang','','[]','與君白黑大分明，縱不相親莫見輕。',32,'全唐诗/poet.tang.24000.json','["與君白黑大分明，縱不相親莫見輕。", "我每夜啼君怨別，玉徽琴裏忝同聲。"]'),
('44a01b43-d5b8-456e-89b2-90bd3d18e949','池鶴八絕句 鶴荅烏','白居易','唐','唐诗','tang','','[]','吾愛栖雲上華表，汝多攫肉下田中。',32,'全唐诗/poet.tang.24000.json','["吾愛栖雲上華表，汝多攫肉下田中。", "吾音中羽汝聲角，琴曲雖同調不同。"]'),
('24b60be4-d7e7-4e75-b28f-bed4ebc4ae08','池鶴八絕句 鳶贈鶴','白居易','唐','唐诗','tang','','[]','君誇名鶴我名鳶，君呌聞天我戾天。',32,'全唐诗/poet.tang.24000.json','["君誇名鶴我名鳶，君呌聞天我戾天。", "更有與君相似處，飢來一種啄腥羶。"]'),
('ee844dd0-3101-4d63-b000-22d5d1b6e1de','池鶴八絕句 鶴荅鳶','白居易','唐','唐诗','tang','','[]','無妨自是莫相非，清濁高低各有歸。',32,'全唐诗/poet.tang.24000.json','["無妨自是莫相非，清濁高低各有歸。", "鸞鶴羣中彩雲裏，幾時曾見喘鳶飛。"]'),
('bf4eeb15-a82e-4f15-836a-5729e0ee8834','池鶴八絕句 鵝贈鶴','白居易','唐','唐诗','tang','','["\u52b1\u5fd7", "\u52a8\u7269"]','君因風送入青雲，我被人驅向鴨羣。',32,'全唐诗/poet.tang.24000.json','["君因風送入青雲，我被人驅向鴨羣。", "雪頸霜毛紅網掌，請看何處不如君。"]'),
('bc31168d-7b68-49f1-9ac0-a0dcaa1c2308','池鶴八絕句 鶴荅鵝','白居易','唐','唐诗','tang','','[]','右軍歿後欲何依，只合隨雞逐鴨飛。',32,'全唐诗/poet.tang.24000.json','["右軍歿後欲何依，只合隨雞逐鴨飛。", "未必犧牲及吾輩，大都我瘦勝君肥。"]'),
('094a6992-bb68-40ae-b6f8-3460a32612cd','談氏小外孫玉童','白居易','唐','唐诗','tang','','[]','外翁七十孫三歲，笑指琴書欲遣傳。',64,'全唐诗/poet.tang.24000.json','["外翁七十孫三歲，笑指琴書欲遣傳。", "自念老夫今耄矣，因思稚子更茫然。", "中郎餘慶鍾羊祜，子幼能文似馬遷。", "才與不才爭料得，東牀空後且嬌憐。"]'),
('ea60b4c2-f2f4-42b6-8f84-197a061aec66','送後集往廬山東林寺兼寄雲臯上人','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','後集寄將何處去，故山迢遞在匡廬。',64,'全唐诗/poet.tang.24000.json','["後集寄將何處去，故山迢遞在匡廬。", "舊僧獨有雲臯在，三二年來不得書。", "別後道情添幾許，老來筋力又何如。", "來生緣會應非遠，彼此年過七十餘。"]'),
('d15fcaaf-1af2-419d-ae5f-47b7ff296266','客有說','白居易','唐','唐诗','tang','','[]','近有人從海上迴，海山深處見樓臺。',32,'全唐诗/poet.tang.24000.json','["近有人從海上迴，海山深處見樓臺。", "中有仙龕虛一室，多傳此待樂天來。"]'),
('6da1f1f2-06c1-4f74-8e64-8cf2b9bcb40d','荅客說','白居易','唐','唐诗','tang','','[]','吾學空門非學仙，恐君此說是虛傳。',32,'全唐诗/poet.tang.24000.json','["吾學空門非學仙，恐君此說是虛傳。", "海山不是吾歸處，歸即應歸兜率天。"]'),
('bdfa7bac-a4b3-47d1-948c-9cd209a10415','哭劉尚書夢得二首 一','白居易','唐','唐诗','tang','','[]','四海齊名白與劉，百年交分兩綢繆。',64,'全唐诗/poet.tang.24000.json','["四海齊名白與劉，百年交分兩綢繆。", "同貧同病退閑日，一死一生臨老頭。", "杯酒英雄君與操，文章微婉我知丘。", "賢豪雖歿精靈在，應共微之地下遊。"]'),
('6f4ff067-5d18-45a9-9212-f1cff9b73ea8','哭劉尚書夢得二首 二','白居易','唐','唐诗','tang','','[]','今日哭君吾道孤，寢門淚滿白髭鬚。',64,'全唐诗/poet.tang.24000.json','["今日哭君吾道孤，寢門淚滿白髭鬚。", "不知箭折弓何用，兼恐脣亡齒亦枯。", "窅窅窮泉埋寶玉，駸駸落景挂桑榆。", "夜臺暮齒期非遠，但問前頭相見無。"]'),
('65f08c95-dbff-4fb9-89ef-0a16df2bf340','昨日復今辰','白居易','唐','唐诗','tang','','[]','昨日復今辰，悠悠七十春。',72,'全唐诗/poet.tang.24000.json','["昨日復今辰，悠悠七十春。", "所經多故處，却想似前身。", "散秩優游老，閑居淨潔貧。", "螺杯中有物，鶴氅上無塵。", "解佩收朝帶，抽簪換野巾。", "風儀與名號，別是一生人。"]'),
('80f61fc5-a49d-47fa-9e6d-e0ec3ebe031d','病瘡','白居易','唐','唐诗','tang','','[]','門有醫來往，庭無客送迎。',48,'全唐诗/poet.tang.24000.json','["門有醫來往，庭無客送迎。", "病銷談笑興，老足歎嗟聲。", "鶴伴臨池立，人扶下砌行。", "脚瘡春斷酒，那得有心情。"]'),
('478242d8-75dd-4b83-8fc3-a98d98028d8e','遊趙村杏花','白居易','唐','唐诗','tang','','[]','趙村紅杏每年開，十五年來看幾迴。',32,'全唐诗/poet.tang.24000.json','["趙村紅杏每年開，十五年來看幾迴。", "七十三人難再到，今春來是別花來。"]'),
('cd281576-53f9-4fd1-b357-d9711a869731','刑部尚書致仕','白居易','唐','唐诗','tang','','[]','十五年來洛下居，道緣俗累兩何如。',64,'全唐诗/poet.tang.24000.json','["十五年來洛下居，道緣俗累兩何如。", "迷路心迴因向佛，宦途事了是懸車。", "全家遁世曾無悶，半俸資身亦有餘。", "唯是名銜人不會，毘耶長者白尚書。"]'),
('0f2be5cc-3532-4e1a-8573-21ac552788f0','初致仕後戲酬留守牛相公幷呈分司諸寮友','白居易','唐','唐诗','tang','','[]','南北東西無所羈，挂冠目在勝分司。',64,'全唐诗/poet.tang.24000.json','["南北東西無所羈，挂冠目在勝分司。", "探花嘗酒多先到，拜表行香盡不知。", "炮筍烹魚飽飱後，擁袍枕臂醉眠時。", "報君一語君應笑，兼亦無心羨保釐。"]'),
('9dae29e2-46d7-4221-86ba-714d0056c616','問諸親友','白居易','唐','唐诗','tang','','[]','七十人難到，過三更較稀。',48,'全唐诗/poet.tang.24000.json','["七十人難到，過三更較稀。", "占花租野寺，定酒典朝衣。", "趁醉春多出，貪歡夜未歸。", "不知親故口，道我是耶非。"]'),
('bf43a47a-103e-477a-9bed-1a4a5a6236a9','戲問牛司徒','白居易','唐','唐诗','tang','','[]','抖擻塵纓捋白鬚，半酣扶起問司徒。',32,'全唐诗/poet.tang.24000.json','["抖擻塵纓捋白鬚，半酣扶起問司徒。", "不知詔下懸車後，醉舞狂歌有例無。"]'),
('b518bde9-459f-468d-8b11-f5ff50ee3c8c','不與老爲期','白居易','唐','唐诗','tang','','[]','不與老爲期，因何兩鬢絲。',96,'全唐诗/poet.tang.24000.json','["不與老爲期，因何兩鬢絲。", "纔應免夭促，便已及衰羸。", "昨夜夢何在，明朝身不知。", "百憂非我所，三樂是吾師。", "閉目常閑坐，低頭每靜思。", "存神機慮息，養氣語言遲。", "行亦攜詩篋，眠多枕酒巵。", "自慙無一事，少有不安時。"]'),
('4de74506-3b4f-4105-b375-42ada59afd02','開龍門八節石灘詩二首 一','白居易','唐','唐诗','tang','','[]','鐵鑿金鎚殷若雷，八灘九石劒稜摧。',64,'全唐诗/poet.tang.24000.json','["鐵鑿金鎚殷若雷，八灘九石劒稜摧。", "竹篙桂檝飛如箭，百筏千艘魚貫來。", "振錫導師憑衆力，揮金退傅施家財。", "他時相逐西方去，莫慮塵沙路不開。"]'),
('628117b3-3f1b-455e-b52f-9d109e0e1bed','開龍門八節石灘詩二首 二','白居易','唐','唐诗','tang','','[]','七十三翁旦暮身，誓開險路作通津。',64,'全唐诗/poet.tang.24000.json','["七十三翁旦暮身，誓開險路作通津。", "夜舟過此無傾覆，朝脛從今免苦辛。", "十里叱灘變河漢，八寒陰獄化陽春。", "我身雖歿心長在，闇施慈悲與後人。"]'),
('d61c8f5e-b2f8-492d-b8e2-8de4281bd62b','閑坐','白居易','唐','唐诗','tang','','[]','婆娑放雞犬，嬉戲任兒童。',48,'全唐诗/poet.tang.24000.json','["婆娑放雞犬，嬉戲任兒童。", "閑坐槐陰下，開襟向晚風。", "漚麻池水裏，曬棗日陽中。", "人物何相稱，居然田舍翁。"]'),
('c52a15d7-0a05-407f-b78e-ed5e0a4fcffb','酬寄牛相公同宿話舊勸酒見贈','白居易','唐','唐诗','tang','','[]','每來政事堂中宿，共憶華陽觀裏時。',64,'全唐诗/poet.tang.24000.json','["每來政事堂中宿，共憶華陽觀裏時。", "日暮獨歸愁米盡，泥深同出借驢騎。", "交遊今日唯殘我，富貴當年更有誰。", "彼此相看頭雪白，一杯可合重推辭。"]'),
('2da1708b-ddc7-4158-b886-8d511a9be33d','道場獨坐','白居易','唐','唐诗','tang','','[]','整頓衣巾拂淨牀，一瓶秋水一爐香。',64,'全唐诗/poet.tang.24000.json','["整頓衣巾拂淨牀，一瓶秋水一爐香。", "不論煩惱先須去，直到菩提亦擬忘。", "朝謁久停收劒珮，宴遊漸罷廢壺觴。", "世間無用殘年處，祗合逍遙坐道場。"]'),
('a802a703-65e1-4ce6-afa8-72120017b7a5','偶作寄朗之','白居易','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u4eba", "\u611f\u6168", "\u6292\u6000"]','歷想爲官日，無如刺史時。',168,'全唐诗/poet.tang.24000.json','["歷想爲官日，無如刺史時。", "歡娛接賓客，飽暖及妻兒。", "自到東都後，安閑更得宜。", "分司勝刺史，致仕勝分司。", "何況園林下，欣然得朗之。", "仰名同舊識，爲樂即新知。", "有雪先相訪，無花不作期。", "鬬醲乾釀酒，誇妙細吟詩。", "里巷千來往，都門五別離。", "岐分兩迴首，書到一開眉。", "葉落槐亭院，冰生竹閣池。", "雀羅誰問訊，鶴氅罷追隨。", "身與心俱病，容將力共衰。", "老來多健忘，唯不忘相思。"]'),
('f1860092-967c-47e0-aced-98686ee642b9','狂吟七言十四韻','白居易','唐','唐诗','tang','','[]','亦知世是休明世，自想身非富貴身。',192,'全唐诗/poet.tang.24000.json','["亦知世是休明世，自想身非富貴身。", "但恐人間爲長物，不如林下作遺民。", "遊依二室成三友，住近雙林當四鄰。", "性海澄渟平少浪，心田灑掃淨無塵。", "香山閑宿一千夜，梓澤連遊十六春。", "是客相逢皆故舊，無僧每見不殷勤。", "藥停有喜閑銷疾，金盡無憂醉忘貧。", "補綻衣裳媿妻女，支持酒肉賴交親。", "俸隨日計錢盈貫，祿逐年支粟滿囷。", "洛堰魚鮮供取足，遊村果熟饋爭新。", "詩章人與傳千首，壽命天教過七旬。", "點檢一生徼倖事，東都除我更無人。"]'),
('888d666c-05ff-41b0-b6c9-e36e23d2f61f','喜裴濤使君攜詩見訪醉中戲贈','白居易','唐','唐诗','tang','','[]','忽聞扣戶醉吟聲，不覺停杯倒屣迎。',32,'全唐诗/poet.tang.24000.json','["忽聞扣戶醉吟聲，不覺停杯倒屣迎。", "共放詩狂同酒癖，與君別是一親情。"]'),
('92bcb1bd-6d78-47b3-b2f9-36374483a7e2','得潮州楊相公繼之書幷詩以此寄之','白居易','唐','唐诗','tang','','[]','詩情書意兩殷勤，來自天南瘴海濱。',64,'全唐诗/poet.tang.24000.json','["詩情書意兩殷勤，來自天南瘴海濱。", "初覩銀鉤還啓齒，細吟瓊什欲霑巾。", "鳳池隔絕三千里，蝸舍沈冥十五春。", "唯有新昌故園月，至今分照兩鄉人。"]'),
('a44defe8-745f-4142-b0f4-27ccc76d780b','宿府池西亭','白居易','唐','唐诗','tang','','[]','池上平橋橋下亭，夜深睡覺上橋行。',32,'全唐诗/poet.tang.24000.json','["池上平橋橋下亭，夜深睡覺上橋行。", "白頭老尹重來宿，十五年前舊月明。"]'),
('e54f653e-e829-4baa-ac7e-ad4e623815f7','閑眠','白居易','唐','唐诗','tang','','[]','暖牀斜臥日曛腰，一覺閑眠百病銷。',32,'全唐诗/poet.tang.24000.json','["暖牀斜臥日曛腰，一覺閑眠百病銷。", "盡日一餐茶兩碗，更無所要到明朝。"]'),
('d7b62f21-3593-430a-96ec-5ce565af34f9','楊柳枝詞','白居易','唐','唐诗','tang','','["\u548f\u7269", "\u67f3\u6811", "\u4e50\u5e9c", "\u548f\u7269\u8bd7", "\u8fd1\u4ee3\u66f2\u8f9e"]','一樹春風千萬枝，嫩於金色軟於絲。',32,'全唐诗/poet.tang.24000.json','["一樹春風千萬枝，嫩於金色軟於絲。", "永豐西角荒園裏，盡日無人屬阿誰。"]'),
('f6d4b865-4825-485b-9094-5f3637756473','詔取永豐柳植禁苑感賦','白居易','唐','唐诗','tang','','["\u67f3\u6811", "\u8fd1\u4ee3\u66f2\u8f9e", "\u4e50\u5e9c"]','一樹衰殘委泥土，雙枝榮耀植天庭。',32,'全唐诗/poet.tang.24000.json','["一樹衰殘委泥土，雙枝榮耀植天庭。", "定知玄象今春後，柳宿光中添兩星。"]'),
('e291d938-e186-4e44-be94-e1a57a4226d3','齋居春久感事遣懷','白居易','唐','唐诗','tang','','[]','齋戒坐三旬，笙歌發四鄰。',96,'全唐诗/poet.tang.24000.json','["齋戒坐三旬，笙歌發四鄰。", "月明停酒夜，眼闇看花人。", "賴學空爲觀，深知念是塵。", "猶思閑語笑，未忘舊交親。", "久作龍門主，多爲兔苑賓。", "水嬉歌盡日，雪宴燭通晨。", "事事皆過分，時時自問身。", "風光拋得也，七十四年春。"]'),
('5bfff99a-ff38-4731-ab96-7f17f5eb50ce','每見呂南二郎中新文輒竊有所歎惜因成長句以詠所懷','白居易','唐','唐诗','tang','','[]','雙金百鍊少人知，縱我知君徒爾爲。',64,'全唐诗/poet.tang.24000.json','["雙金百鍊少人知，縱我知君徒爾爲。", "望梅閤老無妨渴，畫餅尚書不救飢。", "白日迴頭看又晚，青雲舉足躡何遲。", "壯年可惜虛銷擲，遣把閑杯吟詠詩。"]'),
('5609739e-9488-4964-960c-e050fe6b8ddd','胡吉鄭劉盧張等六賢皆多年壽予亦次焉偶於弊居合成尚齒之會七老相顧既醉且歡靜而思之此會稀有因成七言六韻以紀之傳好事者','白居易','唐','唐诗','tang','','[]','七人五百七十歲，拖紫紆朱垂白鬚。',96,'全唐诗/poet.tang.24000.json','["七人五百七十歲，拖紫紆朱垂白鬚。", "手裏無金莫嗟歎，尊中有酒且歡娛。", "詩吟兩句神還王，酒飲三杯氣尚麤。", "嵬峩狂歌教婢拍，婆娑醉舞遣孫扶。", "天年高過二疎傅，人數多於四皓圖。", "除却三山五天竺，人間此會更應無。"]'),
('a90de636-fef6-4077-97c6-b29b7192a1fd','歡喜二偈 一','白居易','唐','唐诗','tang','','[]','得老加年誠可喜，當春對酒亦宜歡。',32,'全唐诗/poet.tang.24000.json','["得老加年誠可喜，當春對酒亦宜歡。", "心中別有歡喜事，開得龍門八節灘。"]'),
('dc957da9-1e39-43d9-a7cb-3bce418ab3fe','歡喜二偈 二','白居易','唐','唐诗','tang','','[]','眼闇頭旋耳重聽，唯餘心口尚醒醒。',32,'全唐诗/poet.tang.24000.json','["眼闇頭旋耳重聽，唯餘心口尚醒醒。", "今朝歡喜緣何事，禮徹佛名百部經。"]'),
('2e7e724e-cea8-4254-be31-1785add00ec3','閑居貧活計','白居易','唐','唐诗','tang','','[]','冠蓋閑居少，簞瓢陋巷深。',72,'全唐诗/poet.tang.24000.json','["冠蓋閑居少，簞瓢陋巷深。", "稱家開戶牖，量力置園林。", "儉薄身都慣，營爲力不任。", "飢烹一斤肉，暖臥兩重衾。", "尊有陶潛酒，囊無陸賈金。", "莫嫌貧活計，更富即勞心。"]'),
('9aced3db-b1d7-415a-b7a9-c56ff7f2e381','贈諸少年','白居易','唐','唐诗','tang','','[]','少年莫笑我蹉跎，聽我狂翁一曲歌。',64,'全唐诗/poet.tang.24000.json','["少年莫笑我蹉跎，聽我狂翁一曲歌。", "入手榮名取雖少，關心穩事得還多。", "老慙退馬霑芻秣，高喜歸鴻脫弋羅。", "官給俸錢天與壽，些些貧病奈吾何。"]'),
('3e117043-6993-4b25-91db-335bfb9932b2','感所見','白居易','唐','唐诗','tang','','[]','巧者焦勞智者愁，愚翁何喜復何憂。',64,'全唐诗/poet.tang.24000.json','["巧者焦勞智者愁，愚翁何喜復何憂。", "莫嫌山木無人用，大勝籠禽不自由。", "網外老雞因斷尾，盤中鮮鱠爲吞鉤。", "誰人會我心中事，冷笑時時一掉頭。"]'),
('1ebf2d97-fb7a-4b70-bdae-161b059e9e23','寄黔州馬常侍','白居易','唐','唐诗','tang','','[]','閑看雙節信爲貴，樂飲一杯誰與同。',32,'全唐诗/poet.tang.24000.json','["閑看雙節信爲貴，樂飲一杯誰與同。", "可惜風情與心力，五年拋擲在黔中。"]'),
('c29ba9a2-373d-45d4-942e-717f0cfbaf9a','和李相公留守題漕上新橋六韻','白居易','唐','唐诗','tang','','[]','選石鋪新路，安橋壓古堤。',72,'全唐诗/poet.tang.24000.json','["選石鋪新路，安橋壓古堤。", "似從銀漢下，落傍玉川西。", "影定欄杆倒，標高華表齊。", "煙開虹半見，月冷鶴雙栖。", "材映夔龍小，功嫌元凱低。", "從容濟世後，餘力及黔黎。"]'),
('2acc2e23-10ea-48bb-b1ba-b7a3940159ae','閑居','白居易','唐','唐诗','tang','','[]','風雨蕭條秋少客，門庭冷靜晝多關。',96,'全唐诗/poet.tang.24000.json','["風雨蕭條秋少客，門庭冷靜晝多關。", "金羈駱馬近賣却，羅袖柳枝尋放還。", "書卷略尋聊取睡，酒杯淺把麤開顏。", "眼昏入夜休看月，脚重經春不上山。", "心靜無妨喧處寂，機忘兼覺夢中閑。", "是非愛惡銷停盡，唯寄空身在世間。"]'),
('a2ad8822-dbac-4ec1-8521-6ba066be1f79','新秋夜雨','白居易','唐','唐诗','tang','','[]','蟋蟀暮啾啾，光陰不少留。',48,'全唐诗/poet.tang.24000.json','["蟋蟀暮啾啾，光陰不少留。", "松簷半夜雨，風幌滿牀秋。", "曙早燈猶在，涼初簟未收。", "新晴好天氣，誰伴老人遊。"]'),
('23d2ed8d-fd6f-4ec8-b37d-8ce7b3380998','春眠','白居易','唐','唐诗','tang','','[]','枕低被暖身安穩，日照房門帳未開。',32,'全唐诗/poet.tang.24000.json','["枕低被暖身安穩，日照房門帳未開。", "還有少年春氣味，時時蹔到夢中來。"]'),
('407caec8-8b7d-4935-bdca-77c475d23db0','喜老自嘲','白居易','唐','唐诗','tang','','[]','面黑頭雪白，自嫌還自憐。',96,'全唐诗/poet.tang.24000.json','["面黑頭雪白，自嫌還自憐。", "毛龜蓍下老，蝙蝠鼠中仙。", "名籍同逋客，衣裝類古賢。", "裘輕被白氎，靴暖蹋烏氈。", "周易休開卦，陶琴不上弦。", "任從人棄擲，自與我周旋。", "鐵馬因疲退，鉛刀以鈍全。", "行開第八秩，可謂盡天年。"]'),
('0ec4e946-fb9a-4800-b7be-5cba376eaabc','能無媿','白居易','唐','唐诗','tang','','[]','十兩新綿褐，披行暖似春。',56,'全唐诗/poet.tang.24000.json','["十兩新綿褐，披行暖似春。", "一團香絮枕，倚坐穩于人。", "婢僕遣他嘗藥草，兒孫與我拂衣巾。", "迴看左右能無媿，養活枯殘廢退身。"]'),
('6486779b-681a-49ac-b49b-f1b3140d8546','河陽石尚書破迴鶻迎貴主過上黨射鷺𪆗繪畫爲圖猥蒙見示稱歎不足以詩美之','白居易','唐','唐诗','tang','','[]','塞北虜郊隨手破，山東賊壘掉鞭收。',96,'全唐诗/poet.tang.24000.json','["塞北虜郊隨手破，山東賊壘掉鞭收。", "烏孫公主歸秦地，白馬將軍入潞州。", "劒拔青鱗蛇尾活，弦抨赤羽火星流。", "須知鳥目猶難漏，縱有天狼豈足憂。", "畫角三聲刁斗曉，清商一部管弦秋。", "他時麟閣圖勳業，更合何人居上頭。"]'),
('0f846d2d-e4d7-4e07-8304-21ae22cef232','自詠老身示諸家屬','白居易','唐','唐诗','tang','','[]','壽及七十五，俸霑五十千。',96,'全唐诗/poet.tang.24000.json','["壽及七十五，俸霑五十千。", "夫妻偕老日，甥姪聚居年。", "粥美嘗新米，袍溫換故綿。", "家居雖濩落，眷屬幸團圓。", "置榻素屏下，移爐青帳前。", "書聽孫子讀，湯看侍兒煎。", "走筆還詩債，抽衣當藥錢。", "支分閑事了，爬背向陽眠。"]'),
('cd7d06e9-ebb7-4aae-9323-03c926003ba0','自問此心呈諸老伴','白居易','唐','唐诗','tang','','[]','朝問此心何所思，暮問此心何所爲。',96,'全唐诗/poet.tang.24000.json','["朝問此心何所思，暮問此心何所爲。", "不入公門慵歛手，不看人面免低眉。", "居士室間眠得所，少年場上飲非宜。", "閑談亹亹留諸老，美醞徐徐進一巵。", "心未曾求過分事，身常少有不安時。", "此心除自謀身外，更問其餘盡不知。"]'),
('5754edd8-51eb-4f85-959d-b588ad282d41','六年立春日人日作','白居易','唐','唐诗','tang','','[]','二日立春人七日，盤蔬餅餌逐時新。',64,'全唐诗/poet.tang.24000.json','["二日立春人七日，盤蔬餅餌逐時新。", "年方吉鄭猶爲少，家比劉韓未是貧。", "鄉園節歲應堪重，親故歡遊莫厭頻。", "試作循潮封眼想，何由得見洛陽春。"]'),
('e758d754-e07d-4267-b98f-25dbbecf77bc','齋居偶作','白居易','唐','唐诗','tang','','[]','童子裝爐火，行添一炷香。',96,'全唐诗/poet.tang.24000.json','["童子裝爐火，行添一炷香。", "老翁持麈尾，坐拂半張牀。", "卷縵看天色，移齋近日陽。", "甘鮮新餅果，穩暖舊衣裳。", "止足安生理，悠閑樂性場。", "是非一以遣，動靜百無妨。", "豈有物相累，兼無情可忘。", "不須憂老病，心是自醫王。"]'),
('edada8fa-dc00-41d6-8715-0481b43d52b3','詠身','白居易','唐','唐诗','tang','','[]','自中風來三歷閏，從懸軍後幾逢春。',64,'全唐诗/poet.tang.24000.json','["自中風來三歷閏，從懸軍後幾逢春。", "周南留滯稱遺老，漢上羸殘號半人。", "薄有文章傳子弟，斷無書札荅交親。", "餘年自問將何用，恐是人間賸長身。"]'),
('5d4e490b-517c-4201-bdf5-90da20d8ac46','予與山南王僕射起淮南李僕射紳事歷五朝踰三紀海內年輩今唯三人榮路雖殊交情不替聊題長句寄舉之公垂二相公','白居易','唐','唐诗','tang','','[]','故交海內只三人，二坐巖廊一臥雲。',64,'全唐诗/poet.tang.24000.json','["故交海內只三人，二坐巖廊一臥雲。", "老愛詩書還似我，榮兼將相不如君。", "百年膠漆初心在，萬里煙霄中路分。", "阿閣鸞凰野田鶴，何人信道舊同羣。"]'),
('4a48014c-71be-4011-b765-2051ece90629','讀道德經','白居易','唐','唐诗','tang','','[]','玄元皇帝著遺文，烏角先生仰後塵。',64,'全唐诗/poet.tang.24000.json','["玄元皇帝著遺文，烏角先生仰後塵。", "金玉滿堂非己物，子孫委蛻是他人。", "世間盡不關吾事，天下無親於我身。", "只有一身宜愛護，少教冰炭逼心神。"]'),
('493f2546-5e66-4084-8387-4c8249d68e86','禽蟲十二章 一','白居易','唐','唐诗','tang','','[]','燕違戊己鵲避歲，茲事因何羽族知。',32,'全唐诗/poet.tang.24000.json','["燕違戊己鵲避歲，茲事因何羽族知。", "疑有鳳凰頒鳥曆，一時一日不參差。"]'),
('43f50dcc-aba0-4e95-b175-c71d2eb203c7','禽蟲十二章 二','白居易','唐','唐诗','tang','','[]','水中科斗長成蛙，林下桑蟲老作蛾。',32,'全唐诗/poet.tang.24000.json','["水中科斗長成蛙，林下桑蟲老作蛾。", "蛙跳蛾舞仰頭笑，焉用鵾鵬鱗羽多。"]'),
('2fc6dbec-3846-48be-83f3-939d956e5ab3','禽蟲十二章 三','白居易','唐','唐诗','tang','','[]','江魚羣從稱妻妾，塞雁聯行號弟兄。',32,'全唐诗/poet.tang.24000.json','["江魚羣從稱妻妾，塞雁聯行號弟兄。", "但恐世間真眷屬，親疎亦是強爲名。"]'),
('ba1120d8-5f62-4ddd-84c7-97839ed41fec','禽蟲十二章 四','白居易','唐','唐诗','tang','','[]','蠶老繭成不庇身，蜂飢蜜熟屬他人。',32,'全唐诗/poet.tang.24000.json','["蠶老繭成不庇身，蜂飢蜜熟屬他人。", "須知年老憂家者，恐是二蟲虛苦辛。"]'),
('67beefac-6047-45e2-8783-b9c15cce4180','禽蟲十二章 五','白居易','唐','唐诗','tang','','[]','阿閣鵷鸞田舍烏，妍蚩貴賤兩懸殊。',32,'全唐诗/poet.tang.24000.json','["阿閣鵷鸞田舍烏，妍蚩貴賤兩懸殊。", "如何閉向深籠裏，一種摧頹觸四隅。"]'),
('ff48aed7-652b-4fb0-8ae2-1861d5771e3e','禽蟲十二章 六','白居易','唐','唐诗','tang','','[]','獸中刀鎗多怒吼，鳥遭羅弋盡哀鳴。',32,'全唐诗/poet.tang.24000.json','["獸中刀鎗多怒吼，鳥遭羅弋盡哀鳴。", "羔羊口在緣何事，闇死屠門無一聲。"]'),
('7a64c6d0-878e-4594-a815-6b4174fb8a86','禽蟲十二章 七','白居易','唐','唐诗','tang','','[]','蟭螟殺敵蚊巢上，蠻觸交爭蝸角中。',32,'全唐诗/poet.tang.24000.json','["蟭螟殺敵蚊巢上，蠻觸交爭蝸角中。", "應是諸天觀下界，一微塵內鬬英雄。"]'),
('d10abc64-0e3c-47f2-bbcf-7a57d50d42a4','禽蟲十二章 八','白居易','唐','唐诗','tang','','[]','蠨蛸網上罥蜉蝣，反覆相持死始休。',32,'全唐诗/poet.tang.24000.json','["蠨蛸網上罥蜉蝣，反覆相持死始休。", "何異浮生臨老日，一彈指頃報恩讐。"]'),
('1cab8a6d-042b-40c7-ad7b-d30f61fd0d90','禽蟲十二章 九','白居易','唐','唐诗','tang','','[]','蟻王化飯爲臣妾，蜾母偷蟲作子孫。',32,'全唐诗/poet.tang.24000.json','["蟻王化飯爲臣妾，蜾母偷蟲作子孫。", "彼此假名非本物，其間何怨復何恩。"]'),
('0207d5b9-9515-46e8-82a1-314d82f32bc9','禽蟲十二章 十','白居易','唐','唐诗','tang','','[]','豆苗鹿嚼解烏毒，艾葉雀銜奪燕巢。',32,'全唐诗/poet.tang.24000.json','["豆苗鹿嚼解烏毒，艾葉雀銜奪燕巢。", "鳥獸不曾看本草，諳知藥性是誰教。"]'),
('983980f4-30da-4799-bec0-b5b597357679','禽蟲十二章 十一','白居易','唐','唐诗','tang','','[]','一鼠得仙生羽翼，衆鼠相看有羨色。',32,'全唐诗/poet.tang.24000.json','["一鼠得仙生羽翼，衆鼠相看有羨色。", "豈知飛上未半空，已作烏鳶口中食。"]'),
('c61c68b9-55a4-4613-9f34-c3183a52452c','禽蟲十二章 十二','白居易','唐','唐诗','tang','','[]','鵝乳養雛遺在水，魚心想子變成鱗。',32,'全唐诗/poet.tang.24000.json','["鵝乳養雛遺在水，魚心想子變成鱗。", "細微幽隱何窮事，知者唯應是聖人。"]'),
('c3eb0494-509b-4e39-8c2f-505a4fc0d6ae','窗中列遠岫','白居易','唐','唐诗','tang','','[]','天靜秋山好，窗開曉翠通。',72,'全唐诗/poet.tang.24000.json','["天靜秋山好，窗開曉翠通。", "遙憐峰窈窕，不隔竹朦朧。", "萬點當虛室，千重疊遠空。", "列檐攢秀氣，緣隙助清風。", "碧愛新晴後，明宜反照中。", "宣城郡齋在，望與古時同。"]'),
('0b9ed86c-2189-475f-bce3-0339fb22707b','玉水記方流','白居易','唐','唐诗','tang','','[]','良璞含章久，寒泉徹底幽。',72,'全唐诗/poet.tang.24000.json','["良璞含章久，寒泉徹底幽。", "矩浮光灩灩，方折浪悠悠。", "凌亂波紋異，縈迴水性柔。", "似風搖淺瀨，疑月落清流。", "潛潁應傍達，藏真豈上浮。", "玉人如不見，淪棄即千秋。"]'),
('ce5a08b3-3f64-4708-ad58-160ce15c51a9','大社觀獻捷詩','白居易','唐','唐诗','tang','','[]','淮海妖氛滅，乾坤嘉氣通。',48,'全唐诗/poet.tang.24000.json','["淮海妖氛滅，乾坤嘉氣通。", "班師郊社內，操袂凱歌中。", "廟算無遺策，天兵不戰功。", "小臣同鳥獸，率舞向皇風。"]'),
('e9f70c89-d21b-4785-b337-cb3f96a31013','自誨','白居易','唐','唐诗','tang','','[]','樂天樂天，來與汝言。',258,'全唐诗/poet.tang.24000.json','["樂天樂天，來與汝言。", "汝宜拳拳，終身行焉。", "物有萬類，錮人如鎖。", "事有萬感，爇人如火。", "萬類遰來，鏁汝形骸。", "使汝未老，形枯如柴。", "萬感遰至，火汝心懷。", "使汝未死，心化爲灰。", "樂天樂天，可不大哀。", "汝胡不懲往而念來，人生百歲七十稀，設使與汝七十期。", "汝今年已四十四，却後二十六年能幾時。", "汝不思二十五六年來事，疾速倏忽如一寐。", "往日來日皆瞥然，胡爲自苦於其間。", "樂天樂天，可不大哀。", "而今而後，汝宜飢而食，渴而飲。", "晝而興，夜而寢。", "無浪喜，無妄憂。", "病則臥，死則休。", "此中是汝家，此中是汝鄉。", "汝何捨此而去，自取其遑遑。", "遑遑兮欲安往哉，樂天樂天歸去來。"]'),
('69cf0d6a-2c3f-455a-8ce1-995d50469d59','三謠 蟠木謠','白居易','唐','唐诗','tang','','[]','蟠木蟠木，有似我身。',138,'全唐诗/poet.tang.24000.json','["蟠木蟠木，有似我身。", "不中乎器，無用於人。", "下擁腫而上轔菌，桷不桷兮輪不輪。", "天子建明堂兮既非梁棟，諸侯斵大輅兮材又不中。", "唯我病夫，或有所用。", "用爾爲几，承吾臂支吾頤而已矣。", "不傷爾性，不枉爾理。", "爾怏怏爲几之外，無所用爾。", "爾既不材，吾亦不材，胡爲乎人間裴回？", "蟠木蟠木，吾與汝歸草堂去來。"]'),
('c437981e-acc7-44aa-a248-ad39993355a1','三謠 素屏謠','白居易','唐','唐诗','tang','','[]','素屏素屏，胡爲乎不文不飾，不丹不青。',205,'全唐诗/poet.tang.24000.json','["素屏素屏，胡爲乎不文不飾，不丹不青。", "當世豈無李陽冰之篆字，張旭之筆迹。", "邊鸞之花鳥，張璪之松石。", "吾不令加一點一畫於其上，欲爾保真而全白。", "吾於香爐峰下置草堂，二屏倚在東西牆。", "夜如明月入我室，曉如白雲圍我牀。", "我心久養浩然氣，亦欲與爾表裏相輝光。", "爾不見當今甲第與王宮，織成步障銀屏風。", "綴珠陷鈿貼雲母，五金七寶相玲瓏。", "貴豪待此方悅目，晏然寢臥乎其中。", "素屏素屏，物各有所宜，用各有所施。", "爾今木爲骨兮紙爲面，捨吾草堂欲何之。"]'),
('4a8ea076-1895-4dfb-a0de-42e17e3a042c','三謠 朱藤謠','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','朱藤朱藤，溫如紅玉，直如朱繩。',277,'全唐诗/poet.tang.24000.json','["朱藤朱藤，溫如紅玉，直如朱繩。", "自我得爾以爲杖，大有裨於股肱。", "前年左選，東南萬里。", "交遊別我於國門，親友送我於滻水。", "登高山兮車倒輪摧，渡漢水兮馬跙蹄開。", "中途不進，部曲多迴。", "唯此朱藤，實隨我來。", "瘴癘之鄉，無人之地。", "扶衛衰病，驅訶魑魅。", "吾獨一身，賴爾爲二。", "或水或陸，自北徂南。", "泥黏雪滑，足力不堪。", "吾本兩足，得爾爲三。", "紫霄峰頭，黃石巖下。", "松門石磴，不通輿馬。", "吾與爾披雲撥水，環山繞野。", "二年蹋徧匡廬間，未嘗一步而相捨。", "雖有佳子弟，良友朋。", "扶危助蹇，不如朱藤。", "嗟乎！窮既若是，通復何如？", "吾不以常杖待爾，爾勿以常人望吾。", "朱藤朱藤，吾雖青雲之上，黃泥之下，誓不棄爾於斯須。"]'),
('da9dca80-4137-4ef6-8851-2c0e23463a22','無可奈何歌','白居易','唐','唐诗','tang','','["\u6cf0\u5c71"]','無可奈何兮！白日走而朱顏頹，少日往而老日催。',323,'全唐诗/poet.tang.24000.json','["無可奈何兮！白日走而朱顏頹，少日往而老日催。", "生者不住兮死者不迴，況乎寵辱豐顇之外物。", "又何常不十去而一來，去不可挽兮來不可推。", "無可奈何兮！已焉哉！惟天長而地久，前無始兮後無終。", "嗟吾生之幾何，寄瞬息乎其中。", "又如太倉之稊米，委一粒於萬鍾。", "何不與道逍遙？", "委化從容。", "縱心放志，洩洩融融。", "胡爲乎分愛惡於生死，繫憂喜於窮通。", "倔強其骨髓，齟齬其心胷。", "合冰炭以交戰，祗自苦兮厥躬。", "彼造物者，云何不爲。", "此與化者，云何不隨。", "或喣或吹，或盛或衰。", "雖千變與萬化，委一順以貫之。", "爲彼何非，爲此何是。", "誰冥此心，夢蝶之子。", "何禍非福，何吉非凶。", "誰達此觀，喪馬之翁。", "俾吾爲秋毫之杪，吾亦自足。", "不見其小，俾吾爲泰山之阿。", "吾亦無餘，不見其多。", "是以達人靜則脗然與陰合迹，動則浩然與陽同波。"]'),
('f058930e-14aa-470d-a0eb-fcec45d2071d','池上篇','白居易','唐','唐诗','tang','','[]','十畝之宅，五畝之園。',153,'全唐诗/poet.tang.24000.json','["十畝之宅，五畝之園。", "有水一池，有竹千竿。", "勿謂土狹，勿謂地偏。", "足以容膝，足以息肩。", "有堂有庭，有橋有船。", "有書有酒，有歌有弦。", "有叟在中，白鬚飄然。", "識分知足，外無求焉。", "如鳥擇木，姑務巢安。", "如龜居坎，不知海寬。", "靈鶴怪石，紫菱白蓮。", "皆吾所好，盡在吾前。", "時飲一杯，或吟一篇。", "妻孥熙熙，雞犬閑閑。", "優哉游哉，吾將終老乎其間。"]'),
('abd4e626-16f4-4beb-bc98-6e9a75f62534','齒落辭','白居易','唐','唐诗','tang','','[]','嗟嗟乎雙齒，自吾有之爾。',314,'全唐诗/poet.tang.24000.json','["嗟嗟乎雙齒，自吾有之爾。", "俾爾嚼肉咀蔬，銜杯漱水。", "豐吾膚革，滋吾血髓。", "從幼逮老，勤亦至矣。", "幸有輔車，非無齗齶。", "胡然捨我，一旦雙落。", "齒雖無情，吾豈無情。", "老與齒別，齒隨涕零。", "我老日來，爾去不迴。", "嗟嗟乎雙齒，孰謂而來哉？孰謂而去哉？齒不能言，請以意宣。", "爲口中之物，忽乎六十餘年。", "昔君之壯也，血剛齒堅。", "今君之老矣，血衰齒寒。", "輔車齗齶，日削月朘。", "上參差而下𠨜𦤞，曾何足以少安。", "嘻！君其聽哉，女長辭姥，臣老辭主。", "髮衰辭頭，葉枯辭樹。", "物無細大，功成者去，君何嗟嗟？", "獨不聞諸道經，我身非我有也，蓋天地之委形。", "君何嗟嗟？", "又不聞諸佛說，是身如浮雲，須臾變滅。", "由是而言，君何有焉？", "所宜委百骸而順萬化，胡爲乎嗟嗟於一牙一齒之間。", "吾應曰：吾過矣，爾之言然。"]'),
('bbd389f4-9ca4-4e6e-842c-e0488b44946b','不能忘情吟','白居易','唐','唐诗','tang','','[]','鬻駱馬兮放楊柳枝，掩翠黛兮頓金羈。',283,'全唐诗/poet.tang.24000.json','["鬻駱馬兮放楊柳枝，掩翠黛兮頓金羈。", "馬不能言兮長鳴而却顧，楊柳枝再拜長跪而致辭。", "辭曰：主乘此駱五年，凡千有八百日。", "銜橜之下，不驚不逸。", "素事主十年，凡三千有六百日。", "巾櫛之間，無違無失。", "今素貌雖陋，未至衰摧。", "駱力猶壯，又無虺隤。", "即駱之力，尚可以代主一步。", "素之歌，亦可以送主一杯。", "一旦雙去，有去無迴。", "故素將去，其辭也苦。", "駱將去，其鳴也哀。", "此人之情也，馬之情也，豈主君獨無情哉？", "予俯而歎，仰而咍，且曰：駱、駱，爾勿嘶，素、素，爾勿啼，駱反廐，素反閨。", "吾疾雖作，年雖頹，幸未及項籍之將死。", "何必一日之內，棄騅兮而別虞兮，乃目素兮素兮。", "爲我歌楊柳枝，我姑酌彼金罍，我與爾歸醉鄉去來。"]'),
('59dcfd79-edf4-40ea-9e7e-166bfba05c0d','勸酒','白居易','唐','唐诗','tang','','[]','昨與美人對尊酒，朱顏如花腰似柳。',304,'全唐诗/poet.tang.24000.json','["昨與美人對尊酒，朱顏如花腰似柳。", "今與美人傾一杯，秋風颯颯頭上來。", "年光似水向東去，兩鬢不禁白日催。", "東鄰起樓高百尺，璇題照日光相射。", "珠翠無非二八人，盤筵何啻三千客。", "鄰家儒者方下帷，夜誦古書朝忍飢。", "身年三十未入仕，仰望東鄰安可期。", "一朝逸翮乘風勢，金榜高張登上第。", "春闈未了冬登科，九萬摶風誰與繼。", "不逾十稔居台衡，門前車馬紛縱橫。", "人人仰望在何處，造化筆頭雲雨生。", "東鄰高樓色未改，主人云亡息猶在。", "金玉車馬一不存，朱門更有何人待。", "牆垣反鎖長安春，樓臺漸漸屬西鄰。", "松篁薄暮亦栖鳥，桃李無情還笑人。", "憶昔東鄰宅初搆，雲甍彩棟皆非舊。", "瑇瑁筵前翡翠栖，芙蓉池上鴛鴦鬬。", "日往月來凡幾秋，一衰一盛何悠悠。", "但教帝里笙歌在，池上年年醉五侯。"]'),
('eefedc03-348b-45e7-bb17-8c718504b317','南陽小將張彥硤口鎮稅人場射虎歌','白居易','唐','唐诗','tang','','[]','海內昔年狎太平，橫目穰穰何崢嶸。',160,'全唐诗/poet.tang.24000.json','["海內昔年狎太平，橫目穰穰何崢嶸。", "天生天殺豈天怒，忍使朝朝餵猛虎。", "關東驛路多丘荒，行人最忌稅人場。", "張彥雄特制殘暴，見之叱起如叱羊。", "鳴弦霹靂越幽阻，往往依林猶旅拒。", "草際旋看委錦茵，腰間不更抽白羽。", "老饕已斃衆雛恐，童穉揶揄皆自勇。", "忠良效順勢亦然，一劒猜狂敢輕動。", "有文有武方爲國，不是英雄伏不得。", "試徵張彥作將軍，幾箇將軍願策勳。"]'),
('34be6242-2eeb-4ef0-8c20-6cc8dc9ec82d','陰雨','白居易','唐','唐诗','tang','','[]','潤葉濡枝浹四方，濃雲來去勢何長。',32,'全唐诗/poet.tang.24000.json','["潤葉濡枝浹四方，濃雲來去勢何長。", "曠然寰宇清風滿，救旱功高暑氣涼。"]'),
('8a3dd357-ff37-47a0-a9cc-7ec4acf7cd4c','喜雨','白居易','唐','唐诗','tang','','[]','西北油然雲勢濃，須臾霶沛雨飄空。',32,'全唐诗/poet.tang.24000.json','["西北油然雲勢濃，須臾霶沛雨飄空。", "頓疎萬物焦枯意，定看秋郊稼穡豐。"]'),
('c69d9b47-c00d-430f-a5f7-d241f4294686','過故洛城','白居易','唐','唐诗','tang','','[]','故城門前春日斜，故城門裏無人家。',32,'全唐诗/poet.tang.24000.json','["故城門前春日斜，故城門裏無人家。", "市朝欲認不知處，漠漠野田飛草花。"]'),
('5ef63d25-57f3-44a9-a3af-57b7f7a76842','江南喜逢蕭九徹因話長安舊遊戲贈五十韻','白居易','唐','唐诗','tang','','[]','憶昔嬉遊伴，多陪歡宴場。',288,'全唐诗/poet.tang.24000.json','["憶昔嬉遊伴，多陪歡宴場。", "寓居同永樂，幽會共平康。", "師子尋前曲，聲兒出內坊。", "花深態奴宅，竹錯得憐堂。", "庭晚開紅藥，門閑蔭綠楊。", "經過悉同巷，居處盡連牆。", "時世高梳髻，風流澹作妝。", "戴花紅石竹，帔暈紫檳榔。", "鬢動懸蟬翼，釵垂小鳳行。", "拂胷輕粉絮，煖手小香囊。", "選勝移銀燭，邀歡舉玉觴。", "爐煙凝麝氣，酒色注鵝黃。", "急管停還奏，繁弦慢更張。", "雪飛迴舞袖，塵起繞歌梁。", "舊曲翻調笑，新聲打義揚。", "名情推阿軌，巧語許秋孃。", "風暖春將暮，星迴夜未央。", "宴餘添粉黛，坐久換衣裳。", "結伴歸深院，分頭入洞房。", "綵帷開翡翠，羅薦拂鴛鴦。", "留宿爭牽袖，貪眠各占牀。", "綠窗籠水影，紅壁背燈光。", "索鏡收花鈿，邀人解袷襠。", "暗嬌妝靨笑，私語口脂香。"]'),
('c37ed807-84d5-4de8-9781-928cb16e602b','贈薛濤','白居易','唐','唐诗','tang','','[]','蛾眉山勢接雲霓，欲逐劉郎北路迷。',32,'全唐诗/poet.tang.24000.json','["蛾眉山勢接雲霓，欲逐劉郎北路迷。", "若似剡中容易到，春風猶隔武陵溪。"]'),
('c40a0235-61c5-4cb6-b96c-471a62afac00','酬令狐留守尚書見贈十韻','白居易','唐','唐诗','tang','','[]','長慶清風在，夔龍燮理餘。',120,'全唐诗/poet.tang.24000.json','["長慶清風在，夔龍燮理餘。", "太和膏雨降，周邵保釐初。", "嵩少當宮署，伊瀍入禁渠。", "曉關開玉兔，夕鑰納銀魚。", "舊眷憐移疾，新吟念索居。", "離聲雙白鸝，行色一籃轝。", "罷免無餘俸，休閑有敝廬。", "慵於嵇叔夜，渴似馬相如。", "酒每蒙酤我，詩嘗許起予。", "洛中歸計定，一半爲尚書。"]'),
('6a1115e5-1ec9-41ec-aab8-d61af62debf2','聽蘆管','白居易','唐','唐诗','tang','','[]','幽咽新蘆管，淒涼古竹枝。',96,'全唐诗/poet.tang.24000.json','["幽咽新蘆管，淒涼古竹枝。", "似臨猨峽唱，疑在雁門吹。", "調爲高多切，聲緣小乍遲。", "麤豪嫌觱篥，細妙勝參差。", "雲水巴南客，風沙隴上兒。", "屈原收淚夜，蘇武斷腸時。", "仰秣胡駒聽，驚栖越鳥知。", "何言胡越異，聞此一同悲。"]'),
('0ca2efb9-9c67-487e-b440-f1b8e77e158a','送滕庶子致仕歸婺州','白居易','唐','唐诗','tang','','[]','春風秋月攜歌酒，八十年來翫物華。',64,'全唐诗/poet.tang.24000.json','["春風秋月攜歌酒，八十年來翫物華。", "已見曾孫騎竹馬，猶聽侍女唱梅花。", "入鄉不杖歸時健，出郭乘軺到處誇。", "兒著繡衣身衣錦，東陽門戶勝滕家。"]'),
('7b6ebc85-65b1-4eb0-850e-0e36b8c80f58','送劉郎中赴任蘇州','白居易','唐','唐诗','tang','','[]','仁風膏雨去隨輪，勝境歡遊到逐身。',64,'全唐诗/poet.tang.24000.json','["仁風膏雨去隨輪，勝境歡遊到逐身。", "水驛路穿兒店月，花船棹入女湖春。", "宣城獨詠窗中岫，柳惲單題汀上蘋。", "何似姑蘇詩太守，吟詩相繼有三人。"]'),
('7cec6558-dc6a-42bb-8e30-aef958651ca3','福先寺雪中餞劉蘇州','白居易','唐','唐诗','tang','','[]','送君何處展離筵，大梵王宮大雪天。',64,'全唐诗/poet.tang.24000.json','["送君何處展離筵，大梵王宮大雪天。", "庾嶺梅花落歌管，謝家柳絮撲金田。", "亂從紈袖交加舞，醉入籃轝取次眠。", "却笑召鄒兼訪戴，只持空酒駕空船。"]'),
('5303d6b6-d8ee-46f2-ac9d-52466da37675','除夜言懷兼贈張常侍','白居易','唐','唐诗','tang','','[]','三百六旬今夜盡，六十四年明日催。',64,'全唐诗/poet.tang.24000.json','["三百六旬今夜盡，六十四年明日催。", "不用歎身隨日老，亦須知壽逐年來。", "加添雪興憑氈帳，消殺春愁付酒杯。", "唯恨詩成君去後，紅箋紙卷爲誰開。"]'),
('3f47be53-0ab1-4098-a9f4-3471b730a781','送張常侍西歸','白居易','唐','唐诗','tang','','[]','二年花下爲閑伴，一旦尊前棄老夫。',64,'全唐诗/poet.tang.24000.json','["二年花下爲閑伴，一旦尊前棄老夫。", "西午橋街行悵望，南龍興寺立踟躕。", "洛城久住留情否，省騎重歸稱意無。", "出鎮歸朝但相訪，此身應不離東都。"]'),
('20519800-0bd2-4ff2-855f-bda534f9b86f','和河南鄭尹新歲對雪','白居易','唐','唐诗','tang','','[]','白雪吟詩鈴閣開，故情新興兩裴回。',64,'全唐诗/poet.tang.24000.json','["白雪吟詩鈴閣開，故情新興兩裴回。", "昔經勤苦照書卷，今助歡娛飄酒杯。", "楚客難酬郢中曲，吳公兼占洛陽才。", "銅街金谷春知否，又有詩人作尹來。"]'),
('56270098-2459-4746-af86-fb7ae3e2d86b','吹笙內人出家','白居易','唐','唐诗','tang','','[]','雨露難忘君念重，電泡易滅妾身輕。',64,'全唐诗/poet.tang.24000.json','["雨露難忘君念重，電泡易滅妾身輕。", "金刀已剃頭然髮，玉管休吹腸斷聲。", "新戒珠從衣裏得，初心蓮向火中生。", "道場夜半香花冷，猶在燈前禮佛名。"]'),
('edf2a3ab-c8b5-423c-a2ae-07d7f89a5ef6','醉中見微之舊卷有感','白居易','唐','唐诗','tang','','[]','今朝何事一霑襟，檢得君詩醉後吟。',64,'全唐诗/poet.tang.24000.json','["今朝何事一霑襟，檢得君詩醉後吟。", "老淚交流風病眼，春箋搖動酒杯心。", "銀鉤塵覆年年暗，玉樹泥埋日日深。", "聞道墓松高一丈，更無消息到如今。"]'),
('b506fa81-e9ae-4f0d-9894-60960596655b','壽安歇馬重吟','白居易','唐','唐诗','tang','','[]','春衫細薄馬蹄輕，一日遲遲進一程。',64,'全唐诗/poet.tang.24000.json','["春衫細薄馬蹄輕，一日遲遲進一程。", "野棗花含新蜜氣，山禽語帶破匏聲。", "垂鞭晚就槐陰歇，低倡閑衝柳絮行。", "忽憶家園須速去，櫻桃欲熟筍應生。"]'),
('fcfc8ccb-85f4-4513-bef2-d60518fb3ec0','贈張處士山人','白居易','唐','唐诗','tang','','[]','蘿襟蕙帶竹皮巾，雖到塵中不染塵。',64,'全唐诗/poet.tang.24000.json','["蘿襟蕙帶竹皮巾，雖到塵中不染塵。", "每見俗人多慘澹，惟逢美酒即殷勤。", "浮雲心事誰能會，老鶴風標不可親。", "世說三生如不謬，共疑巢許是前身。"]'),
('90b02a4b-7245-4e44-939b-ea2583bf285e','池畔閑坐兼呈侍中','白居易','唐','唐诗','tang','','[]','池畔最平處，樹陰新合時。',48,'全唐诗/poet.tang.24000.json','["池畔最平處，樹陰新合時。", "移牀解衣帶，坐任清風吹。", "舉棹鳥先覺，垂綸魚未知。", "前頭何所有，一卷晉公詩。"]'),
('55ea337c-7965-4311-a981-5bc124d9fabe','初冬即事憶皇甫十','白居易','唐','唐诗','tang','','[]','冷竹風成韻，荒街葉作堆。',48,'全唐诗/poet.tang.24000.json','["冷竹風成韻，荒街葉作堆。", "欲尋聯句卷，先飲煖寒杯。", "帽爲迎霜戴，爐因試火開。", "時時還有客，終不當君來。"]'),
('1abe55fd-feae-47a3-af80-b17efbb4b16f','小庭寒夜寄夢得','白居易','唐','唐诗','tang','','[]','庭小同蝸舍，門閑稱雀羅。',48,'全唐诗/poet.tang.24000.json','["庭小同蝸舍，門閑稱雀羅。", "火將燈共盡，風與雪相和。", "老睡隨年減，衰情向夕多。", "不知同病者，爭奈夜長何。"]'),
('2b906b7b-3d76-415a-9742-0ec27d3d9e74','西還壽安路西歇馬','白居易','唐','唐诗','tang','','[]','槐陰歇鞍馬，柳絮惹衣巾。',48,'全唐诗/poet.tang.24000.json','["槐陰歇鞍馬，柳絮惹衣巾。", "日晚獨歸路，春深多思人。", "去家纔百里，爲客只三旬。", "已念紗窗下，應生寶瑟塵。"]'),
('b579e871-dcea-4551-af1a-5fa02101790f','雨中訪崔十八','白居易','唐','唐诗','tang','','[]','肩舁仍挈榼，莫怪就君來。',24,'全唐诗/poet.tang.24000.json','["肩舁仍挈榼，莫怪就君來。", "秋雨經三宿，無人勸一杯。"]'),
('f845b815-e1c5-4bb2-9bce-1400c18b6a80','夢得得新詩','白居易','唐','唐诗','tang','','[]','池上今宵風月涼，閑教少樂理霓裳。',32,'全唐诗/poet.tang.24000.json','["池上今宵風月涼，閑教少樂理霓裳。", "集仙殿裏新詞到，便播笙歌作樂章。"]'),
('51196cf6-9352-4831-80a0-12aed62618d3','初見劉二十八郎中有感','白居易','唐','唐诗','tang','','[]','欲話毘陵君反袂，欲言夏口我霑衣。',32,'全唐诗/poet.tang.24000.json','["欲話毘陵君反袂，欲言夏口我霑衣。", "誰知臨老相逢日，悲歎聲多語笑稀。"]'),
('c3fb875f-d48b-4bce-8485-b4261cb18348','夜題玉泉','白居易','唐','唐诗','tang','','[]','遇客多言愛山水，逢僧盡道厭囂塵。',32,'全唐诗/poet.tang.24000.json','["遇客多言愛山水，逢僧盡道厭囂塵。", "玉泉潭畔松間宿，要且經年無一人。"]'),
('ce175fe6-299b-4d60-b996-e56604bdc99a','拜表早出贈皇甫賓客','白居易','唐','唐诗','tang','','[]','一月一回同拜表，莫辭侵早過中橋。',32,'全唐诗/poet.tang.24000.json','["一月一回同拜表，莫辭侵早過中橋。", "老於君者應無數，猶趁西京十五朝。"]'),
('0b30e493-cb22-4113-8591-ec86070e93e8','贈鄭尹','白居易','唐','唐诗','tang','','[]','府池東北舊亭臺，久別長思醉一回。',32,'全唐诗/poet.tang.24000.json','["府池東北舊亭臺，久別長思醉一回。", "但請主人空埽地，自攜杯酒管弦來。"]'),
('0c7d2368-f4ec-400a-bb7c-617323156c10','別楊同州後却寄','白居易','唐','唐诗','tang','','[]','潘驛橋南醉中別，下邽村北醒時歸。',32,'全唐诗/poet.tang.24000.json','["潘驛橋南醉中別，下邽村北醒時歸。", "春風怪我君知否，榆葉楊花撲面飛。"]'),
('977ecaec-3922-4c0d-9cd5-df1c7fd582a3','狐泉店前作','白居易','唐','唐诗','tang','','[]','野狐泉上柳花飛，逐水東流便不歸。',32,'全唐诗/poet.tang.24000.json','["野狐泉上柳花飛，逐水東流便不歸。", "花水悠悠兩無意，因風吹落偶相依。"]'),
('f37335b1-5784-4e5c-914e-b24f19a7f572','贈盧績','白居易','唐','唐诗','tang','','[]','餘杭縣裏盧明府，虛白亭中白舍人。',32,'全唐诗/poet.tang.24000.json','["餘杭縣裏盧明府，虛白亭中白舍人。", "今日相逢頭似雪，一杯相勸送殘春。"]'),
('adca7e05-f093-4786-b5a5-770c2367d2c7','與裴華州同過敷水戲贈','白居易','唐','唐诗','tang','','[]','使君五馬且蜘躕，馬上能聽絕句無。',32,'全唐诗/poet.tang.24000.json','["使君五馬且蜘躕，馬上能聽絕句無。", "每過桑間試留意，何妨後代有羅敷。"]'),
('e8fd7467-c5e8-4c6b-b534-a4d35a567768','閑遊','白居易','唐','唐诗','tang','','[]','欲笑隨情酒逐身，此身雖老未辜春。',32,'全唐诗/poet.tang.24000.json','["欲笑隨情酒逐身，此身雖老未辜春。", "春來點檢閑遊數，猶自多於年少人。"]'),
('ad862e81-84e0-4999-bebb-c7b0b7af2ca1','招韜光禪師','白居易','唐','唐诗','tang','','[]','白屋炊香飯，葷膻不入家。',48,'全唐诗/poet.tang.24000.json','["白屋炊香飯，葷膻不入家。", "濾泉澄葛粉，洗手摘藤花。", "青芥除黃葉，紅薑帶紫芽。", "命師相伴食，齋罷一甌茶。"]'),
('88d9794a-0ef0-4e93-a798-f72d56d4f094','和柳公權登齊雲樓','白居易','唐','唐诗','tang','','[]','樓外春晴百鳥鳴，樓中春酒美人傾。',64,'全唐诗/poet.tang.24000.json','["樓外春晴百鳥鳴，樓中春酒美人傾。", "路傍花日添衣色，雲裏天風散珮聲。", "向此高吟誰得意，偶來閑客獨多情。", "佳時莫起興亡恨，遊樂今逢四海清。"]'),
('01105fdb-a111-4cf8-b25c-a01172a435fe','毛公壇','白居易','唐','唐诗','tang','','[]','毛公壇上片雲閑，得道何年去不還。',32,'全唐诗/poet.tang.24000.json','["毛公壇上片雲閑，得道何年去不還。", "千載鶴翎歸碧落，五湖空鎮萬重山。"]'),
('bab0c899-7e8b-4126-abf8-c83376a18c40','靈巖寺','白居易','唐','唐诗','tang','','[]','館娃宮畔千年寺，水闊雲多客到稀。',32,'全唐诗/poet.tang.24000.json','["館娃宮畔千年寺，水闊雲多客到稀。", "聞說春來更惆悵，百花深處一僧歸。"]'),
('83284bf1-8b8e-4deb-a29d-6aa9cfaf7184','白雲泉','白居易','唐','唐诗','tang','','[]','天平山上白雲泉，雲自無心水自閑。',32,'全唐诗/poet.tang.24000.json','["天平山上白雲泉，雲自無心水自閑。", "何必奔衝山下去，更添波浪向人間。"]'),
('f7032e43-846d-4583-a2f7-f60598f0d256','寄韜光禪師','白居易','唐','唐诗','tang','','[]','一山門作兩山門，兩寺原從一寺分。',64,'全唐诗/poet.tang.24000.json','["一山門作兩山門，兩寺原從一寺分。", "東澗水流西澗水，南山雲起北山雲。", "前臺花發後臺見，上界鐘聲下界聞。", "遙想吾師行道處，天香桂子落紛紛。"]'),
('a721b13c-026d-4142-a1ac-b1a8cfad5959','和夢得夏至憶蘇州呈盧賓客','白居易','唐','唐诗','tang','','[]','憶在蘇州日，常諳夏至筵。',96,'全唐诗/poet.tang.24000.json','["憶在蘇州日，常諳夏至筵。", "糉香筒竹嫩，炙脆子鵝鮮。", "水國多臺榭，吳風尚管弦。", "每家皆有酒，無處不過船。", "交印君相次，褰帷我在前。", "此鄉俱老矣，東望共依然。", "洛下麥秋月，江南梅雨天。", "齊雲樓上事，已上十三年。"]'),
('a145f815-8e48-4f29-8f2b-ef8e1eb82947','曲江','白居易','唐','唐诗','tang','','[]','細草岸西東，酒旗搖水風。',48,'全唐诗/poet.tang.24000.json','["細草岸西東，酒旗搖水風。", "樓臺在花杪，鷗鷺下煙中。", "翠幄晴相接，芳洲夜暫空。", "何人賞秋景，興與此時同。"]'),
('1a749faf-8fea-46b9-b194-b17a4f034ffa','歲夜詠懷兼寄思黯','白居易','唐','唐诗','tang','','[]','徧數故交親，何人得六旬。',48,'全唐诗/poet.tang.24000.json','["徧數故交親，何人得六旬。", "今年已入手，餘事豈關身。", "老自無多興，春應不揀人。", "陶窗與弘閣，風景一時新。"]'),
('9eadd591-9b76-4772-a1b4-b8930e47b849','寒食日過棗糰店','白居易','唐','唐诗','tang','','[]','寒食棗糰店，春低楊柳枝。',48,'全唐诗/poet.tang.24000.json','["寒食棗糰店，春低楊柳枝。", "酒香留客住，鶯語和人詩。", "困立攀花久，慵行上馬遲。", "若爲將此意，前字與僧期。"]'),
('bf1e46fd-32d1-4ee7-938d-49cc27acf1f3','宿張雲舉院','白居易','唐','唐诗','tang','','[]','不食胡麻飯，杯中自得仙。',72,'全唐诗/poet.tang.24000.json','["不食胡麻飯，杯中自得仙。", "隔房招好客，可室致芳筵。", "美醞香醪嫩，時新異果鮮。", "夜深唯畏曉，坐穩不思眠。", "棊罷嫌無敵，詩成媿在前。", "明朝題壁上，誰得衆人傳。"]'),
('bea62be5-4953-4fb1-80aa-dd4d0eb8c215','惜花','白居易','唐','唐诗','tang','','[]','可憐夭豔正當時，剛被狂風一夜吹。',32,'全唐诗/poet.tang.24000.json','["可憐夭豔正當時，剛被狂風一夜吹。", "今日流鶯來舊處，百般言語泥空枝。"]'),
('97bd0ba1-a40b-4bf0-b044-f7a3e70eb02c','七夕','白居易','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u79bb\u6101", "\u7231\u60c5", "\u4e03\u5915\u8282"]','煙霄微月澹長空，銀漢秋期萬古同。',32,'全唐诗/poet.tang.24000.json','["煙霄微月澹長空，銀漢秋期萬古同。", "幾許歡情與離恨，年年幷在此宵中。"]'),
('f447099a-821e-497b-99c1-47064fdff2fa','宿誠禪師山房題贈','白居易','唐','唐诗','tang','','[]','不出孤峰上，人間四十秋。',48,'全唐诗/poet.tang.24000.json','["不出孤峰上，人間四十秋。", "視身如傳舍，閱世任東流。", "法爲因緣立，心從次第脩。", "中宵問真偈，有住是吾憂。"]'),
('e9a748c0-ba13-4810-b138-ab5fd7df93a3','新池','白居易','唐','唐诗','tang','','[]','數日自穿鑿，引泉來近陂。',48,'全唐诗/poet.tang.24000.json','["數日自穿鑿，引泉來近陂。", "尋渠通咽處，繞岸待清時。", "深好求魚養，閑堪與鶴期。", "幽聲聽難盡，入夜睡常遲。"]'),
('90c594f6-47ec-4008-a541-c5ad7b1b13de','南池','白居易','唐','唐诗','tang','','[]','蕭條微雨絕，荒岸抱清源。',48,'全唐诗/poet.tang.24000.json','["蕭條微雨絕，荒岸抱清源。", "入舫山侵塞，分泉道接邨。", "秋聲依樹色，月影在蒲根。", "淹泊方難遂，他宵關夢魂。"]'),
('9a2c3dfd-288b-4b0d-8c46-583e6a841b4b','宿池上','白居易','唐','唐诗','tang','','[]','泉來從絕壑，亭敞在中流。',48,'全唐诗/poet.tang.24000.json','["泉來從絕壑，亭敞在中流。", "竹密無空岸，松長可絆舟。", "蟪蛄潭上夜，河漢島前秋。", "異夕期新漲，攜琴却此遊。"]'),
('c3f5a717-b877-4d0b-b5df-f1bf0821dcb4','翻經臺','白居易','唐','唐诗','tang','','[]','一會靈山猶未散，重翻貝葉有來由。',32,'全唐诗/poet.tang.24000.json','["一會靈山猶未散，重翻貝葉有來由。", "是名精進纔開眼，巖石無端亦點頭。"]'),
('67ae99f0-5748-4dd0-bdb5-7ed8b72c754d','寄題上強山精舍寺','白居易','唐','唐诗','tang','','[]','慣遊山水住南州，行盡天台及虎丘。',32,'全唐诗/poet.tang.24000.json','["慣遊山水住南州，行盡天台及虎丘。", "惟有上強精舍寺，最堪遊處未曾遊。"]'),
('177fba37-6b56-40cc-9592-88d4e23aa65b','一字至七字詩','白居易','唐','唐诗','tang','','[]','詩，綺美，瓌奇。',68,'全唐诗/poet.tang.24000.json','["詩，綺美，瓌奇。", "明月夜，落花時。", "能助歡笑，亦傷別離。", "調清金石怨，吟苦鬼神悲。", "天下只應我愛，世間唯有君知。", "自從都尉別蘇句，便到司空送白辭。"]'),
('9ab7da5f-f21f-4ef1-8c55-c43d91d3381c','九老圖詩','白居易','唐','唐诗','tang','','[]','雪作鬚眉雲作衣，遼東華表鶴雙歸。',32,'全唐诗/poet.tang.24000.json','["雪作鬚眉雲作衣，遼東華表鶴雙歸。", "當時一鶴猶希有，何況今逢兩令威。"]'),
('3432d1a3-736c-4483-a727-d0d405acea34','和裴相公傍水閑行絕句','白居易','唐','唐诗','tang','','[]','行尋春水坐看山，早出中書晚未還。',32,'全唐诗/poet.tang.24000.json','["行尋春水坐看山，早出中書晚未還。", "爲報野僧巖客道，偷閑氣味勝長閑。"]'),
('2f3b8f8a-a441-4ec9-95a6-aee566a486a4','七老會詩','胡杲','唐','唐诗','tang','','[]','閑居同會在三春，大抵愚年最出羣。',96,'全唐诗/poet.tang.24000.json','["閑居同會在三春，大抵愚年最出羣。", "霜鬢不嫌杯酒興，白頭仍愛玉爐熏。", "裴回玩柳心猶健，老大看花意却勤。", "鑿落滿斟判酩酊，香囊高挂任氤氳。", "搜神得句題紅葉，望景長吟對白雲。", "今日交情何不替？齊年同事聖明君。"]'),
('4056bdfc-5723-4a12-984e-08331e3021b3','七老會詩','吉皎','唐','唐诗','tang','','[]','休官罷任已閑居，林苑園亭興有餘。',96,'全唐诗/poet.tang.24000.json','["休官罷任已閑居，林苑園亭興有餘。", "對酒最宜花藻發，邀歡不厭柳條初。", "低腰醉舞垂緋袖，擊筑謳歌任褐裾。", "寧用管弦來合雜，自親松竹且清虛。", "飛觥酒到須先酌，賦詠成詩不住書。", "借問商山賢四皓，不如此後更何如。"]'),
('cc230638-0d66-4173-97da-1b105c8583a5','七老會詩','劉真','唐','唐诗','tang','','[]','垂絲今日幸同筵，朱紫居身是大年。',96,'全唐诗/poet.tang.24000.json','["垂絲今日幸同筵，朱紫居身是大年。", "賞景尚知心未退，吟詩猶覺力完全。", "閑庭飲酒當三月，在席揮毫象七賢。", "山茗煮時秋霧碧，玉杯斟處彩霞鮮。", "臨堦花笑如歌妓，傍竹松聲當管弦。", "雖未學窮生死訣，人間豈不是神仙。"]'),
('c747250f-d2c1-4419-b630-b3ba4badbac2','七老會詩','鄭據','唐','唐诗','tang','','[]','東洛幽閑日暮春，邀歡多是白頭賓。',96,'全唐诗/poet.tang.24000.json','["東洛幽閑日暮春，邀歡多是白頭賓。", "官班朱紫多相似，年紀高低次第勻。", "聯句每言松竹意，停杯多說古今人。", "更無外事來心肺，空有清虛入思神。", "醉舞兩回迎勸酒，狂歌一曲會娛身。", "今朝何事偏情重，同作明時列任臣。"]'),
('336bb957-2e93-4de4-9b17-379e41afac34','七老會詩','盧真','唐','唐诗','tang','','[]','三春已盡洛陽宮，天氣初晴景象中。',96,'全唐诗/poet.tang.24000.json','["三春已盡洛陽宮，天氣初晴景象中。", "千朵嫩桃迎曉日，萬株垂柳逐和風。", "非論官位皆相似，及至年高亦共同。", "對酒歌聲猶覺妙，玩花詩思豈能窮。", "先時共作三朝貴，今日猶逢七老翁。", "但願醁醽常滿酌，煙霞萬里會應同。"]'),
('263c8159-087f-4d95-8c18-63406c69450c','七老會詩','張渾','唐','唐诗','tang','','[]','幽亭春盡共爲歡，印綬居身是大官。',96,'全唐诗/poet.tang.24000.json','["幽亭春盡共爲歡，印綬居身是大官。", "遁跡豈勞登遠岫，垂絲何必坐谿磻。", "詩聯七韻猶應易，酒飲三杯未覺難。", "每況襟懷同宴會，共將心事比波瀾。", "風吹野柳垂羅帶，日照庭花落綺紈。", "此席不煩鋪錦帳，斯筵堪作畫圖看。"]'),
('8557aa7d-f5cd-4ea2-841a-3df57d855943','一字至七字詩 竹','韋式','唐','唐诗','tang','','[]','竹，臨池，似玉。',68,'全唐诗/poet.tang.24000.json','["竹，臨池，似玉。", "裛露靜，和煙綠。", "抱節寧改，貞心自束。", "渭曲偏種多，王家看不足。", "仙杖正驚龍化，美實當隨鳳熟。", "唯愁吹作別離聲，回首駕驂舞陣速。"]'),
('b606e102-4e53-48df-95b7-0574bd7c6979','奉和白太守揀橘','張彤','唐','唐诗','tang','','["\u592a\u6e56"]','凌霜遠涉太湖深，雙卷朱旗望橘林。',64,'全唐诗/poet.tang.24000.json','["凌霜遠涉太湖深，雙卷朱旗望橘林。", "樹樹籠煙疑帶火，山山照日似懸金。", "行看採掇方盈手，暗覺馨香已滿襟。", "揀選封題皆盡力，無人不感近臣心。"]'),
('0f0d6341-09f4-4227-9256-1649c3049705','和白太守揀貢橘','周元範','唐','唐诗','tang','','[]','離離朱實綠叢中，似火燒山處處紅。',64,'全唐诗/poet.tang.24000.json','["離離朱實綠叢中，似火燒山處處紅。", "影下寒林沈綠水，光搖高樹照晴空。", "銀章自竭人臣力，玉液誰知造化功。", "看取明朝船發後，餘香猶尚逐仁風。"]'),
('2921af23-6e9d-49fb-9f7c-46282b1797fc','句','周元範','唐','唐诗','tang','','[]','誰云蒿上煙，隨雲依碧落。',28,'全唐诗/poet.tang.24000.json','["誰云蒿上煙，隨雲依碧落。", "莫怪西陵風景別，鏡湖花草爲先春。"]'),
('5cd493e0-73cb-4163-812c-3cf445e1074d','書巫山神女祠','繁知一','唐','唐诗','tang','','[]','忠州刺史今才子，行到巫山必有詩。',32,'全唐诗/poet.tang.24000.json','["忠州刺史今才子，行到巫山必有詩。", "爲報高唐神女道，速排雲雨候清詞。"]'),
('72e62ce3-fe42-431a-acee-3c59b1cf2876','唐昌觀玉蘂花折有仙人遊悵然成二絕 一','嚴休復','唐','唐诗','tang','','[]','終日齋心禱玉宸，魂銷目斷未逢真。',32,'全唐诗/poet.tang.24000.json','["終日齋心禱玉宸，魂銷目斷未逢真。", "不如滿樹瓊瑤蘂，笑對藏花洞裏人。"]'),
('1e849a36-6dba-4dca-a9ed-7b806d1975cc','唐昌觀玉蘂花折有仙人遊悵然成二絕 二','嚴休復','唐','唐诗','tang','','[]','羽車潛下玉龜山，塵世何由覩蕣顏。',32,'全唐诗/poet.tang.24000.json','["羽車潛下玉龜山，塵世何由覩蕣顏。", "唯有多情枝上雪，好風吹綴綠雲鬟。"]'),
('de6743f4-806a-49e8-8a21-d415aae1df9a','江亭寓目','盧拱','唐','唐诗','tang','','[]','江郭帶林巒，津亭倚檻看。',48,'全唐诗/poet.tang.24000.json','["江郭帶林巒，津亭倚檻看。", "水風蒲葉戰，沙雨鷺鶿寒。", "晚木初凋柳，秋叢欲敗蘭。", "哀猨自相叫，鄉淚好無端。"]'),
('7cc2a2b5-9288-41c5-9394-fda3c93e5cca','中元日觀法事','盧拱','唐','唐诗','tang','','[]','四孟逢秋序，三元得氣中。',72,'全唐诗/poet.tang.24000.json','["四孟逢秋序，三元得氣中。", "雲迎碧落步，章奏玉皇宮。", "壇滴槐花露，香飄栢子風。", "羽衣凌縹緲，瑤轂輾虛空。", "久慕餐霞客，常悲習蓼蟲。", "青囊如可授，從此訪鴻蒙。"]'),
('652a83fe-31eb-481e-b136-2a340129c03c','句','盧拱','唐','唐诗','tang','','[]','地甃如拳石，溪橫似葉舟。',12,'全唐诗/poet.tang.24000.json','["地甃如拳石，溪橫似葉舟。"]'),
('308213b8-4138-4386-a68d-f0591f3d019b','蘇州元日郡齋感懷寄越州元相公杭州白舍人','李諒','唐','唐诗','tang','','[]','稱慶還鄉郡吏歸，端憂明發儼朝衣。',128,'全唐诗/poet.tang.24000.json','["稱慶還鄉郡吏歸，端憂明發儼朝衣。", "首開三百六旬日，新知四十九年非。", "當官補拙猶勤慮，游宦量才已息機。", "舉族共資隨月俸，一身惟憶故山薇。", "舊交邂逅封疆近，老牧蕭條宴賞稀。", "書札每來同笑語，篇章時到借光輝。", "絲綸暫厭分符竹，舟檝初登擁羽旗。", "未知今日情何似，應與幽人事有違。"]'),
('2045c179-4465-4d77-9760-8abb6c8ae168','月生','劉猛','唐','唐诗','tang','','[]','月生十五前，日望光彩圓。',60,'全唐诗/poet.tang.24000.json','["月生十五前，日望光彩圓。", "月滿十五後，日畏光彩瘦。", "不見夜花色，一尊成暗酒。", "匣中苔背銅，光短不照空。", "不惜補明月，慚無此良工。"]'),
('e69c54f3-6656-40d8-8072-e11ca8f41f5e','苦雨','劉猛','唐','唐诗','tang','','[]','自念數年間，兩手中藏鉤。',48,'全唐诗/poet.tang.24000.json','["自念數年間，兩手中藏鉤。", "於心且無恨，他日爲我羞。", "古老傳童歌，連淫亦兵象。", "夜夢戈甲鳴，苦不願年長。"]'),
('6985e295-03ae-4cc2-8fc3-3d2b48a5a8ed','曉','劉猛','唐','唐诗','tang','','[]','朝梳一把白，夜淚千滴雨。',24,'全唐诗/poet.tang.24000.json','["朝梳一把白，夜淚千滴雨。", "可恥垂拱時，老作在家女。"]'),
('ee1841a7-9041-4e63-bc2b-d69c8170c38a','獻盧尚書','萬彤雲','唐','唐诗','tang','','[]','荷衣拭淚幾回穿，欲謁朱門抵上天。',32,'全唐诗/poet.tang.24000.json','["荷衣拭淚幾回穿，欲謁朱門抵上天。", "不是尚書輕下客，山家無物與王權。"]'),
('427d14b2-8dbe-4d99-84e8-a9da68cafc0a','和白尚書賦永豐柳','盧貞','唐','唐诗','tang','','[]','一樹依依在永豐，兩枝飛去杳無蹤。',32,'全唐诗/poet.tang.24000.json','["一樹依依在永豐，兩枝飛去杳無蹤。", "玉皇曾採人間曲，應逐歌聲入九重。"]'),
('8a4c077d-1458-455a-a14c-7883b2dff50b','和劉夢得歲夜懷友','盧貞','唐','唐诗','tang','','[]','文翰走天下，琴尊臥洛陽。',48,'全唐诗/poet.tang.24000.json','["文翰走天下，琴尊臥洛陽。", "貞元朝士盡，新歲一悲涼。", "名早緣才大，官遲爲壽長。", "時來知病已，莫歎步趨妨。"]'),
('d5d219f8-8b1d-48ff-a988-e478cc65e668','和李校書雨中自秘省見訪知早入朝便入集賢不遇詩','王起','唐','唐诗','tang','','[]','台庭才子來欵扉，典校初從天祿歸。',176,'全唐诗/poet.tang.24000.json','["台庭才子來欵扉，典校初從天祿歸。", "已慙陋巷迴玉趾，仍聞細雨霑綵衣。", "詰朝始趨鳳闕去，此日遂愁雞黍違。", "憶昨謬官在烏府，喜君對門討魚魯。", "直廬相望夜每闌，高閣遙臨月時吐。", "昔聞三入承明廬，今來重入中秘書。", "校文復忝丞相屬，博物更與張侯居。", "新冠峩峩不變鐵，舊泉脉脈猶在渠。", "忽枉情人吐芳訊，臨風不羨潘錦舒。", "憶見青天霞未卷，吟翫瑤華不知晚。", "自憐豈是風引舟，如何漸與蓬山遠。"]'),
('cf241e4f-c01f-4429-80ef-62cebff79a68','貢舉人謁先師聞雅樂','王起','唐','唐诗','tang','','[]','藹藹觀光士，來同鵠鷺羣。',72,'全唐诗/poet.tang.24000.json','["藹藹觀光士，來同鵠鷺羣。", "鞠躬遺像在，稽首雅歌聞。", "度曲飄清漢，餘音遏曉雲。", "兩楹淒已合，九仞杳難分。", "斷續同清吹，洪纖入紫氛。", "長言聽已罷，千載仰斯文。"]'),
('a4767cbe-61c2-4885-a1e7-796313d295c8','濁水求珠','王起','唐','唐诗','tang','','[]','行潦沈明月，光輝也不浮。',72,'全唐诗/poet.tang.24000.json','["行潦沈明月，光輝也不浮。", "識珍能洞鑒，精寶此來求。", "幾被泥沙雜，常隨混濁流。", "潤川終自媚，照乘且何由。", "的皪終難掩，晶熒願見收。", "蛇行無脛至，飲德已聞酬。"]'),
('6f0084f4-da0e-437d-8c17-026280cd427a','和周侍郎見寄','王起','唐','唐诗','tang','','[]','貢院離來二十霜，誰知更忝主文場。',64,'全唐诗/poet.tang.24000.json','["貢院離來二十霜，誰知更忝主文場。", "楊葉縱能穿舊的，桂枝何必愛新香。", "九重每憶同仙禁，六義初吟得夜光。", "莫道相知不相見，蓮峰之下欲徵黃。"]'),
('97504d49-e5d5-44e7-b0a7-feeb27e97e9d','贈毛仙翁','王起','唐','唐诗','tang','','[]','冰霜肌骨稱童年，羽駕何由到俗間。',64,'全唐诗/poet.tang.24000.json','["冰霜肌骨稱童年，羽駕何由到俗間。", "丹竈化金留秘訣，仙宮嗽玉叩玄關。", "壺中世界青天近，洞裏煙霞白日閑。", "若許隨師去塵網，願陪鸞鶴向三山。"]'),
('8030c854-1ecd-4f04-be2d-9a159df53747','賦花','王起','唐','唐诗','tang','','[]','花，點綴，分葩。',68,'全唐诗/poet.tang.24000.json','["花，點綴，分葩。", "露初裛，月未斜。", "一枝曲水，千樹山家。", "戲蝶未成夢，嬌鶯語更誇。", "既見東園成徑，何殊西子同車。", "漸覺風飄輕似雪，能令醉者亂如麻。"]'),
('0e00e8e3-9b98-49b0-a739-950d50ab9a5e','賦得濁水求珠','王損之','唐','唐诗','tang','','[]','積水非澄徹，明珠不易求。',72,'全唐诗/poet.tang.24000.json','["積水非澄徹，明珠不易求。", "依稀沈極浦，想像在中流。", "瞪目思清淺，褰裳恨暗投。", "徒看川色媚，空愛夜光浮。", "月入疑龍吐，星歸似蚌游。", "終希識珍者，採掇冀冥搜。"]'),
('4a499057-19e7-4a35-b55a-cb329af36d90','賦得行不由徑','王炎','唐','唐诗','tang','','[]','邪徑趨時捷，端心惡此名。',72,'全唐诗/poet.tang.24000.json','["邪徑趨時捷，端心惡此名。", "長衢貴高步，大路自規行。", "且慮縈紆僻，將求坦蕩情。", "詎同流俗好，方保立身貞。", "遠跡如違險，修仁在履平。", "始知夫子道，從此得堅誠。"]'),
('182f8141-9e02-4ac1-b11c-e21b5513e4c7','賦得行不由徑','封孟紳','唐','唐诗','tang','','[]','欲速意何成，康莊欲砥平。',72,'全唐诗/poet.tang.24000.json','["欲速意何成，康莊欲砥平。", "天衢皆利往，吾道泰方行。", "不復由萊徑，無由見蔣生。", "三條遵廣達，九軌尚安貞。", "紫陌悠悠去，芳塵步步清。", "澹臺千載後，公正有遺名。"]'),
('5f17636b-e203-4d17-853f-aed1b634c61c','題馬侍中燧木香亭','邵楚萇','唐','唐诗','tang','','[]','春日遲遲木香閣，窈窕佳人褰繡幕。',64,'全唐诗/poet.tang.24000.json','["春日遲遲木香閣，窈窕佳人褰繡幕。", "淋漓玉露滴紫蕤，綿蠻黃鳥窺朱萼。", "橫漢碧雲歌處斷，滿地花鈿舞時落。", "樹影參差斜入簷，風動玲瓏水晶箔。"]'),
('978a6fcf-5269-45bc-b5e4-93c9d36600d0','賦得玉水記方流','鄭俞','唐','唐诗','tang','','[]','積水綦文動，因知玉產幽。',72,'全唐诗/poet.tang.24000.json','["積水綦文動，因知玉產幽。", "如天涵素色，侔地引方流。", "潛潤滋雲起，熒華射浪浮。", "魚龍泉不夜，草木岸無秋。", "璧沼寧堪比，瑤池詎可儔。", "若非懸坐測，誰復寄冥搜。"]'),
('36ca0382-8ca8-480e-9aa9-ec5476adea7c','賦得玉水記方流','吳丹','唐','唐诗','tang','','[]','玉泉何處記，四折水紋浮。',72,'全唐诗/poet.tang.24000.json','["玉泉何處記，四折水紋浮。", "潤下寧踰矩，居方在上流。", "映空虛漾漾，涵白淨悠悠。", "影碎疑衝斗，光清耐觸舟。", "珪璋分辨狀，沙礫共懷柔。", "願赴朝宗日，縈迴入御溝。"]'),
('ddb2db2a-f00e-456b-af3d-fa1c065d22da','賦得玉水記方流','王鑑','唐','唐诗','tang','','[]','玉潤在中洲，光臨碕岸幽。',72,'全唐诗/poet.tang.24000.json','["玉潤在中洲，光臨碕岸幽。", "氤氳冥瑞影，演瀁度方流。", "乍似輕漣合，還疑駭浪收。", "夤緣知有異，洞徹信無儔。", "比德稱殊賞，含輝處至柔。", "沈淪如見念，況乃屬時休。"]'),
('2be2db9a-ea51-4e5f-a052-6dbb3ea6b661','賦得玉水記方流','陳昌言','唐','唐诗','tang','','[]','明媚如懷玉，奇姿自詫幽。',72,'全唐诗/poet.tang.24000.json','["明媚如懷玉，奇姿自詫幽。", "白虹深不見，綠水折空流。", "方珏清沙遍，縱橫氣色浮。", "類圭才有角，寫月讓成鉤。", "久處沈潛貴，希當特達收。", "滔滔在何許，揭厲願從游。"]'),
('a77cc4bb-0039-49dd-b62f-dcbf364155de','白日麗江臯','陳昌言','唐','唐诗','tang','','[]','遲景臨遙水，晴空似不高。',72,'全唐诗/poet.tang.24000.json','["遲景臨遙水，晴空似不高。", "清明開曉鏡，昭晰辨秋毫。", "鬱鬱長隄土，離離淺渚毛。", "煙銷占一候，風靜擁千艘。", "獨媚青春柳，宜看白鷺濤。", "何年謝公賞，遺韻在江臯。"]'),
('cd28b64d-37dd-4fcb-b7cd-fbac0efe6a66','賦得玉水記方流','杜元穎','唐','唐诗','tang','','[]','重泉生美玉，積水異常流。',72,'全唐诗/poet.tang.24000.json','["重泉生美玉，積水異常流。", "始玩清堪賞，因知寶可求。", "斗回虹氣見，磬折紫光浮。", "中矩皆明德，同方叶至柔。", "月華偏共映，風暖佇將遊。", "遇鑒終無暗，逢時願見收。"]'),
('e9d6f683-e123-46ec-b4a5-1229f5ce24af','太常觀閱驃國新樂','胡直鈞','唐','唐诗','tang','','[]','異音來驃國，初被奉常人。',72,'全唐诗/poet.tang.24000.json','["異音來驃國，初被奉常人。", "纔可宮商辨，殊驚節奏新。", "轉規迴繡面，曲折度文身。", "舒散隨鸞吹，喧呼雜鳥春。", "襟袵懷舊識，絲竹變恆陳。", "何事留中夏，長令表化淳。"]'),
('8877c330-ce31-4a0b-a939-33b21e56b422','行不由徑','俞簡','唐','唐诗','tang','','[]','古人心有尚，乃是孔門生。',72,'全唐诗/poet.tang.24000.json','["古人心有尚，乃是孔門生。", "爲計安貧樂，當從大道行。", "詎應流遠迹，方欲料前程。", "捷徑雖云易，長衢豈不平。", "後來無枉路，先達擅前名。", "一示遵途意，微衷益自精。"]'),
('dde4b27e-fc46-4a17-b086-2ec8be0d8776','丁巳歲八月祭武侯祠堂因題臨淮公舊碑','楊嗣復','唐','唐诗','tang','','[]','齋莊修祀事，旌斾出郊闉。',72,'全唐诗/poet.tang.24000.json','["齋莊修祀事，旌斾出郊闉。", "薙草軒墀狹，塗牆赭堊新。", "謀猷期作聖，風俗奉爲神。", "酹酒成坳澤，持兵列偶人。", "非才膺寵任，異代揖芳塵。", "況是平津客，碑前淚滿巾。"]'),
('8b4a887b-0584-427c-9bbe-c7637a7a1467','儀鳳','楊嗣復','唐','唐诗','tang','','[]','八方該帝澤，威鳳忽來賓。',72,'全唐诗/poet.tang.24000.json','["八方該帝澤，威鳳忽來賓。", "向日朱光動，迎風翠羽新。", "低昂多異趣，飲啄迥無鄰。", "郊藪今翔集，河圖意等倫。", "聞韶知鼓舞，偶聖願逡巡。", "比屋初同俗，垂恩擊壤人。"]'),
('906813c1-fa70-4099-9bf1-42ba32cc84da','贈毛仙翁','楊嗣復','唐','唐诗','tang','','["\u6cf0\u5c71"]','天上玉郎騎白鶴，肘後金壺盛妙藥。',176,'全唐诗/poet.tang.24000.json','["天上玉郎騎白鶴，肘後金壺盛妙藥。", "暫遊下界傲五侯，重看當時舊城郭。", "羽衣茸茸輕似雪，雲上雙童持絳節。", "王母親縫紫錦囊，令向懷中藏秘訣。", "令威子晉皆儔侶，東嶽同尋太真女。", "搜奇綴韻和陽春，文章不是人間語。", "藥成自固黃金骨，天地齊兮身不沒。", "日月宮中便是家，下視崑崙何突兀。", "童姿玉貌誰方比，玄髮綠髯光彌彌。", "滿朝將相門弟子，隨師盡願拋塵滓。", "九轉琅玕必有餘，願乞刀圭救生死。"]'),
('a9ff06ff-f269-4113-ac15-def0dc37876b','題李處士山居','楊嗣復','唐','唐诗','tang','','["\u5e90\u5c71"]','臥龍決起爲時君，寂寞匡廬惟白雲。',32,'全唐诗/poet.tang.24000.json','["臥龍決起爲時君，寂寞匡廬惟白雲。", "今日仲容修故業，草堂焉敢更移文。"]'),
('479f4614-220f-481a-b5ac-0fe0fbe3c708','謝寄新茶','楊嗣復','唐','唐诗','tang','','[]','石上生芽二月中，蒙山顧渚莫爭雄。',32,'全唐诗/poet.tang.24000.json','["石上生芽二月中，蒙山顧渚莫爭雄。", "封題寄與楊司馬，應爲前銜是相公。"]'),
('703a0215-431b-446d-b6fb-539da2d98f78','盧十五竹亭送姪偁歸山','楊衡','唐','唐诗','tang','','[]','落葉寒擁壁，清霜夜霑石。',36,'全唐诗/poet.tang.24000.json','["落葉寒擁壁，清霜夜霑石。", "正是憶山時，復送歸山客。", "殷勤一尊酒，曉月當窗白。"]'),
('e7037682-3bb0-4bee-ac82-11823a69b2d3','旅次江亭','楊衡','唐','唐诗','tang','','["\u7f81\u65c5", "\u601d\u4e61"]','扣舷不能寐，皓露清衣襟。',48,'全唐诗/poet.tang.24000.json','["扣舷不能寐，皓露清衣襟。", "彌傷孤舟夜，遠結萬里心。", "幽興惜瑤草，素懷寄鳴琴。", "三奏月初上，寂寥寒江深。"]'),
('a2f66a9a-96ca-45d3-bc0d-2eb994be6674','賦得夜雨滴空堦送魏秀才','楊衡','唐','唐诗','tang','','[]','委簷方滴滴，霑紅復洒綠。',48,'全唐诗/poet.tang.24000.json','["委簷方滴滴，霑紅復洒綠。", "醉聽乍朦朧，愁聞多斷續。", "始兼泉嚮細，稍雜更聲促。", "百慮自縈心，況有人如玉。"]'),
('e4cd131c-5bfd-427b-a762-8ff4882208a1','征人','楊衡','唐','唐诗','tang','','[]','西風屢鳴雁，東郊未升日。',48,'全唐诗/poet.tang.24000.json','["西風屢鳴雁，東郊未升日。", "繁煙幕幕昏，暗騎蕭蕭出。", "望雲愁玉塞，眠月想蕙質。", "借問露霑衣，何如香滿室。"]'),
('8ba918bb-55d5-49c2-9052-e590801839ce','遊陸先生故巖居','楊衡','唐','唐诗','tang','','[]','獨壑臨萬嶂，蒼苔絕行跡。',72,'全唐诗/poet.tang.24000.json','["獨壑臨萬嶂，蒼苔絕行跡。", "仰窺猨挂樹，俯對鶴巢石。", "上有一巖屋，相傳靈人宅。", "深林無陽暉，幽水轉鮮碧。", "拾薪遇遺鼎，探穴得古籍。", "結念候雲興，燒香坐終夕。"]'),
('e7d87879-1a79-4e86-b7b2-686365c02b53','題玄和師仙藥室','楊衡','唐','唐诗','tang','','[]','山邊蕭寂室，石掩浮雲扃。',72,'全唐诗/poet.tang.24000.json','["山邊蕭寂室，石掩浮雲扃。", "遶室微有路，松煙深冥冥。", "入松汲寒水，對鶴問仙經。", "石几香未盡，水花風欲零。", "何年去華表，幾度窮蒼冥。", "却顧宦遊子，眇如霜中螢。"]'),
('5cb3f893-1f2c-40fa-bd31-480c52f11940','宿陸氏齋賦得殘燈詩','楊衡','唐','唐诗','tang','','[]','殷勤照永夜，屬思未成眠。',36,'全唐诗/poet.tang.24000.json','["殷勤照永夜，屬思未成眠。", "餘暉含薄霧，落燼迸空筵。", "誰比秦樓曉，緘愁別幌前。"]'),
('f17adbcb-41cd-43ad-b89a-0c543e132e66','夷陵郡內敘別','楊衡','唐','唐诗','tang','','[]','禮娶嗣明德，同牢夙所欽。',168,'全唐诗/poet.tang.24000.json','["禮娶嗣明德，同牢夙所欽。", "況蒙生死契，豈顧蓬蒿心。", "雁幣任野薄，恩愛緣義深。", "同聲若鼓瑟，合韻似鳴琴。", "將迓空未立，就贅意難任。", "皎月託言誓，滄波信浮沈。", "荆臺理晨轍，巫渚疑宵襟。", "憫憫百慮起，回回萬恨深。", "候更促徒侶，先曉徹夜禽。", "燈彩凝寒風，蟬思噪密林。", "留念同心帶，贈遠芙蓉簪。", "撫懷極投漆，感物重黃金。", "分鸞豈遐阻，別劒念相尋。", "儻甘蓬戶賤，願俟故山岑。"]'),
('30bab693-c9f2-4d94-92c7-c57280e10cc5','將之荆州南與張伯剛馬惣鍾陵夜別','楊衡','唐','唐诗','tang','','[]','荆臺別路長，密緒分離狀。',48,'全唐诗/poet.tang.24000.json','["荆臺別路長，密緒分離狀。", "莫訴杯來促，更籌屢已倡。", "燭花侵霧暗，瑟調寒風亮。", "誰念曉帆開，默睇參差浪。"]'),
('a5d6bf35-4373-4e6b-bcdd-b17ec8472e87','經端溪峽中','楊衡','唐','唐诗','tang','','[]','陰岸東流水，上有微風生。',96,'全唐诗/poet.tang.24000.json','["陰岸東流水，上有微風生。", "素羽漾翠澗，碧苔敷丹英。", "重林宿雨晦，遠岫孤霞明。", "飛猱相攀牽，白雲亂縱橫。", "有客泝輕檝，閱勝匪羈程。", "逍遙一息間，糞土五侯榮。", "搴茗庶蠲熱，漱泉聊析酲。", "寄言絲竹者，詎識松風聲。"]'),
('b58d2e9c-9bb1-487a-834d-7de9bf46b25c','南海苦雨寄贈王四侍御','楊衡','唐','唐诗','tang','','[]','炎風雜海氣，暑雨每成霖。',72,'全唐诗/poet.tang.24000.json','["炎風雜海氣，暑雨每成霖。", "塗泥親杖屨，苔蘚漬衣襟。", "念近劇懷遠，涉淺定知深。", "暗溝夜滴滴，荒庭晝霪霪。", "折簡展離曠，理逕俟招尋。", "處陰誠多慘，況乃觸隅禽。"]'),
('065f8096-2539-4792-b48e-5fc033f855b2','秋夜閑居即事寄廬山鄭員外蜀郡符處士','楊衡','唐','唐诗','tang','','["\u5e90\u5c71"]','憂思繁未整，良辰會無由。',96,'全唐诗/poet.tang.24000.json','["憂思繁未整，良辰會無由。", "引領遲佳音，星紀屢以周。", "蓬閬絕華耀，況乃處窮愁。", "墜葉寒擁砌，燈火夜悠悠。", "開琴弄清弦，窺月俯澄流。", "冉冉鴻雁度，蕭蕭帷箔秋。", "悵懷石門詠，緬慕碧雞遊。", "髣髴蒙顏色，崇蘭隱芳洲。"]'),
('c5878f29-2eed-4700-b49d-7b79bc698a70','寄贈田倉曹灣','楊衡','唐','唐诗','tang','','[]','芳蘭媚庭除，灼灼紅英舒。',72,'全唐诗/poet.tang.24000.json','["芳蘭媚庭除，灼灼紅英舒。", "身爲陋巷客，門有絳轅車。", "朝覽夷胡傳，暮習潁陽書。", "盻雲高羽翼，待賈蘊璠璵。", "纓弁雖云阻，音塵豈復疎。", "若因風雨晦，應念寂寥居。"]'),
('41adf73a-13a5-4d9a-97a9-0bc447e34640','詠春色','楊衡','唐','唐诗','tang','','[]','靄靄復濛濛，非霧滿晴空。',72,'全唐诗/poet.tang.24000.json','["靄靄復濛濛，非霧滿晴空。", "密添宮柳翠，暗泄路桃紅。", "縈絲光乍失，緣隟影纔通。", "夕迷鴛枕上，朝漫綺弦中。", "促駟馳香陌，勞鶯轉豔叢。", "可憐腸斷望，併在洛城東。"]'),
('b821bfa8-5eba-4039-91b2-18abba79c50d','送春','楊衡','唐','唐诗','tang','','[]','三月三十日，春歸日復暮。',120,'全唐诗/poet.tang.24000.json','["三月三十日，春歸日復暮。", "惆悵問春風，明朝應不住。", "送春曲江上，眷眷東西顧。", "但見撲水花，紛紛不知數。", "人生似行客，兩足無停步。", "日日進前程，前程幾多路。", "兵刃與水火，盡可違之去。", "惟有老到來，人間無避處。", "感時良未已，獨倚池南樹。", "今日送春心，心如別親故。"]'),
('1c1d240a-0fe9-45f6-a709-ef307cb25303','遊峽山寺','楊衡','唐','唐诗','tang','','[]','結構天南畔，勝絕固難儔。',144,'全唐诗/poet.tang.24000.json','["結構天南畔，勝絕固難儔。", "幸蒙時所漏，遂得恣閑遊。", "路石蔭松蓋，檻藤維鶴舟。", "雨霽花木潤，風和景氣柔。", "寶殿敞丹扉，靈幡垂絳旒。", "照曜芙蓉壺，金人居上頭。", "翔禽拂危剎，落日避層樓。", "端溪瀰漫駛，曲澗潺湲流。", "高居何重沓，登覽自夷猶。", "煙霞無隱態，巖洞詎遺幽。", "奔駟非久耀，馳波肯暫留。", "會從香火緣，滅跡此山丘。"]'),
('87477559-3470-400d-b812-e90f5373231f','宿陟岵寺雲律師院','楊衡','唐','唐诗','tang','','[]','像宇鬱參差，寶林疎復密。',96,'全唐诗/poet.tang.24000.json','["像宇鬱參差，寶林疎復密。", "中有彌天子，燃燈坐虛室。", "心證紅蓮喻，跡羈青眼律。", "玉爐揚翠煙，金經開縹帙。", "肆陳堅固學，破我夢幻質。", "碧水灑塵纓，涼扇當夏日。", "宿禽詎相保，迸火煙欲失。", "願迴戚促勞，趨隅事休逸。"]'),
('77b81301-7f83-45e5-9fe2-6728a14f5c9f','秋夜桂州宴送鄭十九侍御','楊衡','唐','唐诗','tang','','[]','秋至觸物愁，況當離別筵。',72,'全唐诗/poet.tang.24000.json','["秋至觸物愁，況當離別筵。", "短歌銷夜燭，繁緒遍高弦。", "桂水舟始泛，蘭堂榻詎懸。", "一盃勾離阻，三載奉周旋。", "鴉噪更漏颯，露濡風景鮮。", "斯須不共此，且爲更留連。"]'),
('82cba92a-5c27-4f27-bebc-bb56b08f6d6d','九日陪樊尚書龍山宴集','楊衡','唐','唐诗','tang','','[]','孟嘉從宴地，千乘復登臨。',72,'全唐诗/poet.tang.24000.json','["孟嘉從宴地，千乘復登臨。", "緣危陟高步，憑曠寫幽襟。", "黃花翫初馥，翠物喜盈斟。", "雲雜組繡色，樂和山水音。", "斾搖秋吹急，筵卷夕光沈。", "都人瞻騎火，猶知隔寺深。"]'),
('38b6b48b-e8ef-45f7-b2a6-aa78878ed230','江陵送客歸河北','楊衡','唐','唐诗','tang','','[]','遠客歸故里，臨路結裴回。',36,'全唐诗/poet.tang.24000.json','["遠客歸故里，臨路結裴回。", "山長水復闊，無因重此來。", "聊將歌一曲，送子手中盃。"]'),
('000e96e4-474a-47b9-a0b1-c16d2816ed0c','送鄭丞之羅浮中習業','楊衡','唐','唐诗','tang','','[]','百年泛飄忽，萬事繫衰榮。',96,'全唐诗/poet.tang.24000.json','["百年泛飄忽，萬事繫衰榮。", "高鴻脫矰繳，達士去簪纓。", "始從天目遊，復作羅浮行。", "雲臥石林密，月窺花洞明。", "全形在氣和，習默憑境清。", "夙祕絳囊訣，屢投金簡名。", "鐘管促離觴，煙霞隨去程。", "何當真府內，重得欵平生。"]'),
('d1c2350e-d560-4956-b2dd-9ea8cc72324d','送王秀才往安南','楊衡','唐','唐诗','tang','','[]','君爲蹈海客，客路誰諳悉。',48,'全唐诗/poet.tang.24000.json','["君爲蹈海客，客路誰諳悉。", "鯨度乍疑山，雞鳴先見日。", "所嗟迴櫂晚，倍結離情密。", "無貪合浦珠，念守江陵橘。"]'),
('43d4631b-13c4-44b8-b90f-4be34eea0a24','送公孫器自桂林歸蜀','楊衡','唐','唐诗','tang','','[]','桂林淺復碧，潺湲半露石。',72,'全唐诗/poet.tang.24000.json','["桂林淺復碧，潺湲半露石。", "將乘觸物舟，暫駐飛空錫。", "蜀鄉異青眼，蓬戶高朱戟。", "風度杳難尋，雲飄詎留跡。", "舊戶閑花草，馴鴿傍簷隟。", "揮手共忘懷，日墮千山夕。"]'),
('4e89e730-74b8-4924-ae06-0d2f259c03be','贈羅浮易鍊師','楊衡','唐','唐诗','tang','','[]','海上多仙嶠，靈人信長生。',120,'全唐诗/poet.tang.24000.json','["海上多仙嶠，靈人信長生。", "榮衛冰雪姿，嚥嚼日月精。", "默書絳符遍，晦步斗文成。", "翠髮披肩長，金蓋凌風輕。", "曉籟息塵響，天雞叱幽聲。", "碧樹來戶陰，丹霞照窗明。", "焚香叩虛寂，稽首迴太清。", "鸞鷺振羽儀，飛翻拂斾旌。", "左挹玉泉液，右搴雲芝英。", "念得參龍駕，攀天度赤城。"]'),
('489ae830-c46f-4617-932b-7754556b7660','登紫霄峰贈黃仙師','楊衡','唐','唐诗','tang','','[]','紫霄不可涉，靈峯信穹崇。',120,'全唐诗/poet.tang.24000.json','["紫霄不可涉，靈峯信穹崇。", "下有瓊樹枝，上有翠髮翁。", "雞鳴秋漢側，日出紅霞中。", "璨璨真仙子，執旄爲侍童。", "焚香杳忘言，默念合太空。", "世華徒熠耀，虛室自朦朧。", "雲飛瓊瑤圃，龜息芝蘭藂。", "玉籙掩不開，天窗微微風。", "茲焉悟佳旨，塵境亦幽通。", "浩渺臨廣津，永用挹無窮。"]'),
('fce6309c-7066-454e-ab83-b8be51cc1893','烏啼曲','楊衡','唐','唐诗','tang','','[]','可憐楊葉復楊花，雪淨煙深碧玉家。',48,'全唐诗/poet.tang.24000.json','["可憐楊葉復楊花，雪淨煙深碧玉家。", "烏栖不定枝條弱，城頭夜半聲啞啞。", "浮萍流蕩門前水，任罥芙蓉莫浣紗。"]'),
('faa6ba1b-f44c-4ed0-b5cf-e215b972e1ec','白紵歌二首 一','楊衡','唐','唐诗','tang','','[]','玉纓翠佩雜輕羅，香汗微漬朱顏酡，爲君起唱白紵歌。',72,'全唐诗/poet.tang.24000.json','["玉纓翠佩雜輕羅，香汗微漬朱顏酡，爲君起唱白紵歌。", "清聲褭雲繁思多，凝笳哀瑟時相和。", "金壺半傾芳夜促，梁塵霏霏暗紅燭。", "令君安坐聽終曲，墜葉飄花難再復。"]'),
('ba6cdeae-fe7a-49fc-afc2-831528d8064a','白紵歌二首 二','楊衡','唐','唐诗','tang','','[]','躡珠履，步瓊筵輕身起舞紅燭前，芳姿豔態妖且妍。',55,'全唐诗/poet.tang.24000.json','["躡珠履，步瓊筵輕身起舞紅燭前，芳姿豔態妖且妍。", "迴眸轉袖暗催弦，涼風蕭蕭漏水急。", "月華泛豔紅蓮濕，牽裙攬帶翻成泣。"]'),
('17b722b9-55f8-47d5-800e-5dbcd3382b68','長門怨','楊衡','唐','唐诗','tang','','[]','絲聲繁兮管聲急，珠簾不捲風吹入。',48,'全唐诗/poet.tang.24000.json','["絲聲繁兮管聲急，珠簾不捲風吹入。", "萬遍凝愁枕上聽，千迴候命花間立。", "望望昭陽信不來，迴眸獨掩紅巾泣。"]'),
('af87fd3e-ea52-4b9f-9f7a-c3dce8a42649','寄徹公','楊衡','唐','唐诗','tang','','[]','北風吹霜霜月明，荷葉枯盡越水清。',32,'全唐诗/poet.tang.24000.json','["北風吹霜霜月明，荷葉枯盡越水清。", "別來幾度龍宮宿，雪山童子應相逐。"]'),
('10dda84c-850d-41e0-ac25-005964f60918','哭李象','楊衡','唐','唐诗','tang','','[]','白雞黃犬不將去，寂寞空餘葬時路。',48,'全唐诗/poet.tang.24000.json','["白雞黃犬不將去，寂寞空餘葬時路。", "草死花開年復年，後人知是何人墓。", "憶君思君獨不眠，夜寒月照青楓樹。"]'),
('a6250fd5-bdd4-4c24-9074-a3023c832ae4','宿雲溪觀賦得秋燈引送客','楊衡','唐','唐诗','tang','','[]','雲房寄宿秋夜客，一燈熒熒照虛壁。',48,'全唐诗/poet.tang.24000.json','["雲房寄宿秋夜客，一燈熒熒照虛壁。", "蟲聲呼客客未眠，幾人語話清景側。", "不可離別愁紛多，秋燈秋燈奈別何。"]'),
('d36cdf77-0cd5-4d82-acad-cf1fac698b6c','採蓮曲','楊衡','唐','唐诗','tang','','[]','凝鮮霧渚夕，陽豔綠波風。',48,'全唐诗/poet.tang.24000.json','["凝鮮霧渚夕，陽豔綠波風。", "魚遊乍散藻，露重稍欹紅。", "楚客傷暮節，吳娃泣敗藂。", "促令芳本固，寧望雪霜中。"]'),
('0cf877ff-68b5-485f-9b24-3aa7094635e9','他鄉七夕','楊衡','唐','唐诗','tang','','[]','漢渚常多別，山橋忽重遊。',48,'全唐诗/poet.tang.24000.json','["漢渚常多別，山橋忽重遊。", "向雲迎翠輦，當月拜珠旒。", "寢幌凝宵態，妝奩閉曉愁。", "不堪鳴杼日，空對白榆秋。"]'),
('a33f7773-60f6-4b51-8d26-dc286c485d32','春日偶題','楊衡','唐','唐诗','tang','','[]','何處春先到，橋東水北亭。',50,'全唐诗/poet.tang.24000.json','["何處春先到，橋東水北亭。", "[凍]花開未得，冷酒酌難醒。", "就日移輕榻，遮風展小屏。", "更無人勸飲，鶯語漸叮嚀。"]'),
('1cb26c22-0315-44ce-b3a5-8cf215379d5e','題山寺','楊衡','唐','唐诗','tang','','[]','千峯白露後，雲壁挂殘燈。',48,'全唐诗/poet.tang.24000.json','["千峯白露後，雲壁挂殘燈。", "曙色海邊日，經聲松下僧。", "意閑門不閉，年去水空澄。", "稽首如何問，森羅盡一乘。"]'),
('a1291114-032f-41fe-8172-970bb6741132','廣州石門寺重送李尚赴朝時兼宗正卿','楊衡','唐','唐诗','tang','','[]','象闕趨雲陛，龍宮憩石門。',48,'全唐诗/poet.tang.24000.json','["象闕趨雲陛，龍宮憩石門。", "清鐃猶啓路，黃髮重攀轅。", "藻變朝天服，珠懷委地言。", "那令蓬蒿客，茲席未離尊。"]'),
('048738b5-3469-456f-818a-8d9856a06aa5','送孔周之南海謁王尚書','楊衡','唐','唐诗','tang','','[]','泛櫂若流萍，桂寒山更青。',48,'全唐诗/poet.tang.24000.json','["泛櫂若流萍，桂寒山更青。", "望雲生碧落，看日下滄溟。", "潮盡收珠母，沙閑拾翠翎。", "自趨龍戟下，再爲誦芳馨。"]'),
('7393721d-7797-40f4-94e3-11f18a6698ea','冬夜舉公房送崔秀才歸南陽','楊衡','唐','唐诗','tang','','[]','聞君動征櫂，犯夜故來尋。',48,'全唐诗/poet.tang.24000.json','["聞君動征櫂，犯夜故來尋。", "強置一尊酒，重欵百年心。", "燈白霜氣冷，室虛松韻深。", "南陽三顧地，幸偶價千金。"]'),
('a4cdd165-b0ae-4946-8a1c-30251b149bf9','送陳房謁撫州周使君','楊衡','唐','唐诗','tang','','["\u5e90\u5c71"]','匡山一畝宮，尚有桂蘭叢。',48,'全唐诗/poet.tang.24000.json','["匡山一畝宮，尚有桂蘭叢。", "鑿壁年雖異，穿楊志幸同。", "貌羸緣塞苦，道蹇爲囊空。", "去謁臨川守，因憐鶴在籠。"]'),
('70fe4be9-af28-4661-9891-ad2650bdb22b','山齋獨宿贈晏上人','楊衡','唐','唐诗','tang','','[]','幢幢雲樹秋，黃葉下山頭。',48,'全唐诗/poet.tang.24000.json','["幢幢雲樹秋，黃葉下山頭。", "蟲響夜難度，夢閑神不遊。", "窗燈寒几盡，簾雨曉堦愁。", "何以禪棲客，灰心在沃州。"]'),
('15fbd364-bf79-451d-b7d5-e54abaa514aa','桂州與陳羽念別','楊衡','唐','唐诗','tang','','[]','慘戚損志抱，因君時解顏。',48,'全唐诗/poet.tang.24000.json','["慘戚損志抱，因君時解顏。", "重歎今夕會，復在幾夕間。", "碧桂水連海，蒼梧雲滿山。", "茫茫從此去，何路入秦關。"]'),
('a8608e52-1c76-45c0-be19-e64ade2aa42b','經趙處士居','楊衡','唐','唐诗','tang','','[]','雲居避世客，髮白習儒經。',48,'全唐诗/poet.tang.24000.json','["雲居避世客，髮白習儒經。", "有地水空綠，無人山自青。", "廢梁悲逝水，臥木思荒庭。", "向夕霏煙斂，徒看處士星。"]'),
('941fc72b-a706-4483-b009-e0ed5404e4ce','病中赴袁州次香館','楊衡','唐','唐诗','tang','','[]','病輿憩上館，繚繞向山隅。',48,'全唐诗/poet.tang.24000.json','["病輿憩上館，繚繞向山隅。", "荒葛漫欹壁，幽禽啄朽株。", "力微怯升降，意欲結踟躇。", "誰能挹香水，一爲濯煩紆。"]'),
('5d2d7812-6c66-4644-993c-2b8d74becc7b','送人流雷州','楊衡','唐','唐诗','tang','','[]','逐客指天涯，人間此路賒。',36,'全唐诗/poet.tang.24000.json','["逐客指天涯，人間此路賒。", "地圖經大庾，水驛過長沙。", "臘月雷州雨，秋風桂嶺花。"]'),
('c3e7a1a8-5ccf-4d82-a0e3-e5a71808447c','送徹公','楊衡','唐','唐诗','tang','','[]','白首年空度，幽居俗豈知。',48,'全唐诗/poet.tang.24000.json','["白首年空度，幽居俗豈知。", "敗蕉依晚日，孤鶴立秋墀。", "久客何由造，禪門不可窺。", "會同塵外友，齋沐奉威儀。"]'),
('ef7f1de2-0433-4b56-aefe-5b6dbfb9f558','贈廬山道士','楊衡','唐','唐诗','tang','','["\u5e90\u5c71"]','寂寥高室古松寒，松下仙人字委鸞。',64,'全唐诗/poet.tang.24000.json','["寂寥高室古松寒，松下仙人字委鸞。", "頭垂白髮朝鳴磬，手把青芝夜遶壇。", "物像自隨塵外滅，真源長向性中看。", "悠悠萬古皆如此，秋比松枝春比蘭。"]'),
('7d6127c8-d4df-423d-99b0-a2d061ec0cf0','賦得直如朱絲弦','楊衡','唐','唐诗','tang','','[]','寂寞瑤琴上，深知直者情。',72,'全唐诗/poet.tang.24000.json','["寂寞瑤琴上，深知直者情。", "幸傳朱鷺曲，那止素絲名。", "瑞草人空仰，王言世久行。", "大方聞正位，樂府動清聲。", "文武音初合，宮商調屢更。", "誰能向機杼，終日泣無成。"]'),
('e89cc0d1-1cc9-4141-8b64-2b8f60a5cac4','早春即事','楊衡','唐','唐诗','tang','','[]','眼重朝眠足，頭輕宿醉醒。',72,'全唐诗/poet.tang.24000.json','["眼重朝眠足，頭輕宿醉醒。", "陽光滿前戶，雪水半中庭。", "候變隨天氣，春生逐地形。", "北簷梅晚白，東岸柳先青。", "葱壠抽羊角，松巢墮鶴翎。", "老來詩更拙，吟罷少人聽。"]'),
('4d1b8cd6-b11c-403a-8cb9-ab1d386df704','題花樹','楊衡','唐','唐诗','tang','','[]','都無看花意，偶到樹邊來。',24,'全唐诗/poet.tang.24000.json','["都無看花意，偶到樹邊來。", "可憐枝上色，一一爲愁開。"]'),
('75cdddc3-f951-45c2-8d53-1a0950b5b0ff','宿吉祥寺寄廬山隱者','楊衡','唐','唐诗','tang','','["\u5e90\u5c71"]','風鳴雲外鐘，鶴宿千年松。',24,'全唐诗/poet.tang.24000.json','["風鳴雲外鐘，鶴宿千年松。", "相思杳不見，月出山重重。"]'),
('7760dc67-7ddf-4fb8-a489-4a913f16bf95','邊思','楊衡','唐','唐诗','tang','','[]','蘇武節旄盡，李陵音信稀。',24,'全唐诗/poet.tang.24000.json','["蘇武節旄盡，李陵音信稀。", "梅當隴上發，人向隴頭歸。"]'),
('68cf2f5d-2ff2-4081-ba12-7d20cc456749','夜半步次古城','楊衡','唐','唐诗','tang','','[]','茫茫死復生，惟有古時城。',24,'全唐诗/poet.tang.24000.json','["茫茫死復生，惟有古時城。", "夜半無鳥雀，花枝當月明。"]'),
('26988e9a-11dc-40af-8644-328a0b265855','春夢','楊衡','唐','唐诗','tang','','[]','空庭日照花如錦，紅妝美人當晝寢。',32,'全唐诗/poet.tang.24000.json','["空庭日照花如錦，紅妝美人當晝寢。", "傍人不知夢中事，唯見玉釵時墜枕。"]'),
('8c76c16b-9be1-4923-a85f-58df8d776333','宿青牛谷','楊衡','唐','唐诗','tang','','[]','隨雲步入青牛谷，青牛道士留我宿。',32,'全唐诗/poet.tang.24000.json','["隨雲步入青牛谷，青牛道士留我宿。", "可憐夜久月明中，唯有壇邊一枝竹。"]'),
('93f34d0d-ac70-41f1-82be-cb794cf68a00','槿','楊衡','唐','唐诗','tang','','[]','自用金錢買槿栽，二年方始一花開。',32,'全唐诗/poet.tang.24000.json','["自用金錢買槿栽，二年方始一花開。", "憐紅未許家人見，胡蜨爭知早到來。"]'),
('21079fb4-94a4-4bc9-bd23-541044bb45ae','九日','楊衡','唐','唐诗','tang','','[]','黃菊紫菊傍籬落，摘菊泛酒愛芳新。',32,'全唐诗/poet.tang.24000.json','["黃菊紫菊傍籬落，摘菊泛酒愛芳新。", "不堪今日望鄉意，強插茱萸隨衆人。"]'),
('2b406e77-9d06-4f08-aaaa-29630cefb3e7','仙女詞','楊衡','唐','唐诗','tang','','[]','玉京初侍紫皇君，金縷鴛鴦滿絳裙。',32,'全唐诗/poet.tang.24000.json','["玉京初侍紫皇君，金縷鴛鴦滿絳裙。", "仙宮一閉無消息，遙結芳心向碧雲。"]'),
('62b41013-3655-4b77-b536-12d617cdbc28','句','楊衡','唐','唐诗','tang','','[]','賢人處霄漢，荒澤自耕耘。',32,'全唐诗/poet.tang.24000.json','["賢人處霄漢，荒澤自耕耘。", "隴首降時雨，雷聲出夏雲。", "一一鶴聲飛上天。"]'),
('d024c9b9-948d-4145-b18e-b16162728be2','享太廟樂章','牛僧孺','唐','唐诗','tang','','[]','湜湜頎頎，融昭德輝。',40,'全唐诗/poet.tang.24000.json','["湜湜頎頎，融昭德輝。", "不紐不舒，貫成九圍。", "武烈文經，敷施當宜。", "纂堯付啓，億萬熙熙。"]'),
('ee22fe10-adc1-4c4c-add3-fffe913f4c4a','樂天夢得有歲夜詩聊以奉和','牛僧孺','唐','唐诗','tang','','[]','惜歲歲今盡，少年應不知。',48,'全唐诗/poet.tang.24000.json','["惜歲歲今盡，少年應不知。", "淒涼數流輩，歡喜見孫兒。", "暗減一身力，潛添滿鬢絲。", "莫愁花笑老，花自幾多時。"]'),
('963f314b-9b75-488d-8425-ac217712d67e','李蘇州遺太湖石奇狀絕倫因題二十韻奉呈夢得樂天','牛僧孺','唐','唐诗','tang','','["\u592a\u6e56"]','胚渾何時結，嵌空此日成。',240,'全唐诗/poet.tang.24000.json','["胚渾何時結，嵌空此日成。", "掀蹲龍虎鬬，挾怪鬼神驚。", "帶雨新水靜，輕敲碎玉鳴。", "攙叉鋒刃簇，縷絡釣絲縈。", "近水搖奇冷，依松助澹清。", "通身鱗甲隱，透穴洞天明。", "醜凸隆胡準，深凹刻兕觵。", "雷風疑欲變，陰黑訝將行。", "噤㾕微寒早，輪囷數片橫。", "地祇愁墊壓，鰲足困支撐。", "珍重姑蘇守，相憐嬾慢情。", "爲探湖裏物，不怕浪中鯨。", "利涉餘千里，山河僅百程。", "池塘初展見，金玉自凡輕。", "側眩魂猶悚，周觀意漸平。", "似逢三益友，如對十年兄。", "旺興添魔力，消煩破宿酲。", "嫓人當綺皓，視秩即公卿。", "念此園林寶，還須別識精。", "詩仙有劉白，爲汝數逢迎。"]'),
('17731285-cff6-4bcc-a31f-ff3a5efec520','席上贈劉夢得','牛僧孺','唐','唐诗','tang','','[]','粉署爲郎四十春，今來名輩更無人。',64,'全唐诗/poet.tang.24000.json','["粉署爲郎四十春，今來名輩更無人。", "休論世上昇沉事，且鬬樽前見在身。", "珠玉會應成咳唾，山川猶覺露精神。", "莫嫌恃酒輕言語，曾把文章謁後塵。"]'),
('ad7843b0-3f32-4a73-85c5-cc4124f0b510','句','牛僧孺','唐','唐诗','tang','','[]','但愁封寄去，魔物或驚禪。',62,'全唐诗/poet.tang.24000.json','["但愁封寄去，魔物或驚禪。", "惟羨東都白居士，年年香積問禪師。", "不是道公狂不得，恨公逢我不教狂。", "地瘦草叢短，求人氣色沮。", "憑酒意乃伸。"]'),
('e3593efc-effc-4fa4-af6b-0500fc07c4b8','賦得月照冰池','葉季良','唐','唐诗','tang','','[]','霽夕雲初歛，棲娥月未虧。',72,'全唐诗/poet.tang.24000.json','["霽夕雲初歛，棲娥月未虧。", "圓光生碧海，素色滿瑤池。", "天迥輪空見，波凝影詎窺。", "浮霜玉比彩，照像鏡同規。", "皎潔寒偏淨，裴回夜轉宜。", "誰憐幽境在，長與賞心隨。"]'),
('3e6e4382-bb76-4ef5-964f-79ff81a92d3c','賦得琢玉成器','葉季良','唐','唐诗','tang','','[]','片玉寄幽石，紛綸當代名。',72,'全唐诗/poet.tang.24000.json','["片玉寄幽石，紛綸當代名。", "荆人獻始遇，良匠琢初成。", "冰映寒光動，虹開晚色明。", "雅容看更澈，餘響扣彌清。", "自與瓊瑤比，方隨掌握榮。", "因知君有用，高價佇連城。"]'),
('1a604b12-da73-4826-aa69-34551fe16307','省試吳宮教美人戰','葉季良','唐','唐诗','tang','','[]','強吳矜霸略，講武在深宮。',72,'全唐诗/poet.tang.24000.json','["強吳矜霸略，講武在深宮。", "盡出嬌娥妓，先觀上將風。", "揮戈羅袖卷，擐甲汗妝紅。", "掩笑分旗下，含羞入隊中。", "鼓停行未正，刑舉令纔崇。", "自可威隣國，何勞逞戰功。"]'),
('977ecb65-8497-42e8-8dd1-7a6273946650','題歷山司徒右長史祖宅','湛賁','唐','唐诗','tang','','[]','隳官長史籍，高步歷山椒。',72,'全唐诗/poet.tang.24000.json','["隳官長史籍，高步歷山椒。", "麗句傳黃絹，香名播宋朝。", "分能知止足，跡貴出塵囂。", "松竹心長固，池臺興自饒。", "龍宮欣訪舊，鶯谷忝遷喬。", "從事叨承乏，銅章媿在腰。"]'),
('7e43aed7-a754-43cc-9504-7e1ae5b737fc','伏覽呂侍郎丘員外舊題十三代祖歷山草堂詩因書記事','湛賁','唐','唐诗','tang','','[]','名遂貴知己，道勝方晦跡。',72,'全唐诗/poet.tang.24000.json','["名遂貴知己，道勝方晦跡。", "高居葺蓮宮，遺文煥石壁。", "桑田代已變，池草春猶碧。", "識曲遇周郎，知音荷宗伯。", "調逸南平兆，風清建安跡。", "祖德今發揚，還同書史冊。"]'),
('513c46a9-9e1f-4269-a29f-3b2c860f6cf5','別慧山書堂','湛賁','唐','唐诗','tang','','[]','捲簾曉望雲平檻，下榻宵吟月半窗。',32,'全唐诗/poet.tang.24000.json','["捲簾曉望雲平檻，下榻宵吟月半窗。", "病守未能依結社，更施何術去爲邦。"]'),
('721835c4-f691-47ed-a67d-844403e4c094','暮春自南臺丞再除給事中','薛存誠','唐','唐诗','tang','','[]','再入青鎖闈，忝官誠自非。',48,'全唐诗/poet.tang.24000.json','["再入青鎖闈，忝官誠自非。", "拂塵驚物在，開戶似僧歸。", "積草漸無逕，殘花猶灑衣。", "禁垣偏日近，行坐是恩輝。"]'),
('41c09ae9-ce3c-4b59-9dfb-5f407ce64ac6','御製段太尉碑','薛存誠','唐','唐诗','tang','','[]','葬儀從儉禮，刊石荷堯君。',72,'全唐诗/poet.tang.24000.json','["葬儀從儉禮，刊石荷堯君。", "露跡垂繁字，天哀灑麗文。", "詔深榮嗣子，海變記孤墳。", "寶思皆涵象，皇心永念勳。", "雅詞黃絹妙，渥澤紫泥分。", "青史應同久，芳名萬古聞。"]'),
('ad2f3dda-c1e0-4052-a093-bbb576f5b5ca','御題國子監門','薛存誠','唐','唐诗','tang','','[]','宸翰符玄造，榮題國子門。',72,'全唐诗/poet.tang.24000.json','["宸翰符玄造，榮題國子門。", "筆鋒迴日月，字勢動乾坤。", "簷下雲光絕，梁間鵲影飜。", "張英聖莫擬，索靖妙難言。", "爲著盤龍跡，能彰舞鳳蹲。", "更隨垂露像，常以沐皇恩。"]'),
('15fac948-ab54-4256-a4cf-8c79f00bbc69','御箭連中雙兔','薛存誠','唐','唐诗','tang','','[]','宸遊經上苑，羽獵向閑田。',72,'全唐诗/poet.tang.24000.json','["宸遊經上苑，羽獵向閑田。", "狡兔初迷窟，纖驪詎著鞭。", "三驅仍百步，一發遂雙連。", "影射含霜草，魂消向月弦。", "驩聲動寒木，喜氣滿晴天。", "那似陳王意，空隨樂府篇。"]'),
('809905e2-7b41-4234-ab0f-47ea5433d192','太學創置石經','薛存誠','唐','唐诗','tang','','[]','聖唐復古制，德義功無替。',72,'全唐诗/poet.tang.24000.json','["聖唐復古制，德義功無替。", "奧旨悅詩書，遺文分篆隸。", "銀鉤互交映，石壁靡塵翳。", "永與乾坤期，不逐日月逝。", "儒林道益廣，學者心彌銳。", "從此理化成，恩光遍遐裔。"]'),
('742fa643-9264-4e7d-b069-dd2d9b85148e','觀南郊回仗','薛存誠','唐','唐诗','tang','','[]','傳警千門寂，南郊綵仗迴。',72,'全唐诗/poet.tang.24000.json','["傳警千門寂，南郊綵仗迴。", "但驚龍再見，誰識日雙開。", "德澤施雲雨，恩光變燼灰。", "閱兵貔武振，聽樂鳳皇來。", "候刻移宸輦，遵時集觀臺。", "多慚遠臣賤，不得禮容陪。"]'),
('7b371123-ea49-4d43-ba1a-ecdbd8b28218','聞擊壤','薛存誠','唐','唐诗','tang','','[]','堯年聽野老，擊壤復何云。',72,'全唐诗/poet.tang.24000.json','["堯年聽野老，擊壤復何云。", "自謂歡由己，寧知德在君。", "氣平閑易暢，聲賀作難分。", "耕鑿方隨日，恩威比望雲。", "簣桴均下調，和木等南薰。", "無落於吾事，誰將帝已聞。"]'),
('59098b43-3e67-4a63-855d-0b97c2b65423','膏澤多豐年','薛存誠','唐','唐诗','tang','','[]','帝德方多澤，莓莓井逕同。',72,'全唐诗/poet.tang.24000.json','["帝德方多澤，莓莓井逕同。", "八方甘雨布，四遠報年豐。", "厫庾千廂在，幽流萬壑通。", "候時勤稼穡，擊壤樂農功。", "畎畝人無惰，田廬歲不空。", "何須憂伏臘，千載賀堯風。"]'),
('3d5cbb39-2531-4c18-b45e-fe6af04c857e','東都父老望幸','薛存誠','唐','唐诗','tang','','[]','鑾輿秦地久，羽衛洛陽空。',96,'全唐诗/poet.tang.24000.json','["鑾輿秦地久，羽衛洛陽空。", "彼土雖憑固，茲川乃得中。", "龍顏覲白日，鶴髮仰清風。", "望幸誠逾邈，懷來意不窮。", "昔因封泰岳，今佇躡維嵩。", "天地心無異，神祇理亦同。", "翠華翔渭北，玉檢候關東。", "衆願其難阻，明君早勒功。"]'),
('c5ae2248-4126-4bd8-af7a-0fa63a811bdc','嵩山望幸','薛存誠','唐','唐诗','tang','','[]','峻極位何崇，方知造化功。',72,'全唐诗/poet.tang.24000.json','["峻極位何崇，方知造化功。", "降靈逢聖主，望幸表維嵩。", "隱映連青壁，嵯峨向碧空。", "象車因叶瑞，龍駕願升中。", "萬歲聲長在，千巖氣轉雄。", "東都歌盛事，西笑佇皇風。"]'),
('7f8145eb-0d2a-43cd-bc58-dee0dc1f7bcd','華清宮望幸','薛存誠','唐','唐诗','tang','','[]','驪岫接新豐，岧嶢駕碧空。',72,'全唐诗/poet.tang.24000.json','["驪岫接新豐，岧嶢駕碧空。", "鑿山開秘殿，隱霧蔽仙宮。", "絳闕猶棲鳳，雕梁尚帶虹。", "溫泉曾浴日，華館舊迎風。", "肅穆瞻雲輦，深沉閉綺櫳。", "東郊望幸處，瑞氣靄濛濛。"]'),
('b8442ba9-960f-4d72-9913-685653bddccd','謁見日將至雙闕','薛存誠','唐','唐诗','tang','','[]','曉色臨雙闕，微臣禮位陪。',72,'全唐诗/poet.tang.24000.json','["曉色臨雙闕，微臣禮位陪。", "遠驚龍鳳覩，誰識冕旒開。", "藹藹千年盛，顒顒萬國來。", "天文標日月，時令布雲雷。", "迥出黃金殿，全分白玉臺。", "雕蟲竟何取，瞻戀不知迴。"]'),
('b1488c5c-a16f-4e00-820f-6662d8fbd792','南至日隔仗望含元殿爐香','裴次元','唐','唐诗','tang','','[]','冕旒初負扆，卉服盡朝天。',72,'全唐诗/poet.tang.24000.json','["冕旒初負扆，卉服盡朝天。", "暘谷初移日，金爐漸起煙。", "芬馨流遠近，散漫入貂蟬。", "霜仗凝逾白，朱欄映轉鮮。", "始看浮闕在，稍見逐風遷。", "爲沐皇家慶，來瞻羽衛前。"]'),
('b68310aa-a666-4aa0-9319-618723638f65','律中應鐘','裴次元','唐','唐诗','tang','','[]','律窮方數寸，室暗在三重。',72,'全唐诗/poet.tang.24000.json','["律窮方數寸，室暗在三重。", "伶管灰先動，秦正節已逢。", "商聲辭玉笛，羽調入金鐘。", "密葉翻霜彩，輕冰歛水容。", "望鴻南去絕，迎氣北來濃。", "願託無凋性，寒林自比松。"]'),
('e2f6d3a1-da3e-4651-a066-b9cb1c339757','賦得亞父碎玉斗','裴次元','唐','唐诗','tang','','[]','雄謀竟不決，寶玉將何愛。',72,'全唐诗/poet.tang.24000.json','["雄謀竟不決，寶玉將何愛。", "倏爾霜刃揮，颯然春冰碎。", "飛光動旗幟，散響驚環珮。", "霜濃繡帳前，星流錦筵內。", "圖王業已失，爲虜言空悔。", "獨有青史中，英風冠千載。"]'),
('4e4823eb-f26d-42f8-ac31-9df86cf1a26f','句','裴次元','唐','唐诗','tang','','[]','積高依郡城，迥拔凌霄漢。',12,'全唐诗/poet.tang.24000.json','["積高依郡城，迥拔凌霄漢。"]'),
('00d7b9c5-cc58-49e2-b964-f2a5e9c198ea','幷州路','李宣遠','唐','唐诗','tang','','[]','秋日幷州路，黃榆落故關。',48,'全唐诗/poet.tang.24000.json','["秋日幷州路，黃榆落故關。", "孤城吹角罷，數騎射鵰還。", "帳幕遙臨水，牛羊自下山。", "征人正垂淚，烽火起雲間。"]'),
('e31f5acc-797a-4417-a479-7c69a70360ed','近無西耗','李宣遠','唐','唐诗','tang','','[]','遠戎兵壓境，遷客淚橫襟。',48,'全唐诗/poet.tang.24000.json','["遠戎兵壓境，遷客淚橫襟。", "烽堠驚秦塞，囚居困越吟。", "自憐牛馬走，未識犬羊心。", "一月無消息，西看日又沈。"]'),
('fca19f49-f819-464e-92ca-542790075444','曲江亭望慈恩寺杏園花發','李君何','唐','唐诗','tang','','[]','春晴凭水軒，仙杏發南園。',72,'全唐诗/poet.tang.24000.json','["春晴凭水軒，仙杏發南園。", "開蘂風初曉，浮香景欲暄。", "光華臨御陌，色相對空門。", "野雪遙添淨，山煙近借繁。", "地閑分鹿苑，景勝類桃源。", "況值新晴日，芳枝度彩鴛。"]'),
('b6a25686-6eec-41e5-bb7e-f8379cb385fb','除夜書情','周弘亮','唐','唐诗','tang','','[]','何處風塵歲，雲陽古驛前。',48,'全唐诗/poet.tang.24000.json','["何處風塵歲，雲陽古驛前。", "三冬不再稔，曉日又明年。", "春入江南柳，寒歸塞北天。", "還傷知候客，花景對韋編。"]'),
('923f58d6-c2b1-49dc-aa45-3c32bdbd3b75','曲江亭望慈恩寺杏園花發','周弘亮','唐','唐诗','tang','','[]','江亭閑望處，遠近見秦源。',72,'全唐诗/poet.tang.24000.json','["江亭閑望處，遠近見秦源。", "古寺遲春景，新花發杏園。", "萼中輕蘂密，枝上素姿繁。", "拂雨雲初起，含風雪欲翻。", "容輝明十地，香氣遍千門。", "願莫隨桃李，芳菲不爲言。"]'),
('c28ea383-17ee-4a3e-9569-ddb2d57cba4f','故鄉除夜','周弘亮','唐','唐诗','tang','','[]','三百六十日云終，故鄉還與異鄉同。',64,'全唐诗/poet.tang.24000.json','["三百六十日云終，故鄉還與異鄉同。", "非唯律變情堪恨，抑亦才疎命未通。", "何處夜歌銷臘酒，誰家高燭候春風。", "詩成始欲吟將看，早是去年牽課中。"]'),
('dae62164-312c-4d78-a70e-29a05853ddfc','曲江亭望慈恩寺杏園花發','陳翥','唐','唐诗','tang','','[]','曲江晴望好，近接梵王家。',72,'全唐诗/poet.tang.24000.json','["曲江晴望好，近接梵王家。", "十畝開金地，千林發杏花。", "映雲猶誤雪，煦日欲成霞。", "紫陌傳香遠，紅泉落影斜。", "園中春尚早，亭上路非賒。", "芳景堪游處，其如惜物華。"]'),
('48d6632a-35d7-4327-9627-7d11084a9d66','曲江亭望慈恩寺杏園花發','曹著','唐','唐诗','tang','','[]','渚亭臨淨域，憑望一開軒。',72,'全唐诗/poet.tang.24000.json','["渚亭臨淨域，憑望一開軒。", "晚日分初地，東風發杏園。", "異香飄九陌，麗色映千門。", "照灼瑤華散，葳蕤玉露繁。", "未教游妓折，乍聽早鶯喧。", "誰復爭桃李，含芳自不言。"]'),
('d8ae2410-cf07-4c1f-8aac-5eaf2930842f','魚上冰','王公亮','唐','唐诗','tang','','[]','春生寒氣減，稍動久潛魚。',72,'全唐诗/poet.tang.24000.json','["春生寒氣減，稍動久潛魚。", "乍喜東風至，來看曲岸初。", "出冰朱鬣見，望日錦鱗舒。", "漸覺流澌近，還欣掉尾餘。", "噞喁情自樂，沿泝意寧疎。", "儻得隨鯤化，終能上太虛。"]'),
('725a2cdc-90a1-42c4-86ca-ba6d8a6c3dcf','賦得竹箭有筠','張仲方','唐','唐诗','tang','','[]','東南生綠竹，獨美有筠箭。',72,'全唐诗/poet.tang.24000.json','["東南生綠竹，獨美有筠箭。", "枝葉詎曾凋，風霜孰云變。", "偏宜林表秀，多向歲寒見。", "碧色乍蔥蘢，清光常蒨練。", "皮開鳳彩出，節勁龍文現。", "愛此守堅貞，含歌屬時彥。"]'),
('f9485631-69b1-4f42-acc3-78ae5a64a7c1','贈毛仙翁','張仲方','唐','唐诗','tang','','[]','毛仙翁，毛仙翁，容貌常如二八童。',176,'全唐诗/poet.tang.24000.json','["毛仙翁，毛仙翁，容貌常如二八童。", "幾歲頭梳雲鬢綠，無時面帶桃花紅。", "眼前人世閱滄海，肘後藥成辭月宮。", "方口秀眉編貝齒，瞭然炅炅雙瞳子。", "芝椿稟氣本堅強，龜鶴計年應不死。", "四海五山長獨游，矜貧傲富欺王侯。", "靈通指下甎甓化，瑞氣爐中金玉流。", "定是煙霞列仙侶，暫來塵俗救危苦。", "紫霞妖女瓊華飛，秘法虔心傳付與。", "陰功足，陰功成，羽駕何年歸上清。", "待我休官了婚嫁，桃源洞裏覓仙兄。"]'),
('252908f7-8c99-4232-9021-845595914d80','句','張仲方','唐','唐诗','tang','','[]','入門池色靜，登閣雨聲來。',12,'全唐诗/poet.tang.24000.json','["入門池色靜，登閣雨聲來。"]'),
('ae84339d-0128-4008-bdae-64111d23eafa','和白樂天','崔玄亮','唐','唐诗','tang','','[]','病餘歸到洛陽頭，拭目開眉見白侯。',64,'全唐诗/poet.tang.24000.json','["病餘歸到洛陽頭，拭目開眉見白侯。", "鳳詔恐君今歲去，龍門欠我舊時遊。", "幾人樽下同歌詠，數盞燈前共獻酬。", "相對憶劉劉在遠，寒宵耿耿夢長洲。"]'),
('8cd5c639-0cc6-4da2-9725-2952449bd592','臨終詩','崔玄亮','唐','唐诗','tang','','[]','蹔榮蹔悴石敲火，即空即色眼生花。',32,'全唐诗/poet.tang.24000.json','["蹔榮蹔悴石敲火，即空即色眼生花。", "許時爲客今歸去，大曆元年是我家。"]'),
('d83a78d4-0116-446c-86e3-9296672136b0','句','崔玄亮','唐','唐诗','tang','','[]','共相呼喚醉歸來。',8,'全唐诗/poet.tang.24000.json','["共相呼喚醉歸來。"]'),
('12f064ff-4e03-42fd-a28b-6e1495baf93c','省試臨淵羨魚','徐牧','唐','唐诗','tang','','[]','清泚濯纓處，今來喜一臨。',72,'全唐诗/poet.tang.24000.json','["清泚濯纓處，今來喜一臨。", "慙無下釣處，空有羨魚心。", "退省時頻改，謀身歲屢沈。", "鬣成川上媚，網就水寧深。", "頳尾臨波裏，朱鬚破浪潯。", "此時儻不漏，江上免行吟。"]'),
('500fe33a-f30b-45a7-aeb2-48829ae8d1a8','淮南游故居感舊酬西川李尚書德裕','王播','唐','唐诗','tang','','[]','昔年獻賦去江湄，今日行春到却悲。',64,'全唐诗/poet.tang.24000.json','["昔年獻賦去江湄，今日行春到却悲。", "三徑僅存新竹樹，四鄰惟見舊孫兒。", "壁間潛認偷光處，川上寧忘結網時。", "更見橋邊記名姓，始知題柱免人嗤。"]'),
('112b68ed-ae0b-4340-b44a-854b52ff2af1','題木蘭院二首 一','王播','唐','唐诗','tang','','[]','三十年前此院遊，木蘭花發院新修。',32,'全唐诗/poet.tang.24000.json','["三十年前此院遊，木蘭花發院新修。", "如今再到經行處，樹老無花僧白頭。"]'),
('e987d251-7f5b-45cd-b7f8-d9c08d49750b','題木蘭院二首 二','王播','唐','唐诗','tang','','[]','上堂已了各西東，慚愧闍黎飯後鐘。',32,'全唐诗/poet.tang.24000.json','["上堂已了各西東，慚愧闍黎飯後鐘。", "三十年來塵撲面，如今始得碧紗籠。"]'),
('ef45c9c1-e894-43ca-bae9-50ff17078e44','上巳接清明游宴','獨孤良弼','唐','唐诗','tang','','[]','上巳歡初罷，清明賞又追。',72,'全唐诗/poet.tang.24000.json','["上巳歡初罷，清明賞又追。", "閏年侵舊曆，令節併芳時。", "細雨鶯飛重，春風酒醞遲。", "尋花迷白雪，看柳拆青絲。", "淑氣如相待，天和意爲誰。", "吁嗟名未立，空詠宴遊詩。"]'),
('aec5ce8d-854b-4acc-bebd-f759aba918db','次潭州酬唐侍御姚員外游道林嶽麓寺題示','沈傳師','唐','唐诗','tang','','[]','承明年老輙自論，乞得湘守東南奔。',208,'全唐诗/poet.tang.24000.json','["承明年老輙自論，乞得湘守東南奔。", "爲聞楚國富山水，青嶂邐迤僧家園。", "含香珥筆皆眷舊，謙抑自忘臺省尊。", "不令執簡候亭館，直許攜手游山樊。", "忽驚列岫曉來逼，朔雪洗盡煙嵐昏。", "碧波迴嶼三山轉，丹檻繚郭千艘屯。", "華鑣躞蹀絢砂步，大斾綵錯輝松門。", "樛枝競騖龍蛇勢，折幹不滅風霆痕。", "相重古殿倚嵓腹，別引新徑縈雲根。", "目傷平楚虞帝魂，情多思遠聊開樽。", "危弦細管逐歌飄，畫鼓繡靴隨節飜。", "鏘金七言凌老杜，入木八法蟠高軒。", "嗟余潦倒久不利，忍復感激論元元。"]'),
('e3bc156d-b418-43dc-9ba3-8ee39f9ec5e5','和李德裕觀玉蘂花見懷之作','沈傳師','唐','唐诗','tang','','[]','曾對金鑾直，同依玉樹陰。',48,'全唐诗/poet.tang.24000.json','["曾對金鑾直，同依玉樹陰。", "雪英飛舞近，煙葉動搖深。", "素萼年年密，衰容日日侵。", "勞君想華髮，近欲不勝簪。"]'),
('e399de69-6e6b-4370-bec8-fd39233fde1c','贈毛仙翁','沈傳師','唐','唐诗','tang','','[]','安期何事出雲煙，爲把仙方與世傳。',64,'全唐诗/poet.tang.24000.json','["安期何事出雲煙，爲把仙方與世傳。", "只向人間稱百歲，誰知洞裏過千年。", "青牛到日迎方朔，丹竈開時共稚川。", "更說桃源更深處，異花長占四時天。"]'),
('fedad3f7-f832-4743-93e3-de2618681119','寄大府兄侍史','沈傳師','唐','唐诗','tang','','[]','積雪山陰馬過難，殘更深夜鐵衣寒。',32,'全唐诗/poet.tang.24000.json','["積雪山陰馬過難，殘更深夜鐵衣寒。", "將軍破了單于陣，更把兵書仔細看。"]'),
('52c83522-f832-4ced-9e03-d36bc6979811','蒙泉','沈傳師','唐','唐诗','tang','','[]','京路馬駸駸，塵勞日向深。',24,'全唐诗/poet.tang.24000.json','["京路馬駸駸，塵勞日向深。", "蒙泉聊息駕，可以洗君心。"]'),
('8038b0d7-c3e0-4b18-978d-3415250923de','春從何處來','白行簡','唐','唐诗','tang','','[]','欲識春生處，先從木德來。',72,'全唐诗/poet.tang.24000.json','["欲識春生處，先從木德來。", "入門潛報柳，度嶺暗驚梅。", "透雪寒光散，消冰水鏡開。", "曉迎郊騎發，夜逐斗杓迴。", "淑氣空中變，新聲雨後催。", "偏宜資律呂，應是候陽臺。"]'),
('fdb4b21b-ccc1-4efe-a7cf-13785057a3f5','貢院樓北新栽小松','白行簡','唐','唐诗','tang','','[]','華省春霜曙，樓陰植小松。',72,'全唐诗/poet.tang.24000.json','["華省春霜曙，樓陰植小松。", "移根依厚地，委質別危峰。", "北戶知猶遠，東堂幸見容。", "心堅終待鶴，枝嫩未成龍。", "夜影看仍薄，朝嵐色漸濃。", "山苗不可蔭，孤直俟秦封。"]'),
('ebf633c7-8a56-4ece-aa08-4beeef510ba3','金在鎔','白行簡','唐','唐诗','tang','','[]','巨橐方鎔物，洪鑪欲範金。',72,'全唐诗/poet.tang.24000.json','["巨橐方鎔物，洪鑪欲範金。", "紫光看漸發，赤氣望逾深。", "燄熱晴雲變，煙浮晝景陰。", "堅剛由我性，鼓鑄任君心。", "踴躍徒標異，沈潛自可欽。", "何當得成器，待叩向知音。"]'),
('c5370fc4-16b6-49ca-a979-b40846f99625','歸馬華山','白行簡','唐','唐诗','tang','','[]','牧野功成後，周王戰馬閑。',72,'全唐诗/poet.tang.24000.json','["牧野功成後，周王戰馬閑。", "驅馳休伏皁，飲齕任依山。", "逐日朝仍去，隨風暮自還。", "冰生疑隴坂，葉落似榆關。", "躞蹀仙峰下，騰驤渭水灣。", "幸逢時偃武，不復鼓鼙間。"]'),
('249ae962-2611-4d4f-aeca-7252cc60fafa','夫子鼓琴得其人','白行簡','唐','唐诗','tang','','[]','宣父窮玄奧，師襄授素琴。',72,'全唐诗/poet.tang.24000.json','["宣父窮玄奧，師襄授素琴。", "稍殊流水引，全辨聖人心。", "慕德聲逾感，懷人意自深。", "泠泠傳妙手，摵摵振空林。", "促調清風至，操弦白日沈。", "曲終情不盡，千古仰知音。"]'),
('04588e31-0084-4040-952a-d698f5179092','李都尉重陽日得蘇屬國書','白行簡','唐','唐诗','tang','','[]','降虜意何如，窮荒九月初。',72,'全唐诗/poet.tang.24000.json','["降虜意何如，窮荒九月初。", "三秋異鄉節，一紙故人書。", "對酒情無極，開緘思有餘。", "感時空寂寞，懷舊幾躊躇。", "鴈盡平沙迥，煙銷大漠虛。", "登臺南望處，掩淚對雙魚。"]'),
('99e33312-3699-4723-a276-f050f3a6db6e','在巴南望郡南山呈樂天','白行簡','唐','唐诗','tang','','[]','臨江一嶂白雲間，紅綠層層錦繡班。',32,'全唐诗/poet.tang.24000.json','["臨江一嶂白雲間，紅綠層層錦繡班。", "不作巴南天外意，何殊昭應望驪山。"]'),
('d44e05f1-7746-4e3e-9bbb-39747d6c3b3d','春雲','裴澄','唐','唐诗','tang','','[]','漠漠復溶溶，乘春任所從。',72,'全唐诗/poet.tang.24000.json','["漠漠復溶溶，乘春任所從。", "映林初展葉，觸石未成峰。", "旭日消寒翠，晴煙點淨容。", "霏微將似滅，深淺又如重。", "薄彩臨溪散，輕陰帶雨濃。", "空餘負樵者，嶺上自相逢。"]'),
('dc6bced5-a615-46e6-b945-85f48ba172c5','賦得沽美玉','羅立言','唐','唐诗','tang','','[]','誰憐被褐士，懷玉正求沽。',72,'全唐诗/poet.tang.24000.json','["誰憐被褐士，懷玉正求沽。", "成器終期達，逢時豈見誣。", "寶同珠照乘，價重劒論都。", "浮彩朝虹滿，懸光夜月孤。", "幾年淪瓦礫，今日出泥塗。", "采斵資良匠，無令瑕掩瑜。"]'),
('e08b566f-fbe1-42e0-a407-5ebab46b7a6d','寒食遣懷','張燦','唐','唐诗','tang','','[]','繁華泣清露，悄悄落衣巾。',48,'全唐诗/poet.tang.24000.json','["繁華泣清露，悄悄落衣巾。", "明日逢寒食，春風見故人。", "病來羞滯楚，西去欲迷秦。", "憔悴此時久，青山歸四鄰。"]'),
('be4c8402-cadd-4d2d-8994-2ad5336035bc','春日山亭','牟融','唐','唐诗','tang','','[]','醉來重整華陽巾，搔首驚看白髮新。',64,'全唐诗/poet.tang.24000.json','["醉來重整華陽巾，搔首驚看白髮新。", "莫道愁多因病酒，只緣命薄不辭貧。", "龍魚失水難爲用，龜玉蒙塵未見珍。", "正是聖朝全盛日，詎知林下有閑人。"]'),
('9746efd9-bde5-4955-a36e-0ea30606c55f','寄周韶州','牟融','唐','唐诗','tang','','[]','十年學道困窮廬，空有長才重老儒。',64,'全唐诗/poet.tang.24000.json','["十年學道困窮廬，空有長才重老儒。", "功業要當垂永久，利名那得在須臾。", "山中荆璞誰知玉，海底驪龍不見珠。", "寄語故人休悵怏，古來賢達事多殊。"]'),
('7e093f4c-1102-466b-a026-044f855cc80a','秋夜醉歸有感而賦','牟融','唐','唐诗','tang','','[]','銜盃誰道易更闌，沈醉歸來不自歡。',64,'全唐诗/poet.tang.24000.json','["銜盃誰道易更闌，沈醉歸來不自歡。", "惆悵後時孤劒冷，寂寥無寐一燈殘。", "竹窗涼雨鳴秋籟，江郭清砧擣夜寒。", "多少客懷消不得，臨風搔首浩漫漫。"]'),
('3cd98eed-b2ce-4969-ae2e-4a8e95d5abdb','寄范使君','牟融','唐','唐诗','tang','','[]','未秋爲別已終秋，咫尺婁江路阻脩。',64,'全唐诗/poet.tang.24000.json','["未秋爲別已終秋，咫尺婁江路阻脩。", "心上惟君知委曲，眼前獨我逐漂流。", "從來姑息難爲好，到底依棲總是諏。", "西望家山成浩歎，臨風搔首不勝愁。"]'),
('d8833192-b078-4180-9411-0a15220ceddd','送羅約','牟融','唐','唐诗','tang','','[]','雨晴江館柳依依，握手那堪此別離。',64,'全唐诗/poet.tang.24000.json','["雨晴江館柳依依，握手那堪此別離。", "獨鶴孤琴隨遠斾，紅亭綠酒惜分岐。", "月明野店聞雞早，花暗關城匹馬遲。", "從夜定知相憶處，東風回首不勝悲。"]'),
('df51290b-9d9f-422f-9091-847f2ac62adc','題李昭訓山水','牟融','唐','唐诗','tang','','[]','卜築藏修地自偏，尊前詩酒集羣賢。',64,'全唐诗/poet.tang.24000.json','["卜築藏修地自偏，尊前詩酒集羣賢。", "半岩松暝時藏鶴，一枕秋聲夜聽泉。", "風月謾勞酬逸興，漁樵隨處度流年。", "南州人物依然在，山水幽居勝輞川。"]'),
('f3ad992a-3b8d-437c-af2a-d21dca171871','處厚遊杭作詩寄之','牟融','唐','唐诗','tang','','[]','江村搖落暫逢秋，況是聞君獨遠遊。',64,'全唐诗/poet.tang.24000.json','["江村搖落暫逢秋，況是聞君獨遠遊。", "浙水風煙思弔古，楚鄉人物賦登樓。", "書沈寒鴈雲邊影，夢繞清猨月下愁。", "念我故人勞碌久，不如投老臥滄洲。"]'),
('420c754b-adb6-4e52-830e-0c6ecac2db90','山中有懷李十二','牟融','唐','唐诗','tang','','[]','林前風景晚蒼蒼，林下懷人路杳茫。',64,'全唐诗/poet.tang.24000.json','["林前風景晚蒼蒼，林下懷人路杳茫。", "白髮流年淹舊業，碧山茅屋臥斜陽。", "客邊秋興悲張翰，病裏春情笑沈郎。", "何事登樓□□□，幾迴搔首□思歸。"]'),
('ff8ef2ab-e6be-49f9-a64c-5a54fd42f0ab','客中作','牟融','唐','唐诗','tang','','[]','異鄉歲晚悵離懷，遊子驅馳媿不才。',64,'全唐诗/poet.tang.24000.json','["異鄉歲晚悵離懷，遊子驅馳媿不才。", "夜夜砧聲催客去，年年鴈影帶寒來。", "半林殘葉迎霜落，三徑黃花近節開。", "幾度無聊倍惆悵，臨風搔首獨興哀。"]'),
('fd43b692-8546-4a8b-b12c-1059d85f9a1e','山寺律僧畫蘭竹圖','牟融','唐','唐诗','tang','','[]','偶來絕頂興無窮，獨有山僧筆最工。',64,'全唐诗/poet.tang.24000.json','["偶來絕頂興無窮，獨有山僧筆最工。", "綠徑日長袁戶在，紫荃秋晚謝庭空。", "離花影度湘江月，遺珮香生洛浦風。", "欲結歲寒盟不去，忘機相對畫圖中。"]'),
('3382496a-1340-4163-b42d-8e77c9969cb6','送客之杭','牟融','唐','唐诗','tang','','[]','西風吹[冷]透貂裘，行色匆匆不暫留。',66,'全唐诗/poet.tang.24000.json','["西風吹[冷]透貂裘，行色匆匆不暫留。", "帆帶夕陽投越浦，心隨明月到杭州。", "風清聽漏驚鄉夢，燈下聞歌亂別愁。", "懸想到杭州興地，尊前應與話離憂。"]'),
('5a13ca7f-7b16-4891-a384-6691284c482d','有感二首 一','牟融','唐','唐诗','tang','','[]','何事離懷入夢頻，貧居寂莫四無鄰。',64,'全唐诗/poet.tang.24000.json','["何事離懷入夢頻，貧居寂莫四無鄰。", "詩因韻險難成律，酒爲愁多不顧身。", "眼底故人驚歲別，尊前華髮逐時新。", "十年飄泊如萍跡，一度登臨一悵神。"]'),
('808e9052-a0a5-492a-955b-4751f207c132','有感二首 二','牟融','唐','唐诗','tang','','[]','搔首臨風獨倚欄，客邊驚覺歲華殘。',64,'全唐诗/poet.tang.24000.json','["搔首臨風獨倚欄，客邊驚覺歲華殘。", "栖遲未遇常鋾薦，邂逅寧彈貢禹冠。", "有興不愁詩韻險，無聊只怕酒杯乾。", "何如日日長如醉，付與詩人一笑看。"]'),
('0e929886-6739-4e8b-bebd-560091ec2028','送沈侯之京','牟融','唐','唐诗','tang','','[]','悠悠旌斾出東樓，特出仙郎上帝州。',64,'全唐诗/poet.tang.24000.json','["悠悠旌斾出東樓，特出仙郎上帝州。", "劉旻才高能富國，蕭何人傑足封侯。", "關河弱柳垂金縷，水驛青帘拂畫樓。", "欲盡故人尊酒意，春風江上暫停舟。"]'),
('d4ced2a2-cdb0-4ad7-8504-6c43fc8bdf43','寄羽士','牟融','唐','唐诗','tang','','[]','別來有路隔仙凡，幾度臨風欲去難。',64,'全唐诗/poet.tang.24000.json','["別來有路隔仙凡，幾度臨風欲去難。", "樂道無時忘鶴伴，談玄何日到星壇。", "山中勝景常留客，林下清風好煉丹。", "使我浮生塵鞅脫，相從應得一盤桓。"]'),
('93d833bc-de2c-471c-8498-8377b2725f82','題趙支','牟融','唐','唐诗','tang','','[]','林間曲徑掩衡茅，遶屋青青翡翠梢。',64,'全唐诗/poet.tang.24000.json','["林間曲徑掩衡茅，遶屋青青翡翠梢。", "一枕秋聲鸞舞月，半窗雲影鶴歸巢。", "曾聞賈誼陳奇策，肯學楊雄賦解嘲。", "我有清風高節在，知君不負歲寒交。"]'),
('3ceaed1a-4c6c-487e-ac43-be8b0939d2f5','司馬遷墓','牟融','唐','唐诗','tang','','[]','落落長才負不羈，中原回首益堪悲。',64,'全唐诗/poet.tang.24000.json','["落落長才負不羈，中原回首益堪悲。", "英雄此日誰能薦，聲價當時衆所推。", "一代高風留異國，百年遺跡剩殘碑。", "經過詞客空惆悵，落日寒煙賦黍離。"]'),
('1cc1f8ed-d210-41cc-8b71-b59d730cf0b6','春遊','牟融','唐','唐诗','tang','','[]','錦袍日暖耀冰蠶，上客陪遊酒半酣。',64,'全唐诗/poet.tang.24000.json','["錦袍日暖耀冰蠶，上客陪遊酒半酣。", "笑拂吟鞭邀好興，醉欹烏帽逞雄談。", "樓前弱柳搖金縷，林外遙山隔翠嵐。", "正是太平行樂處，春風花下且停驂。"]'),
('97d3b17d-fcf2-4e26-85cc-b20973baec0e','水西草堂','牟融','唐','唐诗','tang','','[]','蘿徑蕭然曲業存，閑雲流水四無鄰。',64,'全唐诗/poet.tang.24000.json','["蘿徑蕭然曲業存，閑雲流水四無鄰。", "身留白屋潛踪跡，門□□吟學隱淪。", "吟對琴尊江上月，笑看花木鏡中春。", "遺書自有親□處，何必驅馳擾世塵。"]'),
('34027b3f-c235-49e6-9fd4-990d009c453c','送羽衣之京','牟融','唐','唐诗','tang','','[]','羽衣縹緲拂塵囂，悵別河梁贈柳條。',64,'全唐诗/poet.tang.24000.json','["羽衣縹緲拂塵囂，悵別河梁贈柳條。", "閬苑雲深孤鶴逈，蓬萊天近一身遙。", "香浮寶輦仙風潤，花落瑤壇絳雨消。", "自是長生林下客，也陪鴛鷺入清朝。"]'),
('5e4b8d84-47a0-4187-9757-22fa3ad8677c','題道院壁','牟融','唐','唐诗','tang','','[]','山中舊宅四無鄰，草淨雲和逈絕塵。',64,'全唐诗/poet.tang.24000.json','["山中舊宅四無鄰，草淨雲和逈絕塵。", "神棗胡麻能飯客，桃花流水蔭通津。", "星壇火伏煙霞暝，林壑春香鳥雀馴。", "若使凡緣終可脫，也應從此度閑身。"]'),
('2cb43cb3-ac66-45da-80d7-28e8dcf8d21f','贈歐陽詹','牟融','唐','唐诗','tang','','[]','爲客囊無季子金，半生踪跡任浮沈。',64,'全唐诗/poet.tang.24000.json','["爲客囊無季子金，半生踪跡任浮沈。", "服勤因念劬勞重，思養徒懷感慨深。", "島外斷雲凝遠日，天涯芳草動愁心。", "家林千里遙相憶，幾度停車一悵吟。"]'),
('52ce7d70-ec64-4c42-8545-fc5fa2a18790','邵公母','牟融','唐','唐诗','tang','','[]','搔首驚聞楚些歌，拂衣歸去淚懸河。',64,'全唐诗/poet.tang.24000.json','["搔首驚聞楚些歌，拂衣歸去淚懸河。", "劬勞常想三春恨，思養其如寸草何。", "淛水夢懷千里遠，蘇臺愁望白雲多。", "傷心獨有黃堂客，幾度臨風詠蓼莪。"]'),
('610b6a5f-0703-4ebc-8359-dbcbd4be40c7','客中作','牟融','唐','唐诗','tang','','[]','千里雲山戀舊遊，寒窗涼雨夜悠悠。',64,'全唐诗/poet.tang.24000.json','["千里雲山戀舊遊，寒窗涼雨夜悠悠。", "浮亭花竹頻勞夢，別路風煙半是愁。", "芳草傍人空對酒，流年多病倦登樓。", "一杯重向樽前醉，莫遣相思累白頭。"]'),
('b7fdeea9-903c-422d-9776-34ce1b808e34','贈楊處厚','牟融','唐','唐诗','tang','','[]','十年學道苦勞神，贏得尊前一病身。',64,'全唐诗/poet.tang.24000.json','["十年學道苦勞神，贏得尊前一病身。", "天上故人皆自貴，山中明月獨相親。", "客心淡泊偏宜靜，吾道從容不厭貧。", "幾度臨風一回首，笑看華髮及時新。"]'),
('19a692cc-c56d-42ee-9483-71823fa9bedd','重贈張籍','牟融','唐','唐诗','tang','','[]','舊日儀容只宛然，笑談不覺度流年。',64,'全唐诗/poet.tang.24000.json','["舊日儀容只宛然，笑談不覺度流年。", "凡緣未了嗟無子，薄命能孤不怨天。", "一醉便同塵外客，百杯疑是酒中仙。", "人生隨處堪爲樂，管甚秋香滿鬢邊。"]'),
('91268533-471e-400b-b149-b5d13d546ff7','贈殷以道','牟融','唐','唐诗','tang','','[]','世路紅塵懶步趨，長年結屋傍巖隅。',64,'全唐诗/poet.tang.24000.json','["世路紅塵懶步趨，長年結屋傍巖隅。", "獨留鄉井誠非隱，老向山林不自愚。", "肯信白圭終在璞，誰憐滄海竟遺珠。", "閑來撫景窮吟處，尊酒臨風不自娛。"]'),
('9d297f4f-d935-4c89-9c5b-f0934ca509c4','翁母些','牟融','唐','唐诗','tang','','[]','滿頭華髮向人垂，長逝音容逈莫追。',64,'全唐诗/poet.tang.24000.json','["滿頭華髮向人垂，長逝音容逈莫追。", "先壠每懷風木夜，畫堂無復綵衣時。", "停車遙望孤雲影，翹首驚看弔鶴悲。", "獨有賢人崇孝義，傷心共詠蓼莪詩。"]'),
('eceea571-d49a-4753-8a90-d5150f57e509','題山莊','牟融','唐','唐诗','tang','','[]','蘿屋蕭蕭事事幽，臨風搔首遠凝眸。',64,'全唐诗/poet.tang.24000.json','["蘿屋蕭蕭事事幽，臨風搔首遠凝眸。", "東園松菊存遺業，晚景桑榆樂舊遊。", "吟對清尊江上月，笑談華髮鏡中秋。", "牀頭濁酒時時漉，上客相過一任留。"]'),
('d42c39a9-e273-45e9-9b88-6198596d374a','沈存尚林亭夜宴','牟融','唐','唐诗','tang','','[]','草堂寂寂景偏幽，到此令人一縱眸。',64,'全唐诗/poet.tang.24000.json','["草堂寂寂景偏幽，到此令人一縱眸。", "松菊寒香三徑晚，桑榆煙景兩淮秋。", "近山紅葉堆林屋，隔浦青帘拂畫樓。", "終日忘情能自樂，清尊應得遣閑愁。"]'),
('e04a36c8-eae9-437e-880e-4cbea61baba0','題孫君山亭','牟融','唐','唐诗','tang','','[]','長年樂道遠塵氛，靜築藏修學隱淪。',64,'全唐诗/poet.tang.24000.json','["長年樂道遠塵氛，靜築藏修學隱淪。", "吟對琴樽庭下月，笑看花木檻前春。", "閑來欲著登山屐，醉裏還披漉酒巾。", "林壑能忘軒冕貴，白雲黃鶴好相親。"]'),
('2291a937-cdb2-4e74-ba2a-68dcc7f5688a','題徐俞山居','牟融','唐','唐诗','tang','','[]','青山重疊巧裁攢，引水流泉夜激湍。',64,'全唐诗/poet.tang.24000.json','["青山重疊巧裁攢，引水流泉夜激湍。", "嵐鎖巖扉清晝瞑，雲歸松壑翠陰寒。", "不因李相門前見，曾向袁生畫裏看。", "老我不堪詩思杳，幾回吟倚曲欄干。"]'),
('4369b75b-6729-4281-807d-c7d5b154e66f','送范啓東還京','牟融','唐','唐诗','tang','','[]','蕭蕭行李上征鞍，滿目離情欲去難。',64,'全唐诗/poet.tang.24000.json','["蕭蕭行李上征鞍，滿目離情欲去難。", "客裏故人尊酒別，天涯遊子弊裘寒。", "官橋楊柳和愁折，驛路梅花帶雪看。", "重到京華舊遊處，春風佳麗好盤桓。"]'),
('2674caf2-9c0c-4db5-8f01-9ad5c898d49b','樓城敘別','牟融','唐','唐诗','tang','','[]','故人爲客上神州，傾蓋相逢感昔遊。',64,'全唐诗/poet.tang.24000.json','["故人爲客上神州，傾蓋相逢感昔遊。", "屈指年華嗟遠別，對牀風雨話離愁。", "清樽不負花前約，白髮驚看鏡裏秋。", "此際那堪重分手，緣波芳草暫停舟。"]'),
('57938398-b4bb-4494-82b3-f36c14f76658','寫意二首 一','牟融','唐','唐诗','tang','','[]','寂寥荒館閉閑門，苔徑陰陰屐少痕。',64,'全唐诗/poet.tang.24000.json','["寂寥荒館閉閑門，苔徑陰陰屐少痕。", "白髮顛狂塵夢斷，青氈泠落客心存。", "高山流水琴三弄，明月清風酒一樽。", "醉後曲肱林下臥，此生榮辱不須論。"]'),
('ba64c085-07d7-4323-9f12-5b9d6f4e296a','寫意二首 二','牟融','唐','唐诗','tang','','[]','蕭蕭華髮滿頭生，深遠蓬門倦送迎。',64,'全唐诗/poet.tang.24000.json','["蕭蕭華髮滿頭生，深遠蓬門倦送迎。", "獨喜冥心無外慕，自憐知命不求榮。", "閑情欲賦思陶令，臥病和人問馬卿。", "林下貧居甘困守，儘教城市不知名。"]'),
('d201c3e6-164a-4668-b5cd-a637b59caf4f','贈浙西李相公','牟融','唐','唐诗','tang','','[]','長庚烈烈獨遙天，盛世應知降謫仙。',64,'全唐诗/poet.tang.24000.json','["長庚烈烈獨遙天，盛世應知降謫仙。", "月裏昔曾分兔藥，人間今喜得椿年。", "文章政事追先達，冠蓋聲華羨昔賢。", "尊酒與君稱壽畢，春風入醉綺羅筵。"]'),
('b543e7c6-827c-4426-9e56-a73dca37d38c','天台','牟融','唐','唐诗','tang','','[]','碧溪流水泛桃花，樹繞天台逈不賒。',64,'全唐诗/poet.tang.24000.json','["碧溪流水泛桃花，樹繞天台逈不賒。", "洞裏無塵通客境，人間有路入仙家。", "雞鳴犬吠三山近，草靜雲和一徑斜。", "此地不知何處去，暫留瓊珮臥煙霞。"]'),
('87e09967-1a44-4c5e-84ea-9c42c79ddad2','送陳衡','牟融','唐','唐诗','tang','','[]','秋江煙景晚蒼蒼，江上離人促去航。',64,'全唐诗/poet.tang.24000.json','["秋江煙景晚蒼蒼，江上離人促去航。", "千里一官嗟獨往，十年雙髩付三霜。", "雲迷樓曲親庭遠，夢遶通山客路長。", "不必臨風悲冷落，古來白首尚爲郎。"]'),
('61a291be-82d4-447c-880e-02588a163229','送沈翔','牟融','唐','唐诗','tang','','[]','江上西風一櫂歸，故人此別會應稀。',64,'全唐诗/poet.tang.24000.json','["江上西風一櫂歸，故人此別會應稀。", "清朝盡道無遺逸，當路誰曾訪少微。", "謾有才華嗟未達，閑尋鷗鳥暫忘機。", "臨岐不用空惆悵，未必新豐老布衣。"]'),
('c58691a5-35ce-435d-a5f1-bc7e217981d7','過蠡湖','牟融','唐','唐诗','tang','','[]','東湖煙水浩漫漫，湘浦秋聲入夜寒。',64,'全唐诗/poet.tang.24000.json','["東湖煙水浩漫漫，湘浦秋聲入夜寒。", "風外暗香飄落粉，月中清影無離鸞。", "多情袁尹頻移席，有道喬仙獨倚闌。", "幾度篝簾相對處，無邊詩思到吟壇。"]'),
('1a7946a8-5bb2-46aa-a315-26090c935d28','登環翠樓','牟融','唐','唐诗','tang','','[]','山中地僻好藏修，寂寂幽居架小樓。',64,'全唐诗/poet.tang.24000.json','["山中地僻好藏修，寂寂幽居架小樓。", "雲樹四圍當戶瞑，煙嵐一帶隔簾浮。", "舉杯對月邀詩興，撫景令人豁醉眸。", "我亦人間肥遁客，也將蹤跡寄林丘。"]'),
('4db63521-2550-452f-ac70-9d605c61ea0e','遊淮雲寺','牟融','唐','唐诗','tang','','[]','白雲深鎖沃州山，冠蓋登臨衆仰攀。',64,'全唐诗/poet.tang.24000.json','["白雲深鎖沃州山，冠蓋登臨衆仰攀。", "松徑風清聞鶴唳，曇花香瞑見僧還。", "玄機隱隱應難覺，塵事悠悠了不關。", "興盡凡緣因未晚，裴回依舊到人間。"]'),
('8a720961-a110-49ed-a0a4-032177945e48','遊報本寺 一','牟融','唐','唐诗','tang','','[]','山房寂寂蓽門開，此日相期社友來。',64,'全唐诗/poet.tang.24000.json','["山房寂寂蓽門開，此日相期社友來。", "雅興共尋方外樂，新詩爭羨郢中才。", "茶煙褭褭籠禪榻，竹影蕭蕭掃徑苔。", "醉後不知明月上，狂歌直到夜深回。"]'),
('b206e326-7cb5-44cc-b151-af9eba779434','遊報本寺 二','牟融','唐','唐诗','tang','','[]','了然塵事不相關，錫杖時時獨看山。',64,'全唐诗/poet.tang.24000.json','["了然塵事不相關，錫杖時時獨看山。", "白髮任教雙鬢改，黃金難買一生閑。", "不留活計存囊底，贏得詩名滿世間。", "自笑微軀長碌碌，幾時來此學無還。"]'),
('371f7357-b097-4255-9cac-7499ccdcb856','題陳侯竹亭','牟融','唐','唐诗','tang','','[]','曾向幽亭一榻分，清風滿座絕塵氛。',64,'全唐诗/poet.tang.24000.json','["曾向幽亭一榻分，清風滿座絕塵氛。", "丹山鳳泣鉤簾聽，滄海龍吟對酒聞。", "漠漠瞑陰籠砌月，盈盈寒翠動湘雲。", "歲寒高節誰能識，獨有王猷愛此君。"]'),
('fbe8ec8d-5657-431d-85d9-d3672bbbe8a5','送報本寺分韻得通字','牟融','唐','唐诗','tang','','[]','幾度乘閑謁梵宮，此郎聲價重江東。',64,'全唐诗/poet.tang.24000.json','["幾度乘閑謁梵宮，此郎聲價重江東。", "貴侯知重曾忘勢，閑客頻來也悟空。", "滿地新蔬和雨綠，半林殘葉帶霜紅。", "□□□□□□□，□□□□□□□。"]'),
('2667b4fe-af45-4d3d-8ac6-1db4a3956aad','寄永平友人 一','牟融','唐','唐诗','tang','','[]','故人千里隔天涯，幾度臨風動遠思。',64,'全唐诗/poet.tang.24000.json','["故人千里隔天涯，幾度臨風動遠思。", "賈誼上書曾伏闕，仲舒陳策欲匡時。", "高風落落誰同調，往事悠悠我獨悲。", "何日歸來話疇昔，一樽重敘舊襟期。"]'),
('e695912e-4d3a-4f25-9d57-c2c00ee844d6','寄永平友人 二','牟融','唐','唐诗','tang','','[]','朔風獵獵慘寒沙，關月寥寥咽暮笳。',64,'全唐诗/poet.tang.24000.json','["朔風獵獵慘寒沙，關月寥寥咽暮笳。", "放逐一心終去國，驅馳千里未還家。", "青蠅點玉原非病，滄海遺珠世所嗟。", "直道未容淹屈久，暫勞踪跡寄天涯。"]'),
('6b4fc113-fbd5-44ef-9815-8a084b6f7a0b','陳使君山莊','牟融','唐','唐诗','tang','','[]','新卜幽居地自偏，士林爭羨使君賢。',64,'全唐诗/poet.tang.24000.json','["新卜幽居地自偏，士林爭羨使君賢。", "數椽瀟灑臨溪屋，十畝膏腴附郭田。", "流水斷橋芳草路，淡煙疎雨落花天。", "秋成準擬重來此，沈醉何妨一榻眠。"]'),
('2b0ef576-82d1-496b-bdd4-e3aee01dfaef','題寺壁','牟融','唐','唐诗','tang','','[]','僧家勝景瞰平川，霧重嵐深馬不前。',64,'全唐诗/poet.tang.24000.json','["僧家勝景瞰平川，霧重嵐深馬不前。", "宛轉數聲花外鳥，往來幾葉渡頭船。", "青山遠隔紅塵路，碧殿深籠綠樹煙。", "聞道此中堪遁跡，肯容一榻學逃禪。"]'),
('a7676563-d551-42d6-ba01-92ebfe231f4a','送徐浩','牟融','唐','唐诗','tang','','[]','渡口潮平促去舟，莫辭尊酒暫相留。',64,'全唐诗/poet.tang.24000.json','["渡口潮平促去舟，莫辭尊酒暫相留。", "弟兄聚散雲邊鴈，踪跡浮沈水上鷗。", "千里好山青入楚，幾家深樹碧藏樓。", "知君此去情偏切，堂上椿萱雪滿頭。"]'),
('7bac46d9-0931-4b69-beec-3f548366faad','謝惠劒','牟融','唐','唐诗','tang','','[]','感君三尺鐵，揮攉鬼神驚。',48,'全唐诗/poet.tang.24000.json','["感君三尺鐵，揮攉鬼神驚。", "浩氣中心發，雄風兩腋生。", "犬戎從此滅，巢穴不時平。", "萬里橫行去，封侯賴有成。"]'),
('5f2b88c2-40e1-4095-b449-107411eaa74b','送僧','牟融','唐','唐诗','tang','','[]','梵王生別思，之子事遐征。',48,'全唐诗/poet.tang.24000.json','["梵王生別思，之子事遐征。", "煙水浮杯渡，雲山隻履行。", "三生塵夢醒，一錫衲衣輕。", "此去家林近，飄飄物外情。"]'),
('5a902c04-8ad9-4f73-9fd8-9e4340dee965','送友人','牟融','唐','唐诗','tang','','[]','有客櫂扁舟，相逢不暫留。',48,'全唐诗/poet.tang.24000.json','["有客櫂扁舟，相逢不暫留。", "衣冠重文物，詩酒足風流。", "官路生歸興，家林想舊遊。", "臨岐分手後，乘月過蘇州。"]'),
('b95f1d2a-0b4f-45df-8eb2-aae906c694a6','題朱慶餘閑居四首 一','牟融','唐','唐诗','tang','','[]','瀟灑藏脩處，琴書與畫圖。',48,'全唐诗/poet.tang.24000.json','["瀟灑藏脩處，琴書與畫圖。", "白丁門外遠，俗子眼前無。", "楚楚臨軒竹，青青映水蒲。", "道人能愛靜，諸事近清枯。"]'),
('07f32064-b036-48ed-942a-b4e62130bf12','題朱慶餘閑居四首 二','牟融','唐','唐诗','tang','','[]','盡日衡門閉，蒼苔一徑新。',48,'全唐诗/poet.tang.24000.json','["盡日衡門閉，蒼苔一徑新。", "客心非厭靜，悟道不憂貧。", "白屋懸塵榻，清樽憶故人。", "近來疎懶甚，詩債後吟身。"]'),
('ccf84325-f427-4c29-a7ea-1b260fc51f82','題朱慶餘閑居四首 三','牟融','唐','唐诗','tang','','[]','閑客幽棲處，瀟然一草廬。',48,'全唐诗/poet.tang.24000.json','["閑客幽棲處，瀟然一草廬。", "路通元亮宅，門對子雲居。", "按劒心猶壯，琴書樂有餘。", "黃金都散盡，收得鄴侯書。"]'),
('81d9840a-ce29-4a20-ad28-e1b6b7988399','題朱慶餘閑居四首 四','牟融','唐','唐诗','tang','','[]','寂寥荒館下，投老欲何爲。',48,'全唐诗/poet.tang.24000.json','["寂寥荒館下，投老欲何爲。", "草色凝陳榻，書聲出董帷。", "閑雲長作伴，歸鶴獨相隨。", "才薄知無用，安貧不自危。"]'),
('8d31c3d7-cf58-4292-8c48-3849855a7dfe','寄張源','牟融','唐','唐诗','tang','','[]','咫尺西江路，悲歡暫莫聞。',48,'全唐诗/poet.tang.24000.json','["咫尺西江路，悲歡暫莫聞。", "青年俱未達，白社獨離羣。", "曲徑荒秋草，衡茅掩夕曛。", "相思不相見，愁絕賦停雲。"]'),
('941c12ec-7d72-4d86-b9f1-9c5057fae10c','題竹','牟融','唐','唐诗','tang','','[]','瀟灑碧玉枝，清風追晉賢。',48,'全唐诗/poet.tang.25000.json','["瀟灑碧玉枝，清風追晉賢。", "數點渭川雨，一縷湘江煙。", "不見鳳皇尾，誰識珊瑚鞭。", "柯亭丁相遇，驚聽奏鈞天。"]'),
('95329e84-1101-42c8-a307-221afe9adedf','有感','牟融','唐','唐诗','tang','','[]','盛世嗟沈伏，中情怏未舒。',48,'全唐诗/poet.tang.25000.json','["盛世嗟沈伏，中情怏未舒。", "途窮悲阮籍，病久憶相如。", "無客空塵榻，閑門閉草廬。", "不勝岑絕處，高臥半牀書。"]'),
('ab5af83c-c12a-4be9-9cd9-527685541f38','題山房壁','牟融','唐','唐诗','tang','','[]','珠林春寂寂，寶地夜沈沈。',48,'全唐诗/poet.tang.25000.json','["珠林春寂寂，寶地夜沈沈。", "玄奧凝神久，禪機入妙深。", "參同大塊理，窺測至人心。", "定處波羅蜜，須從物外尋。"]'),
('092cd738-8136-43ef-9316-8ad09aa8b6be','訪請上人','牟融','唐','唐诗','tang','','[]','曲徑遶叢林，鐘聲雜梵音。',48,'全唐诗/poet.tang.25000.json','["曲徑遶叢林，鐘聲雜梵音。", "松風吹定衲，蘿月照禪心。", "撫景吟行遠，談玄入悟深。", "不能塵鞅脫，聊復一登臨。"]'),
('d1e265dd-c04b-4ce7-b253-9c1bd436bcc6','送范啓東','牟融','唐','唐诗','tang','','[]','楊柳春江上，東風一櫂輕。',48,'全唐诗/poet.tang.25000.json','["楊柳春江上，東風一櫂輕。", "行囊歸客興，尊酒故人情。", "畫史名當代，聲華重兩京。", "臨岐分手處，無奈別離生。"]'),
('151c740c-79b9-41e6-8e76-a087145df87a','客中作','牟融','唐','唐诗','tang','','[]','十年江漢客，幾度帝京遊。',48,'全唐诗/poet.tang.25000.json','["十年江漢客，幾度帝京遊。", "跡比風前葉，身如水上鷗。", "醉吟愁裏月，羞對鏡中秋。", "悵望頻回首，西風憶故丘。"]'),
('44570ebc-6f0d-4230-8b79-50c392b095ac','贈韓翃','牟融','唐','唐诗','tang','','[]','京國久知名，江河近識荆。',48,'全唐诗/poet.tang.25000.json','["京國久知名，江河近識荆。", "不辭今日醉，便有故人情。", "細雨孤鴻遠，西風一櫂輕。", "暫時分手去，應不負詩盟。"]'),
('7a7c5b6b-7d8b-40fd-a4f1-1ab8962a0826','禁煙作','牟融','唐','唐诗','tang','','[]','柳拖金縷拂朱欄，花撲香塵滿繡鞍。',32,'全唐诗/poet.tang.25000.json','["柳拖金縷拂朱欄，花撲香塵滿繡鞍。", "尊酒臨風酬令節，越羅衣薄覺春寒。"]'),
('854a5f66-f4b6-49dd-b2d5-f8e873246c66','閩中回','牟融','唐','唐诗','tang','','[]','帆影隨風過富陽，櫓聲搖月下錢塘。',32,'全唐诗/poet.tang.25000.json','["帆影隨風過富陽，櫓聲搖月下錢塘。", "千山積雪凝寒碧，夢入楓宸遶御牀。"]'),
('1e7a0f84-0c9b-4318-b378-8691bb22a63a','苦婦詞','劉言史','唐','唐诗','tang','','[]','地遠易驕崇，用刑匪精研。',216,'全唐诗/poet.tang.25000.json','["地遠易驕崇，用刑匪精研。", "哀哉苦婦身，夫死百殃纏。", "草草催出門，衣墮髮披肩。", "獨隨軍吏行，當夕余欲遷。", "來時已厭生，到此自不全。", "臨江臥黃砂，二子死在邊。", "氣噦不發聲，背頭血涓涓。", "有時強爲言，祗是尤青天。", "藳蓐無一枝，冷氣兩懸懸。", "窮荒夷教卑，骨肉病棄捐。", "況非本族音，肌露誰爲憐。", "事痛感行賓，住得貪程船。", "必當負嚴法，豈有胎孕篇。", "遊畋復釋麛，羔兔尚免鸇。", "何處擯逐深，一罪三見顛。", "校尉勳望重，幕府才且賢。", "蘭裙間珠履，食玉處花筵。", "但勿輕所暗，莫慮無人焉。"]'),
('26f085ee-d6b5-4461-9197-8ada7ead97fe','與孟郊洛北野泉上煎茶','劉言史','唐','唐诗','tang','','[]','粉細越笋芽，野煎寒溪濱。',108,'全唐诗/poet.tang.25000.json','["粉細越笋芽，野煎寒溪濱。", "恐乖靈草性，觸事皆手親。", "敲石取鮮火，撇泉避腥鱗。", "熒熒爨風鐺，拾得墜巢薪。", "潔色既爽別，浮氳亦慇懃。", "以茲委曲靜，求得正味真。", "宛如摘山時，自歠指下春。", "湘瓷泛輕花，滌盡昏渴神。", "此遊愜醒趣，可以話高人。"]'),
('cf438e2b-71eb-4b9a-bafc-171e9c1b3a60','七夕歌','劉言史','唐','唐诗','tang','','[]','星寥寥兮月細輪，佳期可想兮不可親。',97,'全唐诗/poet.tang.25000.json','["星寥寥兮月細輪，佳期可想兮不可親。", "雲衣香薄粧態新，彩軿悠悠度天津。", "玉幌相逢夜將極，妖紅慘黛生愁色。", "寂寞低容入舊機，歇著金梭思往夕。", "人間不見因誰知，萬家閨豔求此時。", "碧空露重彩盤濕，花上乞得蜘蛛絲。"]'),
('308cd53c-fc61-4dde-899e-a4db10cb3302','立秋日','劉言史','唐','唐诗','tang','','[]','商風動葉初，蕭索一貧居。',48,'全唐诗/poet.tang.25000.json','["商風動葉初，蕭索一貧居。", "老性容茶少，羸肌與簟疎。", "舊醅難重漉，新菜未勝鉏。", "才薄無潘興，便便畫偃廬。"]'),
('83155f4e-a52e-4787-8b9f-5f160fb8f59c','題茅山仙臺藥院','劉言史','唐','唐诗','tang','','[]','擾擾浮生外，華陽一洞春。',60,'全唐诗/poet.tang.25000.json','["擾擾浮生外，華陽一洞春。", "道書金字小，仙圃玉苗新。", "芝草迎飛燕，桃花笑俗人。", "樓臺爭聳漢，雞犬亦嫌秦。", "願得青芽散，長年駐此身。"]'),
('debf0e3c-9f40-43cf-8102-ce0c7852f93c','送婆羅門歸本國','劉言史','唐','唐诗','tang','','[]','剎利王孫字迦攝，竹錐橫寫叱蘿葉。',112,'全唐诗/poet.tang.25000.json','["剎利王孫字迦攝，竹錐橫寫叱蘿葉。", "遙知漢地未有經，手牽白馬遶天行。", "龜茲磧西胡雪黑，大師凍死來不得。", "地盡年深始到船，海裏更行三十國。", "行多耳斷金環落，冉冉悠悠不停脚。", "馬死經留却去時，往來應盡一生期。", "出漠獨行人絕處，磧西天漏雨絲絲。"]'),
('6f8b1f28-3851-4b7f-bd62-2b63eb67793d','瀟湘遊','劉言史','唐','唐诗','tang','','[]','夷女采山蕉，緝紗浸江水。',128,'全唐诗/poet.tang.25000.json','["夷女采山蕉，緝紗浸江水。", "野花滿髻妝色新，閑歌[欸]乃深峽裏。", "[欸]乃知從何處生，當時泣舜腸斷聲。", "翠華寂寞嬋娟沒，野篠空餘紅淚情。", "青煙冥冥覆杉桂，崖壁凌天風雨細。", "昔人幽恨此地遺，綠芳紅豔含怨姿。", "清猨未盡鼯鼠切，淚水流到湘妃祠。", "北人莫作瀟湘遊，九疑雲入蒼梧愁。"]'),
('97bdc1a3-da7a-46b1-a6f3-effdb768335c','放螢怨','劉言史','唐','唐诗','tang','','[]','放螢去，不須留，聚時年少今白頭。',96,'全唐诗/poet.tang.25000.json','["放螢去，不須留，聚時年少今白頭。", "架中科斗萬餘卷，一字千回重照見。", "青雲杳渺不可親，開囊欲放增餘怨。", "且逍遙，還酩酊，仲舒漫不窺園井。", "那將寂寞老病身，更就微蟲借光影。", "欲放時，淚沾裳，衝籬落，千點光。"]'),
('f45d47f8-14cf-4462-b963-db53411723ec','觀繩伎','劉言史','唐','唐诗','tang','','[]','泰陵遺樂何最珍，綵繩冉冉天仙人。',144,'全唐诗/poet.tang.25000.json','["泰陵遺樂何最珍，綵繩冉冉天仙人。", "廣場寒食風日好，百夫伐鼓錦臂新。", "銀畫青綃抹雲髮，高處綺羅香更切。", "重肩接立三四層，著屐背行仍應節。", "兩邊丸劒漸相迎，側身交步何輕盈。", "閃然欲落却收得，萬人肉上寒毛生。", "危機險勢無不有，倒挂纖腰學垂柳。", "下來一一芙蓉姿，粉薄鈿稀態轉奇。", "坐中還有沾巾者，曾見先皇初教時。"]'),
('a5942196-b9e8-4ee2-a96a-2130cde47cbb','買花謠','劉言史','唐','唐诗','tang','','[]','杜陵村人不田穡，入谷經谿復緣壁。',128,'全唐诗/poet.tang.25000.json','["杜陵村人不田穡，入谷經谿復緣壁。", "每至南山草木春，即向侯家取金碧。", "幽豔凝華春景曙，林夫移得將何處。", "蝶惜芳叢送下山，尋斷孤香始回去。", "豪少居連鳷鵲東，千金使買一株紅。", "院多花少栽未得，零落綠娥纖指中。", "咸陽親戚長安里，無限將金買花子。", "澆紅溼綠千萬家，青絲玉轤聲啞啞。"]'),
('a22c9e9b-2ac1-4bc1-a2ff-0d4e853748e0','王中丞宅夜觀舞胡騰','劉言史','唐','唐诗','tang','','[]','石國胡兒人見少，蹲舞尊前急如鳥。',112,'全唐诗/poet.tang.25000.json','["石國胡兒人見少，蹲舞尊前急如鳥。", "織成蕃帽虛頂尖，細氎胡衫雙袖小。", "手中拋下蒲萄盞，西顧忽思鄉路遠。", "跳身轉轂寶帶鳴，弄脚繽紛錦靴軟。", "四座無言皆瞪目，橫笛琵琶徧頭促。", "亂騰新毯雪朱毛，傍拂輕花下紅燭。", "酒闌舞罷絲管絕，木槿花西見殘月。"]'),
('9debbe96-77b3-4b24-ab2d-7c3afc4a9245','竹裏梅','劉言史','唐','唐诗','tang','','[]','竹裏梅花相竝枝，梅花正發竹枝垂。',32,'全唐诗/poet.tang.25000.json','["竹裏梅花相竝枝，梅花正發竹枝垂。", "風吹總向竹枝上，直似王家雪下時。"]'),
('1d6dc622-41f0-47a1-956b-e2e37a6d9d97','春過趙墟','劉言史','唐','唐诗','tang','','[]','下馬邯鄲陌頭歇，寂寥崩隧臨車轍。',48,'全唐诗/poet.tang.25000.json','["下馬邯鄲陌頭歇，寂寥崩隧臨車轍。", "古柏重生枝亦乾，餘燎見風幽燄滅。", "白蒿微發紫槿新，行人感此復悲春。"]'),
('7909697a-00a4-4e4e-b709-f2868012c347','初下東周贈孟郊','劉言史','唐','唐诗','tang','','[]','鶴老身更卬，龜死殼亦靈。',194,'全唐诗/poet.tang.25000.json','["鶴老身更卬，龜死殼亦靈。", "正信非外沿，終始全本情。", "童子不戲塵，積書就巖扃。", "身著木葉衣，養鹿兼牸耕。", "偶隨下山雲，荏苒失故程。", "漸入機險中，危思難太行。", "十髮九縷絲，悠然東周城。", "言詞野麋態，出口多累形。", "因依漢元寮，未思羇細輕。", "[冷]竈助新熱，靜砧與寒聲。", "斷蓬在門欄，豈當桃李榮。", "寄食若蠹蟲，侵損利微生。", "固非拙爲強，懦劣外療幷。", "素堅冰蘖心，潔持保堅貞。", "修文返正風，刊字齊古經。", "慙將衰末分，高棲喧世名。"]'),
('60e1af46-66be-43d8-a2ad-94a12302cab2','過春秋峽','劉言史','唐','唐诗','tang','','[]','峭壁蒼蒼苔色新，無風晴景自勝春。',32,'全唐诗/poet.tang.25000.json','["峭壁蒼蒼苔色新，無風晴景自勝春。", "不知何樹幽崖裏，臘月開花似北人。"]'),
('d0c63bd0-63fa-4596-b2f0-5e12338b05b7','長門怨','劉言史','唐','唐诗','tang','','[]','獨坐爐邊結夜愁，暫時思去亦難留。',32,'全唐诗/poet.tang.25000.json','["獨坐爐邊結夜愁，暫時思去亦難留。", "手持金筯垂紅淚，亂撥寒灰不舉頭。"]'),
('f133634b-1548-4a95-86ca-f80023f85859','春遊曲 一','劉言史','唐','唐诗','tang','','[]','花頷紅騣一何偏，綠槐香陌欲朝天。',32,'全唐诗/poet.tang.25000.json','["花頷紅騣一何偏，綠槐香陌欲朝天。", "仍嫌衆裏嬌行疾，傍𩍐深藏白玉鞭。"]'),
('05f48ef3-a731-43b3-9464-67870b443044','春遊曲 二','劉言史','唐','唐诗','tang','','[]','噴沫團香小桂條，玉鞭兼賜霍嫖姚。',32,'全唐诗/poet.tang.25000.json','["噴沫團香小桂條，玉鞭兼賜霍嫖姚。", "弄影便從天禁出，碧蹄聲碎五門橋。"]'),
('b37edae0-497b-4ba6-a5d7-0ea0adbc3e3f','廣州王園寺伏日即事寄北中親友','劉言史','唐','唐诗','tang','','[]','南越逢初伏，東林度一朝。',120,'全唐诗/poet.tang.25000.json','["南越逢初伏，東林度一朝。", "曲池煎畏景，高閣絕微飇。", "竹簟移先灑，蒲葵破復搖。", "地偏毛瘴近，山毒火威饒。", "裛汗絺如濯，親牀枕竝燒。", "墮枝傷翠羽，萎葉惜紅蕉。", "且困流金熾，難成獨酌謠。", "望霖窺潤礎，思吹候生條。", "旅恨生烏滸，鄉心繫洛橋。", "誰憐在炎客，一夕壯容銷。"]'),
('0be6139d-9f86-4c80-8689-babed4019d9f','立秋','劉言史','唐','唐诗','tang','','[]','茲晨戒流火，商飇早已驚。',24,'全唐诗/poet.tang.25000.json','["茲晨戒流火，商飇早已驚。", "雲天收夏色，木葉動秋聲。"]'),
('b4cf3361-d8ac-48f7-9120-f58bff432536','別落花','劉言史','唐','唐诗','tang','','[]','風豔霏霏去，羈人處處游。',24,'全唐诗/poet.tang.25000.json','["風豔霏霏去，羈人處處游。", "明年縱相見，不在此枝頭。"]'),
('d2b2d38c-9a11-48df-a7be-a47c3aa44e0e','登甘露臺','劉言史','唐','唐诗','tang','','[]','偶至無塵空翠間，雨花甘露境閑閑。',32,'全唐诗/poet.tang.25000.json','["偶至無塵空翠間，雨花甘露境閑閑。", "身心未寂終爲累，非想天中獨退還。"]'),
('bcfd4a4f-69d0-4de5-b609-28eb7608c9bb','夜泊潤州江口','劉言史','唐','唐诗','tang','','[]','秋江欲起白頭波，賈客瞻風無渡河。',32,'全唐诗/poet.tang.25000.json','["秋江欲起白頭波，賈客瞻風無渡河。", "千船火絕寒宵半，獨聽鐘聲覺寺多。"]'),
('e2d1b5b7-a667-462c-bc61-5cd7ebde7bcc','看山木瓜花二首 一','劉言史','唐','唐诗','tang','','[]','裛露凝氛紫豔新，千般婉娜不勝春。',32,'全唐诗/poet.tang.25000.json','["裛露凝氛紫豔新，千般婉娜不勝春。", "年年此樹花開日，出盡丹陽郭裏人。"]'),
('6d9a74e6-a65c-497f-bbd0-9f5d37d4255d','看山木瓜花二首 二','劉言史','唐','唐诗','tang','','[]','柔枝濕豔亞朱欄，暫作庭芳便欲殘。',32,'全唐诗/poet.tang.25000.json','["柔枝濕豔亞朱欄，暫作庭芳便欲殘。", "深藏數片將歸去，紅縷金針繡取看。"]'),
('ab5d3922-f997-44f7-8cc7-72b017e320f8','題十三弟竹園','劉言史','唐','唐诗','tang','','[]','繞屋扶疎聳翠莖，苔滋粉漾有幽情。',32,'全唐诗/poet.tang.25000.json','["繞屋扶疎聳翠莖，苔滋粉漾有幽情。", "丹陽萬戶春光靜，獨自君家秋雨聲。"]'),
('83ddcde7-d0a1-4aff-aed2-e715b4718bd7','樂府雜詞三首 一','劉言史','唐','唐诗','tang','','[]','紫禁梨花飛雪毛，春風絲管翠樓高。',32,'全唐诗/poet.tang.25000.json','["紫禁梨花飛雪毛，春風絲管翠樓高。", "城裏萬家聞不見，君王試舞鄭櫻桃。"]'),
('15fe86ed-edfe-4f94-86fd-8877d8d97182','樂府雜詞三首 二','劉言史','唐','唐诗','tang','','[]','蟬鬢紅冠粉黛輕，雲和新教羽衣成。',32,'全唐诗/poet.tang.25000.json','["蟬鬢紅冠粉黛輕，雲和新教羽衣成。", "月光如雪金堦上，迸却頗梨義甲聲。"]'),
('5aa7a45a-49ec-41aa-bb3f-ede353c76957','樂府雜詞三首 三','劉言史','唐','唐诗','tang','','[]','不耐簷前紅槿枝，薄妝春寢覺仍遲。',32,'全唐诗/poet.tang.25000.json','["不耐簷前紅槿枝，薄妝春寢覺仍遲。", "夢中無限風流事，夫壻多情亦未知。"]'),
('52e9e9f5-c0cb-4da9-9274-f407121aa5b3','歲暮題楊錄事江亭','劉言史','唐','唐诗','tang','','[]','垂絲蜀客涕濡衣，歲盡長沙未得歸。',32,'全唐诗/poet.tang.25000.json','["垂絲蜀客涕濡衣，歲盡長沙未得歸。", "腸斷錦帆風日好，可憐桐鳥出花飛。"]'),
('f9fc950a-f38f-4afa-9651-39cfecafba6d','冬日峽中旅泊','劉言史','唐','唐诗','tang','','[]','霜月明明雪復殘，孤舟夜泊使君灘。',32,'全唐诗/poet.tang.25000.json','["霜月明明雪復殘，孤舟夜泊使君灘。", "一聲鐘出遠山裏，暗想雪窗僧起寒。"]'),
('54fdc1da-b71b-465c-b8f8-dc9d91069fec','泊花石浦','劉言史','唐','唐诗','tang','','[]','舊業叢臺廢苑東，幾年爲梗復爲蓬。',32,'全唐诗/poet.tang.25000.json','["舊業叢臺廢苑東，幾年爲梗復爲蓬。", "杜鵑啼斷回家夢，半在邯鄲驛樹中。"]'),
('89f674d5-2011-4d86-aa84-f8ec4c1b8315','聞崔倚旅葬','劉言史','唐','唐诗','tang','','[]','遠客那能返故廬，蒼梧埋骨痛何如。',32,'全唐诗/poet.tang.25000.json','["遠客那能返故廬，蒼梧埋骨痛何如。", "他時親戚空相憶，席上同悲一紙書。"]'),
('75d190fd-838a-4d42-a10b-cb5e0e514fbf','賦蕃子牧馬','劉言史','唐','唐诗','tang','','[]','磧淨山高見極邊，孤烽引上一條煙。',32,'全唐诗/poet.tang.25000.json','["磧淨山高見極邊，孤烽引上一條煙。", "蕃落多晴塵擾擾，天軍獵到鸊鵜泉。"]'),
('41e7ebc7-76c3-4292-8f3d-4c2bb6fa4c6b','牧馬泉','劉言史','唐','唐诗','tang','','[]','平沙漫漫馬悠悠，弓箭閑拋郊水頭。',32,'全唐诗/poet.tang.25000.json','["平沙漫漫馬悠悠，弓箭閑拋郊水頭。", "鼠毛衣裏取羌笛，吹向秋天眉眼愁。"]'),
('835d1c01-fd05-4d92-ab55-700116717b60','越井臺望','劉言史','唐','唐诗','tang','','[]','獨立陽臺望廣州，更添羈客異鄉愁。',32,'全唐诗/poet.tang.25000.json','["獨立陽臺望廣州，更添羈客異鄉愁。", "晚潮未至早潮落，井邑暫依沙上頭。"]'),
('96827e11-bc6c-4705-b95c-64c46f9f1ea8','扶病春亭','劉言史','唐','唐诗','tang','','[]','強梳稀髮著綸巾，捨杖空行試病身。',32,'全唐诗/poet.tang.25000.json','["強梳稀髮著綸巾，捨杖空行試病身。", "花間自欲裴回立，穉子牽衣不許人。"]'),
('e6dc08a7-68bb-4817-a92f-48c2bc8657a6','贈童尼','劉言史','唐','唐诗','tang','','[]','舊時豔質如明玉，今日空心是冷灰。',32,'全唐诗/poet.tang.25000.json','["舊時豔質如明玉，今日空心是冷灰。", "料得襄王惆悵極，更無雲雨到陽臺。"]'),
