('e0cf02ab-c5a8-4fc3-a3cb-53e21d4a3679','席上贈李尹','劉言史','唐','唐诗','tang','','[]','傴僂山夫髮似絲，松間石上坐多時。',32,'全唐诗/poet.tang.25000.json','["傴僂山夫髮似絲，松間石上坐多時。", "瓢飲不曾看酒肆，世人空笑亦何爲。"]'),
('62398c45-64ca-45a1-af5c-f788c479f1f8','弼公院問病','劉言史','唐','唐诗','tang','','[]','一頭細髮兩分絲，臥見芭蕉白露滋。',32,'全唐诗/poet.tang.25000.json','["一頭細髮兩分絲，臥見芭蕉白露滋。", "欲令居士身無病，直待衆生苦盡時。"]'),
('ba152c85-e889-40b0-812b-2fb34179e18f','惜花','劉言史','唐','唐诗','tang','','[]','年少共憐含露色，老人偏惜委塵紅。',32,'全唐诗/poet.tang.25000.json','["年少共憐含露色，老人偏惜委塵紅。", "如何遂得心中事，每要花時不厭風。"]'),
('85d5ca9c-bcd9-4cbc-b1dd-265dc92dc649','代胡僧留別','劉言史','唐','唐诗','tang','','[]','此地緣疎語未通，歸時老病去無窮。',32,'全唐诗/poet.tang.25000.json','["此地緣疎語未通，歸時老病去無窮。", "定知不徹南天竺，死在條支陰磧中。"]'),
('a35b581c-9679-4bac-9c39-5c2b0d043910','桂江逢王使君旅櫬歸','劉言史','唐','唐诗','tang','','[]','故人丹旐出南威，少婦隨喪哭漸歸。',32,'全唐诗/poet.tang.25000.json','["故人丹旐出南威，少婦隨喪哭漸歸。", "遙想北原新壠上，日寒光淺水松稀。"]'),
('223fbd22-9e58-4cb8-8185-7d404ae4e3ec','玉京詞','劉言史','唐','唐诗','tang','','[]','絕景寥寥日更遲，人間甲子不同時。',32,'全唐诗/poet.tang.25000.json','["絕景寥寥日更遲，人間甲子不同時。", "未知樵客終何得，歸後無家是看棋。"]'),
('b862611f-7390-4eae-b8e4-0a31e57d6993','葛巾歌','劉言史','唐','唐诗','tang','','[]','一片白葛巾，潛夫自能結。',136,'全唐诗/poet.tang.25000.json','["一片白葛巾，潛夫自能結。", "籬邊折枯蒿，聊用簪華髮。", "有時醉倒長松側，酒醒不見心還憶。", "谷鳥銜將却趁來，野風吹去還尋得。", "十年紫竹溪南住，跡同玄豹依深霧。", "草堂窗底漉春醅，山寺門前逢暮雨。", "臨汝袁郎得相見，閑雲引到東陽縣。", "魯性將他類此身，還拈野物贈傍人。", "空留梲杖犢鼻褌，濛濛煙雨歸山村。"]'),
('0bbef731-af78-45d6-8fa4-868a1ec97821','北原情三首 一','劉言史','唐','唐诗','tang','','[]','錯莫天色愁，挽歌出重闉。',108,'全唐诗/poet.tang.25000.json','["錯莫天色愁，挽歌出重闉。", "誰家白網車，送客入幽塵。", "銘旌下官道，葬輿去轔轔。", "蕭條黃蒿中，奠酒花翠新。", "米雪晚霏微，墓成悄無人。", "烏鳶下空地，煙火殘荒榛。", "生人更多苦，入戶事盈身。", "營營日易深，却到不得頻。", "寂寥孤隧頭，草綠棠梨春。"]'),
('bda257f6-9f1d-4194-a076-32d79968eb20','北原情三首 二','劉言史','唐','唐诗','tang','','[]','洛陽城北山，古今葬冥客。',72,'全唐诗/poet.tang.25000.json','["洛陽城北山，古今葬冥客。", "聚骨朽成泥，此山土多白。", "近來送葬人，亦去聞歸聲。", "豈能車輪疾，漸是墓侵城。", "城中人不絕，哀挽相次行。", "莫非北邙後，重向洛城生。"]'),
('4ad3e909-fb79-445d-b108-df85d7a28d5f','北原情三首 三','劉言史','唐','唐诗','tang','','[]','卜地起孤墳，全家送葬去。',48,'全唐诗/poet.tang.25000.json','["卜地起孤墳，全家送葬去。", "歸來却到時，不復重知處。", "疊疊葬相續，土乾草已綠。", "列紙瀉壺漿，空向春雲哭。"]'),
('35d39e8c-a34a-4a4b-b569-6f9a87b44b05','林中獨醒','劉言史','唐','唐诗','tang','','[]','晚來林沼靜，獨坐間瓢尊。',48,'全唐诗/poet.tang.25000.json','["晚來林沼靜，獨坐間瓢尊。", "向己非前跡，齊心欲不言。", "微涼生亂篠，輕馥起孤萱。", "未得渾無事，瓜田草正繁。"]'),
('edfa6d28-d658-49ed-939d-c52c34d5d22d','江陵客舍留別樊尚書','劉言史','唐','唐诗','tang','','[]','信陵門館下，多病有歸思。',48,'全唐诗/poet.tang.25000.json','["信陵門館下，多病有歸思。", "墜履忘情後，寒灰更濕時。", "委欄芳蕙晚，憑几雪髫垂。", "明日秋關外，單車風雨隨。"]'),
('aa7f9bd4-42f8-47cc-9ad9-2e410647b389','擬古詠河邊枯樹','長孫佐輔','唐','唐诗','tang','','[]','野火燒枝水洗根，數圍孤樹半心存。',32,'全唐诗/poet.tang.25000.json','["野火燒枝水洗根，數圍孤樹半心存。", "應是無機承雨露，却將春色寄苔痕。"]'),
('206b89d1-ec09-42c4-97cf-b0b2cff84e29','別友人','長孫佐輔','唐','唐诗','tang','','[]','愁多不忍醒時別，想極還尋靜處行。',32,'全唐诗/poet.tang.25000.json','["愁多不忍醒時別，想極還尋靜處行。", "誰遣同衾又分手，不如行路本無情。"]'),
('e0cfc3de-c236-4904-aca1-f3c8536c5e17','傷故人歌妓','長孫佐輔','唐','唐诗','tang','','[]','愁臉無紅衣滿塵，萬家門戶不容身。',32,'全唐诗/poet.tang.25000.json','["愁臉無紅衣滿塵，萬家門戶不容身。", "曾將一笑君前去，悞殺幾多回顧人。"]'),
('fc27b340-1e98-48f2-b3f6-2a8e67608bc0','南中客舍對雨送故人歸北','長孫佐輔','唐','唐诗','tang','','[]','猨聲啾啾雁聲苦，卷簾相對愁不語。',48,'全唐诗/poet.tang.25000.json','["猨聲啾啾雁聲苦，卷簾相對愁不語。", "幾年客吳君在楚，況送君歸我猶阻。", "家書作得不忍封，北風吹斷堦前雨。"]'),
('3355f85a-00ae-422d-b446-f3df558da00c','杭州秋日別故友','長孫佐輔','唐','唐诗','tang','','[]','相見又相別，大江秋水深。',36,'全唐诗/poet.tang.25000.json','["相見又相別，大江秋水深。", "悲歡一世事，去住兩鄉心。", "淅瀝籬下葉，淒清階上琴。"]'),
('c050a0b4-59c6-44fb-b232-5be59cb4d784','代別後夢別','長孫佐輔','唐','唐诗','tang','','[]','別中還夢別，悲後更生悲。',48,'全唐诗/poet.tang.25000.json','["別中還夢別，悲後更生悲。", "覺夢俱千里，追隨難再期。", "翻思夢裏苦，却恨覺來遲。", "縱是非真事，何妨夢會時。"]'),
('2aefdb6f-b553-4f13-94cc-cb7a922a9855','荅邊信','長孫佐輔','唐','唐诗','tang','','[]','征人去年戍遼水，夜得邊書字盈紙。',96,'全唐诗/poet.tang.25000.json','["征人去年戍遼水，夜得邊書字盈紙。", "揮刀就燭裁紅綺，結作同心荅千里。", "君寄邊書書莫絕，妾荅同心心自結。", "同心再解心不離，書字頻看字愁滅。", "結成一夜和淚封，貯書只在懷袖中。", "莫如書字故難久，願學同心長可同。"]'),
('0e2d1361-03c5-444c-ab51-166201d23d35','對鏡吟','長孫佐輔','唐','唐诗','tang','','[]','憶昔逢君新納娉，青銅鑄出千年鏡。',128,'全唐诗/poet.tang.25000.json','["憶昔逢君新納娉，青銅鑄出千年鏡。", "意憐光彩固無瑕，義比恩情永相映。", "每將鑒面兼鑒心，鑒來不輟情逾深。", "君非結心空結帶，結處尚新恩已背。", "開簾覽鏡悲難語，對面相看孟門阻。", "掩匣徒慙雙鳳飛，懸臺欲效孤鸞舞。", "昔日照來人共許，今朝照罷自生疑。", "鏡上有塵猶可淬，君恩詎肯無迴時。"]'),
('dfcd7fea-4ff7-456b-bf87-8cbf77ca87e1','山行書事','長孫佐輔','唐','唐诗','tang','','[]','日落風䬘䬘，驅車行遠郊。',144,'全唐诗/poet.tang.25000.json','["日落風䬘䬘，驅車行遠郊。", "中心有所悲，古墓穿黃茅。", "茅中狐兔窠，四面烏鳶巢。", "鬼火時獨出，人煙不相交。", "行行近破村，一徑欹還坳。", "迎霜聽蟋蟀，向月看蠨蛸。", "翁喜客來至，客來羞廚庖。", "濁醪誇潑蟻，時果仍新苞。", "相勸對寒燈，呼兒爇枯梢。", "性朴頗近古，其言無斗筲。", "憂歡世上幷，歲月途中拋。", "誰知問津客，空作楊雄嘲。"]'),
('efd0a168-459e-485c-824b-54b29ea51736','古宮怨','長孫佐輔','唐','唐诗','tang','','[]','窗前好樹名玫瑰，去年花落今年開。',224,'全唐诗/poet.tang.25000.json','["窗前好樹名玫瑰，去年花落今年開。", "無情春色尚識返，君心忽斷何時來。", "憶昔妝成候僊仗，宮璅玲瓏日新上。", "拊心却笑西子嚬，掩鼻誰憂鄭姬謗。", "草染文章衣下履，花黏甲乙牀前帳。", "三千玉貌休自誇，十二金釵獨相向。", "盛衰傾奪欲何如，嬌愛翻悲逐佞諛。", "重遠豈能慙沼鵠，棄前方見泣船魚。", "看籠不記薰龍腦，詠扇空曾禿鼠鬚。", "始喜類蘿新託柏，終傷如薺却甘荼。", "院深獨開還獨閉，鸚鵡驚飛苔覆地。", "滿箱舊賜前日衣，漬枕新垂夜來淚。", "痕多開鏡照還悲，綠髻青蛾尚未衰。", "莫道新縑長絕比，猶逢故劒會相追。"]'),
('2f933ee2-48fe-4db9-aebe-339daabdeb75','關山月','長孫佐輔','唐','唐诗','tang','','[]','淒淒還切切，戍客多離別。',144,'全唐诗/poet.tang.25000.json','["淒淒還切切，戍客多離別。", "何處最傷心，關山見秋月。", "關月竟如何，由來遠近過。", "始經玄菟塞，終繞白狼河。", "忽憶秦樓婦，流光應共有。", "已得並蛾眉，還知攬纖手。", "去歲照同行，比翼復連形。", "今宵照獨立，顧影自煢煢。", "餘暉漸西落，夜夜看如昨。", "借問暎旌旗，何如鑒帷幕。", "拂曉朔風悲，蓬驚鴈不飛。", "幾時征戍罷，還向月中歸。"]'),
('a4b51bc4-cf49-48d2-a578-d1305c057455','隴西行','長孫佐輔','唐','唐诗','tang','','[]','陰雲凝朔氣，隴上正飛雪。',96,'全唐诗/poet.tang.25000.json','["陰雲凝朔氣，隴上正飛雪。", "四月草不生，北風勁如切。", "朝來羽書急，夜救長城窟。", "道隘行不前，相呼抱鞍歇。", "人寒指欲墮，馬凍蹄亦裂。", "射雁旋充飢，斧冰還止渴。", "寧辭解圍鬬，但恐乘疲沒。", "早晚邊候空，歸來養羸卒。"]'),
('0e8f6d2d-015f-49f6-9756-3131b2d5e793','尋山家','長孫佐輔','唐','唐诗','tang','','[]','獨訪山家歇還涉，茅屋斜連隔松葉。',32,'全唐诗/poet.tang.25000.json','["獨訪山家歇還涉，茅屋斜連隔松葉。", "主人聞語未開門，繞籬野菜飛黃蝶。"]'),
('89e56e93-9ca5-442b-9aa1-42f401bc7589','山居','長孫佐輔','唐','唐诗','tang','','[]','看書愛幽寂，結宇青冥間。',84,'全唐诗/poet.tang.25000.json','["看書愛幽寂，結宇青冥間。", "飛泉引風聽，古桂和雲攀。", "地深草木稠，境靜魚鳥閑。", "陰氣晚出谷，朝光先照山。", "有時獨杖藜，入夜猶啓關。", "星昏歸鳥過，火出樵童還。", "神體自和適，不是離人寰。"]'),
('8d2ccb80-ac5b-4193-a65e-b5980715b2f7','楚州鹽𡏖古牆望海','長孫佐輔','唐','唐诗','tang','','[]','混沌本冥冥，泄爲洪川流。',96,'全唐诗/poet.tang.25000.json','["混沌本冥冥，泄爲洪川流。", "雄哉大造化，萬古橫中州。", "我從西北來，登高望蓬丘。", "陰晴乍開合，天地相沈浮。", "長風卷繁雲，日出扶桑頭。", "水淨露鮫室，煙銷凝蜃樓。", "時來會雲翔，道蹇即津遊。", "明發促歸軫，滄波非宿謀。"]'),
('198447a8-8c14-4edb-b1ce-0adf48bfad63','聞韋駙馬使君遷拜台州','長孫佐輔','唐','唐诗','tang','','[]','溟藩軫帝憂，見說初鳴騶。',144,'全唐诗/poet.tang.25000.json','["溟藩軫帝憂，見說初鳴騶。", "德勝禍先戢，情閑思自流。", "蠶殷桑柘空，廩實雀鼠稠。", "諫虎昔賜駿，安人將問牛。", "曾陪後乘光，共逐平津遊。", "旌斾擁追賞，歌鐘催獻酬。", "音徽一寂寥，貴賤雙沈浮。", "北郭乏中崖，東方稱上頭。", "躋山望百城，目盡增遐愁。", "海逼日月近，天高星漢秋。", "無階異漸鴻，有志慙馴鷗。", "終期促孤櫂，暫訪天台幽。"]'),
('6fe5e136-876f-4a59-b9c8-07030731961e','山行經村徑','長孫佐輔','唐','唐诗','tang','','[]','一徑有人迹，到來唯數家。',48,'全唐诗/poet.tang.25000.json','["一徑有人迹，到來唯數家。", "依稀聽機杼，寂歷看桑麻。", "雨濕渡頭草，風吹墳上花。", "却驅羸馬去，數點歸林鴉。"]'),
('0ccf7c9c-b897-4c42-b550-8faa35864d71','野田行','張碧','唐','唐诗','tang','','[]','風昏晝色飛斜雨，冤骨千堆髑髏語。',100,'全唐诗/poet.tang.25000.json','["風昏晝色飛斜雨，冤骨千堆髑髏語。", "八紘牢落人物悲，是箇田園荒廢主。", "悲嗟自古爭天下，幾度乾坤復如此。", "秦皇矻矻築長城，漢祖區區白蛇死。", "野田之骨兮又成塵，樓閣風煙兮還復新。", "願得華山之下長歸馬，野田無復堆冤者。"]'),
('dc46bde3-b694-4690-a1bf-cbcdbd3e0829','貧女','張碧','唐','唐诗','tang','','[]','豈是昧容華，豈不知機織。',24,'全唐诗/poet.tang.25000.json','["豈是昧容華，豈不知機織。", "自是生寒門，良媒不相識。"]'),
('74002940-307e-4d52-940e-0aeadf86e0c1','幽思','張碧','唐','唐诗','tang','','[]','金爐煙靄微，錦釭殘影滅。',24,'全唐诗/poet.tang.25000.json','["金爐煙靄微，錦釭殘影滅。", "出戶獨裴回，落花滿明月。"]'),
('7b087bb0-7346-405f-888d-4e926134f9a6','惜花三首 一','張碧','唐','唐诗','tang','','[]','千枝萬枝占春開，彤霞著地紅成堆。',32,'全唐诗/poet.tang.25000.json','["千枝萬枝占春開，彤霞著地紅成堆。", "一窖閑愁驅不去，殷勤對爾酌金杯。"]'),
('aae1a96c-39e5-4b58-be2e-232eff1e671f','惜花三首 二','張碧','唐','唐诗','tang','','[]','老鴉拍翼盤空疾，准擬浮生如瞬息。',32,'全唐诗/poet.tang.25000.json','["老鴉拍翼盤空疾，准擬浮生如瞬息。", "阿母蟠桃香未齊，漢皇骨葬秋山碧。"]'),
('f8fc048b-6b07-408d-a125-634818bc95ee','惜花三首 三','張碧','唐','唐诗','tang','','[]','朝開暮落煎人老，無人爲報東君道。',32,'全唐诗/poet.tang.25000.json','["朝開暮落煎人老，無人爲報東君道。", "留取穠紅伴醉吟，莫教少女來吹掃。"]'),
('e18fb650-be22-4f0e-925b-e8e0252c1d85','遊春引三首 一','張碧','唐','唐诗','tang','','[]','句芒愛弄春風權，開萌發翠無黨偏。',32,'全唐诗/poet.tang.25000.json','["句芒愛弄春風權，開萌發翠無黨偏。", "句芒小女精神巧，機羅杼綺滿平川。"]'),
('8b006226-237f-4f13-b01f-5f8cee04c2bb','遊春引三首 二','張碧','唐','唐诗','tang','','[]','五陵年少輕薄客，蠻錦花多春袖窄。',32,'全唐诗/poet.tang.25000.json','["五陵年少輕薄客，蠻錦花多春袖窄。", "酌桂鳴金翫物華，星蹄繡轂填香陌。"]'),
('a11ed140-dae9-4923-828a-1379113fd0e1','遊春引三首 三','張碧','唐','唐诗','tang','','[]','千條碧綠輕拖水，金毛泣怕春江死。',32,'全唐诗/poet.tang.25000.json','["千條碧綠輕拖水，金毛泣怕春江死。", "萬彙俱含造化恩，見我春工無私理。"]'),
('0c8565cc-bd2e-4b5a-87e3-00119062da17','農父','張碧','唐','唐诗','tang','','[]','運鋤耕斸侵星起，隴畝豐盈滿家喜。',32,'全唐诗/poet.tang.25000.json','["運鋤耕斸侵星起，隴畝豐盈滿家喜。", "到頭禾黍屬他人，不知何處抛妻子。"]'),
('ec20615e-d3da-4109-b0f3-f754488e7b42','古意','張碧','唐','唐诗','tang','','[]','鑾輿不碾香塵滅，更殘三十六宮月。',32,'全唐诗/poet.tang.25000.json','["鑾輿不碾香塵滅，更殘三十六宮月。", "手持紈扇獨含情，秋風吹落橫波血。"]'),
('efad3f8b-87d3-406e-a916-fc8fb2bdf381','秋日登岳陽樓晴望','張碧','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','三秋倚練飛金盞，洞庭波定平如剗。',96,'全唐诗/poet.tang.25000.json','["三秋倚練飛金盞，洞庭波定平如剗。", "天高雲卷綠羅低，一點君山礙人眼。", "漫漫萬頃鋪琉璃，煙波闊遠無鳥飛。", "西南東北競無際，直疑侵斷青天涯。", "屈原回日牽愁吟，龍宮感激致應沈。", "賈生憔悴說不得，茫茫煙靄堆湖心。"]'),
('bb869dca-e445-493b-a97b-1031cdb5f49b','鴻溝','張碧','唐','唐诗','tang','','[]','毒龍銜日天地昏，八紘靉靆生愁雲。',272,'全唐诗/poet.tang.25000.json','["毒龍銜日天地昏，八紘靉靆生愁雲。", "秦園走鹿無藏處，紛紛爭處蜂成羣。", "四溟波立鯨相吞，蕩搖五岳崩山根。", "魚蝦舞浪狂鰍鯤，龍蛇膽戰登鴻門。", "星旗羽鏃強者尊，黑風白雨東西屯。", "山河欲拆人煙分，壯士鼓勇君王存。", "項莊憤氣吐不得，亞父斗聲天上聞。", "玉光墮地驚崑崙，留侯氣魄吞太華。", "舌頭一寸生陽春，神農女媧愁不言。", "蛇枯老媼啼淚痕，星曹定秤秤王孫。", "項籍骨輕迷精魂，沛公仰面爭乾坤。", "須臾垓下賊星起，歌聲繚繞悽人耳。", "吳娃捧酒橫秋波，霜天月照空城壘。", "力拔山兮忽到此，騅嘶懶渡烏江水。", "新豐瑞色生樓臺，西楚寒蒿哭愁鬼。", "三尺霜鳴金匣裏，神光一掉八千里。", "漢皇驟馬意氣生，西南掃地迎天子。"]'),
('e66e7b43-a267-43d2-a201-49c17bcddcf9','美人梳頭','張碧','唐','唐诗','tang','','[]','玉堂花院小枝紅，綠窗一片春光曉。',112,'全唐诗/poet.tang.25000.json','["玉堂花院小枝紅，綠窗一片春光曉。", "玉容驚覺濃睡醒，圓蟾挂出妝臺表。", "金盤解下叢鬟碎，三尺巫雲綰朝翠。", "皓指高低寸黛愁，水精梳滑參差墜。", "須臾攏掠蟬鬢生，玉釵冷透冬冰明。", "芙蓉拆向新開臉，秋泉慢轉眸波橫。", "鸚鵡偷來話心曲，屏風半倚遙山綠。"]'),
('9ff7a464-23c9-406b-b0ee-8c59bc0f3183','題祖山人池上怪石','張碧','唐','唐诗','tang','','[]','寒姿數片奇突兀，曾作秋江秋水骨。',100,'全唐诗/poet.tang.25000.json','["寒姿數片奇突兀，曾作秋江秋水骨。", "先生應是厭風雲，著向江邊塞龍窟。", "我來池上傾酒尊，半酣書破青煙痕。", "參差翠縷擺不落，筆頭驚怪黏秋雲。", "我聞吳中項容水墨有高價，邀得將來倚松下。", "鋪却雙繒直道難，掉首空歸不成畫。"]'),
('fd50445d-5cb4-40c4-b2b4-c24f1b205aa2','山居雨霽即事','張碧','唐','唐诗','tang','','[]','結茅蒼嶺下，自與喧卑隔。',144,'全唐诗/poet.tang.25000.json','["結茅蒼嶺下，自與喧卑隔。", "況值雷雨晴，郊原轉岑寂。", "出門看反照，繞屋殘溜滴。", "古路絕人行，荒陂響螻蟈。", "籬崩瓜豆蔓，圃壞牛羊跡。", "斷續古祠鴉，高低遠村笛。", "喜聞東臯潤，欲往未通屐。", "杖策試危橋，攀蘿瞰苔壁。", "鄰翁夜相訪，緩酌聊跂石。", "新月出汙尊，浮雲在巾舃。", "常隳腐儒操，謬習經邦畫。", "有待時未知，非關慕沮溺。"]'),
('b580a2e7-ef9a-4853-b003-445e9f52a792','贈琴棋僧歌','張瀛','唐','唐诗','tang','','[]','我嘗聽師法一說，波上蓮花水中月。',148,'全唐诗/poet.tang.25000.json','["我嘗聽師法一說，波上蓮花水中月。", "不垢不淨是色空，無法無空亦無滅。", "我嘗聽師禪一觀，浪溢鰲頭蟾魄滿。", "河沙世界盡空空，一寸寒灰冷燈畔。", "我又聽師琴一撫，長松喚住秋山雨。", "弦中雅弄若鏗金，指下寒泉流太古。", "我又聽師棋一著，山頂坐沈紅日腳。", "阿誰稱是國手人，羅浮道士賭却鶴。", "輸却藥，法懷斟下紅霞丹，束手不敢爭頭角。"]'),
('fda12646-31b5-4d99-ad4d-e046a6d265cc','妾換馬','盧殷','唐','唐诗','tang','','[]','伴鳳樓中妾，如龍櫪上宛。',48,'全唐诗/poet.tang.25000.json','["伴鳳樓中妾，如龍櫪上宛。", "同年辭舊寵，異地受新恩。", "香閣更衣處，塵蒙噴草痕。", "連嘶將忍淚，俱戀主人門。"]'),
('3f4e80c2-593c-4273-aff7-4fe977f6dcf4','七夕','盧殷','唐','唐诗','tang','','[]','河耿月涼時，牽牛織女期。',48,'全唐诗/poet.tang.25000.json','["河耿月涼時，牽牛織女期。", "歡娛方在此，漏刻竟由誰。", "定不嫌秋駛，唯當乞夜遲。", "全勝客子媍，十載泣生離。"]'),
('3a8d206c-0bb0-4e9f-acb9-a7a447fc6c31','月夜','盧殷','唐','唐诗','tang','','[]','露下涼生簟，無人月滿庭。',48,'全唐诗/poet.tang.25000.json','["露下涼生簟，無人月滿庭。", "難聞逆河浪，徒望白榆星。", "樹遶孤棲鵲，窗飛就暗螢。", "移時宿蘭影，思共習芳馨。"]'),
('b55a8cfb-2b3e-4948-85ec-d6473d853a63','仲夏寄江南','盧殷','唐','唐诗','tang','','[]','五月行將近，三年客未迴。',48,'全唐诗/poet.tang.25000.json','["五月行將近，三年客未迴。", "夢成千里去，酒醒百憂來。", "晚暮時看槿，悲酸不食梅。", "空將白團扇，從寄復裴回。"]'),
('c345b92f-9b61-4434-b082-6f2a9449108e','欲銷雲','盧殷','唐','唐诗','tang','','[]','欲隱從龍質，仍餘觸石文。',48,'全唐诗/poet.tang.25000.json','["欲隱從龍質，仍餘觸石文。", "霏微依碧落，髣髴悞非雲。", "度月光無隔，傾河影不分。", "如逢作霖處，當爲起氤氳。"]'),
('fa7f2085-67ca-4b38-b9ec-7153f430559d','遇邊使','盧殷','唐','唐诗','tang','','[]','累年無的信，每夜夢邊城。',24,'全唐诗/poet.tang.25000.json','["累年無的信，每夜夢邊城。", "袖掩千行淚，書封一尺情。"]'),
('18c7dd89-9d35-4399-9859-8ec8e1d34aef','移住別居','盧殷','唐','唐诗','tang','','[]','自到西川住，唯君別有情。',24,'全唐诗/poet.tang.25000.json','["自到西川住，唯君別有情。", "常逢對門遠，又隔一重城。"]'),
('692fe24d-082f-4305-a4de-adfee955322b','堋口逢友人','盧殷','唐','唐诗','tang','','[]','艱難別離久，中外往還深。',24,'全唐诗/poet.tang.25000.json','["艱難別離久，中外往還深。", "已改當時法，空餘舊日心。"]'),
('9cca0a6d-cc6b-4465-846b-5e3b4ff39470','雨霽登北岸寄友人','盧殷','唐','唐诗','tang','','[]','稻黃撲撲黍油油，野樹連山澗自流。',32,'全唐诗/poet.tang.25000.json','["稻黃撲撲黍油油，野樹連山澗自流。", "憶得年時馮翊部，謝郎相引上樓頭。"]'),
('a7b6f371-3af0-4ee9-aaab-8c42e1bc9f9b','長安親故','盧殷','唐','唐诗','tang','','[]','楚蘭不佩佩吳鉤，帶酒城頭別舊遊。',32,'全唐诗/poet.tang.25000.json','["楚蘭不佩佩吳鉤，帶酒城頭別舊遊。", "年事已多筋力在，試將弓箭到幷州。"]'),
('b57f5d4c-ed74-4a50-b93b-8bda505ca726','悲秋','盧殷','唐','唐诗','tang','','[]','秋空雁度青天遠，疎樹蟬嘶白露寒。',32,'全唐诗/poet.tang.25000.json','["秋空雁度青天遠，疎樹蟬嘶白露寒。", "階下敗蘭猶有氣，手中團扇漸無端。"]'),
('31e24eb7-cdb4-4e50-823a-e1dd7e00423a','晚蟬','盧殷','唐','唐诗','tang','','[]','深藏高柳背斜暉，能軫孤愁減昔圍。',32,'全唐诗/poet.tang.25000.json','["深藏高柳背斜暉，能軫孤愁減昔圍。", "猶畏旅人頭不白，再三移樹帶聲飛。"]'),
('91b73970-1dbf-43e8-9162-4c503882e241','維揚郡西亭贈友人','盧殷','唐','唐诗','tang','','[]','萍颯風池香滿船，楊花漠漠暮春天。',32,'全唐诗/poet.tang.25000.json','["萍颯風池香滿船，楊花漠漠暮春天。", "玉人此日心中事，何似乘羊入市年。"]'),
('ec5c013d-fda1-4825-bba0-90b06cfcfd7b','終南精舍月中聞磬','獨孤申叔','唐','唐诗','tang','','[]','精廬殘夜景，天宇滅埃氛。',72,'全唐诗/poet.tang.25000.json','["精廬殘夜景，天宇滅埃氛。", "幽磬此時擊，餘音幾處聞。", "隨風樹杪去，支策月中分。", "斷絕如殘漏，淒清不隔雲。", "羇人方罷夢，獨鴈忽迷羣。", "響盡河漢落，千山空糾紛。"]'),
('46bf764a-2ccb-479c-991b-e83fc8966b16','題漢州西湖','嚴公弼','唐','唐诗','tang','','["\u897f\u6e56"]','西湖創置自房公，心匠縱橫造化同。',32,'全唐诗/poet.tang.25000.json','["西湖創置自房公，心匠縱橫造化同。", "見說鳳池推獨步，高名何事滯川中。"]'),
('632dc421-6fac-46f6-9e92-590d5adfb994','題漢州西湖','嚴公貺','唐','唐诗','tang','','["\u897f\u6e56"]','鳳沼才難盡，餘思鑿西湖。',48,'全唐诗/poet.tang.25000.json','["鳳沼才難盡，餘思鑿西湖。", "珍木羅修岸，冰光映坐隅。", "琴臺今寂寞，竹島尚縈紆。", "猶蘊濟川志，芳名終不渝。"]'),
('9cb64625-be19-4118-bc44-bafaf721b140','湘弦曲','莊南傑','唐','唐诗','tang','','["\u957f\u6c5f"]','楚雲錚錚戛秋露，巫雲峽雨飛朝暮。',96,'全唐诗/poet.tang.25000.json','["楚雲錚錚戛秋露，巫雲峽雨飛朝暮。", "古磬高敲百尺樓，孤猨夜哭千丈樹。", "雲軒碾火聲瓏瓏，連山卷盡長江空。", "鶯啼寂寞花枝雨，鬼嘯荒郊松柏風。", "滿堂怨咽悲相續，苦調中含古離曲。", "繁弦響絕楚魂遙，湘江水碧湘山綠。"]'),
('8a307890-59f1-4f39-a01d-75d5fca72b77','黃雀行','莊南傑','唐','唐诗','tang','','[]','穿屋穿牆不知止，爭樹爭巢入營死。',64,'全唐诗/poet.tang.25000.json','["穿屋穿牆不知止，爭樹爭巢入營死。", "林間公子夾彈弓，一丸致斃花叢裏。", "小口黃雛未有知，青天不解高高飛。", "虞人設網當要路，白日啾嘲禍萬機。"]'),
('764d0ce9-8a0c-4770-b26e-0edc9a54a6b9','雁門太守行','莊南傑','唐','唐诗','tang','','[]','旌旗閃閃搖天末，長笛橫吹虜塵闊。',64,'全唐诗/poet.tang.25000.json','["旌旗閃閃搖天末，長笛橫吹虜塵闊。", "跨下嘶風白練獰，腰間切玉青蛇活。", "擊革摐金燧牛尾，犬羊兵敗如山死。", "九泉寂寞葬秋蟲，濕雲荒草啼秋思。"]'),
('541a9825-1c3c-4d42-a5d7-f1e11b3fac7a','陽春曲','莊南傑','唐','唐诗','tang','','[]','紫錦紅囊香滿風，金鸞玉軾搖丁冬。',64,'全唐诗/poet.tang.25000.json','["紫錦紅囊香滿風，金鸞玉軾搖丁冬。", "沙鷗白羽翦晴碧，野桃紅豔燒春空。", "芳草緜延鏁平地，壠蝶雙雙舞幽翠。", "鳳葉龍吟白日長，落花聲底仙娥醉。"]'),
('14c0cb93-023b-49e7-8227-055140ea43b9','傷歌行','莊南傑','唐','唐诗','tang','','[]','兔走烏飛不相見，人事依稀速如電。',96,'全唐诗/poet.tang.25000.json','["兔走烏飛不相見，人事依稀速如電。", "王母夭桃一度開，玉樓紅粉千回變。", "車馳馬走咸陽道，石家舊宅空荒草。", "秋雨無情不惜花，芙蓉一一驚香倒。", "勸君莫謾栽荆棘，秦皇虛費驅山力。", "英風一去更無言，白骨沈埋暮山碧。"]'),
('5c808a5d-d8c5-4280-bb32-9efd90c3f831','無題','李溟','唐','唐诗','tang','','[]','喬木挂斗邑，水驛壞門開。',48,'全唐诗/poet.tang.25000.json','["喬木挂斗邑，水驛壞門開。", "向月片帆去，背雲行雁來。", "晚年名利跡，寧免路岐哀。", "前計不能息，若爲玄鬢迴。"]'),
('7be8bb2b-1e40-4e51-8632-98e33d27f5e5','客舍喜友人相訪','賀蘭朋吉','唐','唐诗','tang','','[]','荒居無四隣，誰肯訪來頻。',48,'全唐诗/poet.tang.25000.json','["荒居無四隣，誰肯訪來頻。", "古樹秋中葉，他鄉病裏身。", "鴈聲風送急，螢影月流新。", "獨爲成名晚，多慙見友人。"]'),
('4ff4f244-0714-4046-8b5f-069cf67d1b5a','詣李侍郎','王魯復','唐','唐诗','tang','','[]','文字元無底，功夫轉到難。',24,'全唐诗/poet.tang.25000.json','["文字元無底，功夫轉到難。", "苦心三百首，暫請侍郎看。"]'),
('bd157d95-20f8-4e64-b2df-bda96308e128','弔靈均','王魯復','唐','唐诗','tang','','[]','萬古汨羅深，騷人道不沈。',24,'全唐诗/poet.tang.25000.json','["萬古汨羅深，騷人道不沈。", "明明唐日月，應見楚臣心。"]'),
('d0375e10-11a5-4d5d-9644-98de60f215f6','弔韓侍郎','王魯復','唐','唐诗','tang','','[]','星落少微宮，高人入古風。',24,'全唐诗/poet.tang.25000.json','["星落少微宮，高人入古風。", "幾年才子淚，併寫五言中。"]'),
('bdd3fd1e-2b3c-4f55-af83-8af3b2b0e662','故白巖禪師院','王魯復','唐','唐诗','tang','','[]','能師還世名還在，空閉禪堂滿院苔。',32,'全唐诗/poet.tang.25000.json','["能師還世名還在，空閉禪堂滿院苔。", "花樹不隨人寂寞，數枝猶自出牆來。"]'),
('658a51ea-a071-4fdb-b6f2-1d356b199e44','招玉川子詠新文','徐希仁','唐','唐诗','tang','','[]','清氣宿我心，結爲清泠音。',24,'全唐诗/poet.tang.25000.json','["清氣宿我心，結爲清泠音。", "一夜吟不足，君來相和吟。"]'),
('65d27677-f275-4f9b-9eb8-d717fb1fc98c','五雜組','雍裕之','唐','唐诗','tang','','[]','五雜組，刺繡窠。',24,'全唐诗/poet.tang.25000.json','["五雜組，刺繡窠。", "往復還，織錦梭。", "不得已，戍交河。"]'),
('5f0e0450-dc67-42b1-b59d-718213cee4b4','剪綵花','雍裕之','唐','唐诗','tang','','[]','敢競桃李色，自呈刀尺功。',24,'全唐诗/poet.tang.25000.json','["敢競桃李色，自呈刀尺功。", "蝶猶迷剪翠，人豈辨裁紅。"]'),
('0fe7c75d-41bb-461c-984c-bbcbd4756045','春晦送客','雍裕之','唐','唐诗','tang','','[]','野酌亂無巡，送君兼送春。',24,'全唐诗/poet.tang.25000.json','["野酌亂無巡，送君兼送春。", "明年春色至，莫作未歸人。"]'),
('ec20bca9-81ab-429f-b0e2-07c8f349d735','自君之出矣','雍裕之','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e50\u5e9c"]','自君之出矣，寶鏡爲誰明。',24,'全唐诗/poet.tang.25000.json','["自君之出矣，寶鏡爲誰明。", "思君如隴水，長聞嗚咽聲。"]'),
('c473b868-563b-4842-912e-5330ba6118ee','自君之出矣','徐幹','唐','唐诗','tang','','[]','自君之出矣，明鏡暗不治。',24,'全唐诗/poet.tang.25000.json','["自君之出矣，明鏡暗不治。", "思君如流水，無有窮已時。"]'),
