('fad618fa-7d73-4df3-ab70-59a4534c5c57','姑熟雜詠 姑熟溪','李赤','唐','唐诗','tang','','[]','愛此溪水閑，乘流興無極。',48,'全唐诗/poet.tang.25000.json','["愛此溪水閑，乘流興無極。", "擊檝怕鷗驚，垂竿待魚食。", "波翻曉霞影，岸疊春山色。", "何處浣紗人，紅顏未相識。"]'),
('1b2fa983-01ec-4aed-a9f3-3a50bc295323','姑熟雜詠 丹陽湖','李赤','唐','唐诗','tang','','[]','湖與元氣通，風波浩難止。',48,'全唐诗/poet.tang.25000.json','["湖與元氣通，風波浩難止。", "天外賈客歸，雲間片帆起。", "龜游蓮葉上，鳥宿蘆花裏。", "少女棹舟歸，歌聲逐流水。"]'),
('44f39a71-1f3b-4772-bbf0-77963dc0e35f','姑熟雜詠 謝公宅','李赤','唐','唐诗','tang','','[]','青山日將暝，寂寞謝公宅。',48,'全唐诗/poet.tang.25000.json','["青山日將暝，寂寞謝公宅。", "竹裏無人聲，池中虛月白。", "荒庭衰草徧，廢井蒼苔積。", "唯有清風聞，時時起泉石。"]'),
('400b2396-b7f7-42b3-bed8-5e9cbf1a7a0d','姑熟雜詠 凌[歊]臺','李赤','唐','唐诗','tang','','[]','曠望登古臺，臺高極人目。',48,'全唐诗/poet.tang.25000.json','["曠望登古臺，臺高極人目。", "疊嶂列遠空，閑花雜平陸。", "白雲入窗牖，野翠生松竹。", "欲覽碑上文，苔侵豈堪讀。"]'),
('f0c91cfd-11a0-4e1f-9e52-66ee7c47d259','姑熟雜詠 桓公井','李赤','唐','唐诗','tang','','[]','桓公名已古，廢井曾未竭。',48,'全唐诗/poet.tang.25000.json','["桓公名已古，廢井曾未竭。", "石甃冷蒼苔，寒泉湛孤月。", "秋來桐暫落，春至桃還發。", "路遠人罕窺，誰能見清澈。"]'),
('ce3d2a74-0d46-41ac-9d58-ad95c18e0da4','姑熟雜詠 慈姥竹','李赤','唐','唐诗','tang','','[]','野竹攢石生，含煙映江島。',48,'全唐诗/poet.tang.25000.json','["野竹攢石生，含煙映江島。", "翠色落波深，虛聲帶寒早。", "龍吟曾未聽，鳳曲吹應好。", "不學蒲柳凋，貞心常自保。"]'),
('ed347645-de13-496a-9078-cea6912d3c1c','姑熟雜詠 望夫山','李赤','唐','唐诗','tang','','[]','顒望臨碧空，怨情感離別。',48,'全唐诗/poet.tang.25000.json','["顒望臨碧空，怨情感離別。", "芳草不知愁，巖花但爭發。", "雲山萬重隔，音信千里絕。", "春去秋復來，相思幾時歇。"]'),
('7e4e03c2-33b9-4cdd-8c8c-a5a7ec0d10e8','姑熟雜詠 牛渚磯','李赤','唐','唐诗','tang','','[]','絕壁臨巨川，連峰勢相向。',48,'全唐诗/poet.tang.25000.json','["絕壁臨巨川，連峰勢相向。", "亂石流洑間，迴波自成浪。", "但驚羣木秀，莫測精靈狀。", "更聽猨夜啼，憂心醉江上。"]'),
('d05392d8-6055-4a73-8f26-21182eb38768','姑熟雜詠 靈墟山','李赤','唐','唐诗','tang','','[]','丁令辭世人，拂衣向仙路。',48,'全唐诗/poet.tang.25000.json','["丁令辭世人，拂衣向仙路。", "伏鍊九丹成，方隨五雲去。", "松蘿蔽幽洞，桃杏深隱處。", "不知曾化鶴，遼海歸幾度。"]'),
('765fdf4b-1622-4468-a1d7-809dff28a441','姑熟雜詠 天門山','李赤','唐','唐诗','tang','','["\u5929\u95e8\u5c71"]','迥出江水上，雙峰自相對。',48,'全唐诗/poet.tang.25000.json','["迥出江水上，雙峰自相對。", "岸映松色寒，石分浪花碎。", "參差遠天際，縹緲晴霞外。", "落日舟去遙，回首沈青靄。"]'),
('670a79ca-fcc1-46a5-b5d5-f23d05fe5e64','勅贈康尚書美人','薛𦀒','唐','唐诗','tang','','[]','天門喜氣曉氛氳，聖主臨軒召冠軍。',32,'全唐诗/poet.tang.25000.json','["天門喜氣曉氛氳，聖主臨軒召冠軍。", "欲令從此行霖雨，先賜巫山一片雲。"]'),
('27cfd8f3-dc04-4569-9a92-3539b04cf58a','將赴東都上李相國','孫叔向','唐','唐诗','tang','','[]','四海兵初偃，平津閣正開。',24,'全唐诗/poet.tang.25000.json','["四海兵初偃，平津閣正開。", "誰知大爐火，還有不然灰。"]'),
('9d9d715f-464e-4976-83ae-e95220d1417a','題昭應溫泉','孫叔向','唐','唐诗','tang','','[]','一道溫泉遶御樓，先皇曾向此中游。',32,'全唐诗/poet.tang.25000.json','["一道溫泉遶御樓，先皇曾向此中游。", "雖然水是無情物，也到宮前咽不流。"]'),
('4f3fd12d-8dd2-41b7-a5ef-62aa300a3bbe','送咸安公主','孫叔向','唐','唐诗','tang','','[]','鹵簿遲遲出國門，漢家公主嫁烏孫。',32,'全唐诗/poet.tang.25000.json','["鹵簿遲遲出國門，漢家公主嫁烏孫。", "玉顏便向穹廬去，衛霍空承明主恩。"]'),
('03d2d673-c147-4a37-a717-fbe578d229bf','邊城柳','劉皂','唐','唐诗','tang','','[]','一株新柳色，十里斷孤城。',24,'全唐诗/poet.tang.25000.json','["一株新柳色，十里斷孤城。", "爲近東西路，長懸離別情。"]'),
('20696ee7-637c-42bc-8dce-ef4a1dd67b37','長門怨三首 一','劉皂','唐','唐诗','tang','','[]','雨滴長門秋夜長，愁心和雨到昭陽。',32,'全唐诗/poet.tang.25000.json','["雨滴長門秋夜長，愁心和雨到昭陽。", "淚痕不學君恩斷，拭却千行更萬行。"]'),
('d995cd69-6e1a-4f0d-bc9d-bbbedc747d33','長門怨三首 二','劉皂','唐','唐诗','tang','','[]','宮殿沈沈月欲分，昭陽更漏不堪聞。',32,'全唐诗/poet.tang.25000.json','["宮殿沈沈月欲分，昭陽更漏不堪聞。", "珊瑚枕上千行淚，不是思君是恨君。"]'),
('14025f1e-c4e6-4a70-b0c7-0f5c46720449','長門怨三首 三','劉皂','唐','唐诗','tang','','[]','蟬鬢慵梳倚帳門，蛾眉不掃慣承恩。',32,'全唐诗/poet.tang.25000.json','["蟬鬢慵梳倚帳門，蛾眉不掃慣承恩。", "旁人未必知心事，一面殘妝空淚痕。"]'),
('3a9d922c-4204-4708-8664-7618495553be','旅次朔方','劉皂','唐','唐诗','tang','','["\u601d\u4e61"]','客舍幷州數十霜，歸心日夜憶咸陽。',32,'全唐诗/poet.tang.25000.json','["客舍幷州數十霜，歸心日夜憶咸陽。", "無端又渡桑乾水，却望幷州似故鄉。"]'),
('af5c74a2-84a3-4dac-9e4c-c86065f395a2','早起','楊厚','唐','唐诗','tang','','[]','星漢轉寒更，伊余索寞情。',48,'全唐诗/poet.tang.25000.json','["星漢轉寒更，伊余索寞情。", "鐘催歸夢斷，雁引遠愁生。", "危壁蘭光暗，疎簾露氣清。", "閑庭聊一望，海日爲分明。"]'),
('49a7bc67-c231-4821-908b-d6c0e81007d4','長門怨','裴交泰','唐','唐诗','tang','','[]','自閉長門經幾秋，羅衣濕盡淚還流。',32,'全唐诗/poet.tang.25000.json','["自閉長門經幾秋，羅衣濕盡淚還流。", "一種蛾眉明月夜，南宮歌管北宮愁。"]'),
('10a6e2d0-d3e7-4335-aed4-72f88593b741','禁中送任山人','李祕','唐','唐诗','tang','','[]','子去非長往，君恩取大還。',48,'全唐诗/poet.tang.25000.json','["子去非長往，君恩取大還。", "補天留彩石，縮地入青山。", "獻壽千春外，來朝數月間。", "莫拋殘藥物，竊取駐童顏。"]'),
('14d0922f-6240-4a11-8e01-adeec4928421','府試中元觀道流步虛','殷堯恭','唐','唐诗','tang','','[]','玄都開秘籙，白石禮先生。',72,'全唐诗/poet.tang.25000.json','["玄都開秘籙，白石禮先生。", "上界秋光靜，中元夜景清。", "星辰朝帝處，鸞鶴步虛聲。", "玉洞花長發，珠宮月最明。", "掃壇天地肅，投簡鬼神驚。", "儻賜刀圭藥，還成不死名。"]'),
('36a25bff-3b02-442b-bb20-aee0cbac4d2a','王仙壇','林傑','唐','唐诗','tang','','[]','羽客已登仙路去，丹鑪草木盡凋殘。',32,'全唐诗/poet.tang.25000.json','["羽客已登仙路去，丹鑪草木盡凋殘。", "不知千載歸何日，空使時人掃舊壇。"]'),
('ed4fb444-ae63-4764-8acd-dabf1e82fe23','乞巧','林傑','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282", "\u4e09\u5e74\u7ea7\u4e0b\u518c", "\u5c0f\u5b66\u53e4\u8bd7"]','七夕今宵看碧霄，牽牛織女渡河橋。',32,'全唐诗/poet.tang.25000.json','["七夕今宵看碧霄，牽牛織女渡河橋。", "家家乞巧望秋月，穿盡紅絲幾萬條。"]'),
('903bd047-49ab-401d-a07f-4c62095f3dca','句','林傑','唐','唐诗','tang','','[]','金盤摘下挂朱顆，紅殼開時飲玉漿。',16,'全唐诗/poet.tang.25000.json','["金盤摘下挂朱顆，紅殼開時飲玉漿。"]'),
('2ae0c1a8-700c-4f7d-a8a3-d6b3615f3dd7','哭林傑','鄭立之','唐','唐诗','tang','','[]','才高未及賈生年，何事孤魂逐逝川。',32,'全唐诗/poet.tang.25000.json','["才高未及賈生年，何事孤魂逐逝川。", "螢聚帳中人已去，鶴離臺上月空圓。"]'),
('603011ce-f76d-48f8-84b5-da89d641b408','詠和親','蘇郁','唐','唐诗','tang','','[]','關月夜懸青冢鏡，寒雲秋薄漢宮羅。',32,'全唐诗/poet.tang.25000.json','["關月夜懸青冢鏡，寒雲秋薄漢宮羅。", "君王莫信和親策，生得胡雛虜更多。"]'),
('f51a5fb3-9e4c-483f-a4a3-502c02cda6b5','鸚鵡詞','蘇郁','唐','唐诗','tang','','[]','莫把金籠閉鸚鵡，箇箇分明解人語。',32,'全唐诗/poet.tang.25000.json','["莫把金籠閉鸚鵡，箇箇分明解人語。", "忽然更向君前言，三十六宮愁幾許。"]'),
('0bbd87b4-c9f0-4434-aca4-25b1a0ea5fb6','步虛詞','蘇郁','唐','唐诗','tang','','[]','十二樓藏玉堞中，鳳凰雙宿碧芙蓉。',32,'全唐诗/poet.tang.25000.json','["十二樓藏玉堞中，鳳凰雙宿碧芙蓉。", "流霞淺酌誰同醉，今夜笙歌第幾重。"]'),
('fe67e7a5-7f23-4293-adf1-d7fb1c8b7a64','句','蘇郁','唐','唐诗','tang','','[]','吟倚雨殘樹，月收山下村。',12,'全唐诗/poet.tang.25000.json','["吟倚雨殘樹，月收山下村。"]'),
('1642ad20-a4da-43e3-884e-bf41e837f10d','賦得琢玉成器','浩虛舟','唐','唐诗','tang','','[]','已沐識堅貞，應憐器未成。',72,'全唐诗/poet.tang.25000.json','["已沐識堅貞，應憐器未成。", "輝山方可重，散璞乍堪驚。", "玷滅隨心正，瑕消奪眼明。", "琢磨虹氣在，拂拭水容生。", "賞翫冰光冷，提攜月魄輕。", "佇當親捧握，瑚璉幸齊名。"]'),
('7323d9ca-ba59-47f3-bceb-b47a0278e872','責商山四皓','蔡京','唐','唐诗','tang','','[]','秦末家家思逐鹿，商山四皓獨忘機。',32,'全唐诗/poet.tang.25000.json','["秦末家家思逐鹿，商山四皓獨忘機。", "如何鬢髮霜相似，更出深山定是非。"]'),
('ab1856cf-c7d6-4e06-bdd0-488281bf93ab','假節邕交道由吳溪','蔡京','唐','唐诗','tang','','[]','停橈橫水中，舉目孤煙外。',24,'全唐诗/poet.tang.25000.json','["停橈橫水中，舉目孤煙外。", "借問吳溪人，誰家有山賣。"]'),
('d84bafce-1546-4d65-be8d-e3528e5cc367','詠子規','蔡京','唐','唐诗','tang','','[]','千年冤魄化爲禽，永逐悲風叫遠林。',64,'全唐诗/poet.tang.25000.json','["千年冤魄化爲禽，永逐悲風叫遠林。", "愁血滴花春豔死，月明飄浪冷光沈。", "凝成紫塞風前淚，驚破紅樓夢裏心。", "腸斷楚詞歸不得，劒門迢遰蜀江深。"]'),
('e3bb0eb8-5bf2-4489-9edf-1ff56178c787','獻蔡京','張頂','唐','唐诗','tang','','[]','拋却長竿卷却絲，手持蓑笠獻新詩。',32,'全唐诗/poet.tang.25000.json','["拋却長竿卷却絲，手持蓑笠獻新詩。", "臨川太守清如鏡，不是漁人下釣時。"]'),
('687d3659-19ca-4e01-b6a6-a92a9d01b076','享惠昭太子廟樂章','李逢吉','唐','唐诗','tang','','[]','既潔酒醴，聿陳熟腥。',40,'全唐诗/poet.tang.25000.json','["既潔酒醴，聿陳熟腥。", "肅將震念，昭格儲靈。", "展矣禮典，薰然德馨。", "愔愔管磬，亦具是聽。"]'),
('1dd5eb30-e884-4c6b-ae9d-fc0cc866d226','望京樓上寄令狐華州','李逢吉','唐','唐诗','tang','','[]','祗役滯南服，頹思屬暮年。',84,'全唐诗/poet.tang.25000.json','["祗役滯南服，頹思屬暮年。", "閑上望京臺，萬山蔽其前。", "落日歸飛翼，連翩東北天。", "涪江適在下，爲我久潺湲。", "中葉成文教，德威清遠邊。", "頒條信徒爾，華髮生蒼然。", "寄懷三峰守，岐路隔雲煙。"]'),
('8e6cf897-36ad-477a-9cc9-d1c9cde971c7','再赴襄陽辱宣武相公貽詩今用奉酬','李逢吉','唐','唐诗','tang','','[]','解韍辭丹禁，揚旌去赤墀。',72,'全唐诗/poet.tang.25000.json','["解韍辭丹禁，揚旌去赤墀。", "自驚非素望，何力及清時。", "又據三公席，多慙四老祠。", "峴山風已遠，棠樹事難追。", "江漢饒春色，荆蠻足夢思。", "唯憐吐鳳句，相示鑿龍期。"]'),
('5d8cd4e1-2227-47f3-ae49-2c567d0c6033','奉送李相公重鎮襄陽','李逢吉','唐','唐诗','tang','','[]','海內埏埴徧，漢陰旌斾還。',72,'全唐诗/poet.tang.25000.json','["海內埏埴徧，漢陰旌斾還。", "望留丹闕下，恩在紫霄間。", "冰雪背秦嶺，風煙經武關。", "樹皆人尚愛，轅即吏曾攀。", "自惜兩心合，相看雙鬢斑。", "終期謝戎務，同隱鑿龍山。"]'),
('3b54bcc9-2aa7-43ec-8d3c-2e29138e5a3a','和嚴揆省中宿齋遇令狐員外當直之作','李逢吉','唐','唐诗','tang','','[]','致齋分直宿南宮，越石盧諶此夜同。',64,'全唐诗/poet.tang.25000.json','["致齋分直宿南宮，越石盧諶此夜同。", "位極班行猶念舊，名題章奏亦從公。", "曾驅爪士三邊靜，新贈髯參六義窮。", "竟夕文昌知有月，可憐如在庾樓中。"]'),
('a3c0838e-bd8c-4b12-9669-3d27ee29a4ac','奉酬忠武李相公見寄','李逢吉','唐','唐诗','tang','','[]','直繼先朝衛與英，能移孝友作忠貞。',64,'全唐诗/poet.tang.25000.json','["直繼先朝衛與英，能移孝友作忠貞。", "劒門失險曾縛虎，淮水安流緣斬鯨。", "黃閣碧幢惟是儉，三公二伯未爲榮。", "惠連忽贈池塘句，又遣羸師破膽驚。"]'),
('3fc948e9-b51c-4816-a914-d5fea60403e4','酬致政楊祭酒見寄','李逢吉','唐','唐诗','tang','','[]','初還相印罷戎旃，獲守皇居在紫煙。',64,'全唐诗/poet.tang.25000.json','["初還相印罷戎旃，獲守皇居在紫煙。", "妄比酇侯功蔑爾，每懷疏傅意悠然。", "應將半俸霑閭里，料入中條訪洞天。", "十載別離那可道，倍令驚喜見來篇。"]'),
('7472bede-ec71-48cf-9b45-26ca7ec65ac1','送令狐秀才赴舉','李逢吉','唐','唐诗','tang','','[]','子有雄文藻思繁，齠年射策向金門。',64,'全唐诗/poet.tang.25000.json','["子有雄文藻思繁，齠年射策向金門。", "前隨鸞鶴登霄漢，却望風沙走塞垣。", "獨憶忘機陪出處，自憐何力繼飛翻。", "那堪兩地生離緒，蓬戶長扃行旅喧。"]'),
('d8eb0b45-88ed-475c-afc8-5a7cb868a116','郡齋臥疾贈晝上人','于頔','唐','唐诗','tang','','[]','夙陪翰墨徒，深論窮文格。',240,'全唐诗/poet.tang.25000.json','["夙陪翰墨徒，深論窮文格。", "麗則風騷後，公然我詞客。", "晚依方外友，極理探精賾。", "吻合南北宗，晝公我禪伯。", "尤明性不染，故我行貞白。", "隨順令得解，故我言芳澤。", "霅水漾清潯，吳山橫碧岑。", "含珠復蘊玉，價重雙南金。", "的皪曜奇彩，淒清流雅音。", "商聲發楚調，調切譜瑤琴。", "吳山爲我高，霅水爲我深。", "萬景徒有象，孤雲本無心。", "衆木豈無聲，椅桐有清響。", "衆耳豈不聆，鍾期有真賞。", "高潔古人操，素懷夙所仰。", "覿君冰雪姿，祛我淫滯想。", "常吟柳惲詩，苕浦久相思。", "逮此遠爲郡，蘋洲芳草衰。", "逢師年臘長，值我病容羸。", "共話無生理，聊用契心期。"]'),
('549fb397-6297-4c75-bbe0-f9bace405b5d','和丘員外題湛長史舊居','于頔','唐','唐诗','tang','','[]','蕭條歷山下，水木無氛滓。',72,'全唐诗/poet.tang.25000.json','["蕭條歷山下，水木無氛滓。", "王門結長裾，巖扃怡暮齒。", "昔賢枕高躅，今彥仰知止。", "依依矚煙霞，眷眷返墟里。", "湛生久已沒，丘也亦同恥。", "立言咸不朽，何必在青史。"]'),
('b164994f-94c1-4b16-920a-0725c091bedb','寒夜聞霜鐘','盧景亮','唐','唐诗','tang','','[]','洪鐘發長夜，清響出層岑。',72,'全唐诗/poet.tang.25000.json','["洪鐘發長夜，清響出層岑。", "暗入繁霜切，遙傳古寺深。", "何城亂遠漏，幾處雜疎砧。", "已警離人夢，仍霑旅客襟。", "待時當命侶，抱器本無心。", "儻若無知者，誰能設此音。"]'),
('6bd30d03-bad0-4f27-b9fb-7212cd74d89b','南溪詩','李渤','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','玄巖麗南溪，新泉發幽色。',120,'全唐诗/poet.tang.25000.json','["玄巖麗南溪，新泉發幽色。", "巖泉孕靈秀，雲煙紛崖壁。", "斜峰信天插，奇洞固神闢。", "窈窕去未窮，環迴勢難極。", "玉池似無水，玄井昏不測。", "仙戶掩復開，乳膏凝更滴。", "丹砂有遺址，石徑無留跡。", "南眺蒼梧雲，北望洞庭客。", "蕭條風煙外，爽朗形神寂。", "若值浮丘翁，從此謝塵役。"]'),
('b795db08-a132-4d2c-9925-654193077602','喜弟淑再至爲長歌','李渤','唐','唐诗','tang','','["\u5e90\u5c71"]','前年別時秋九月，白露吹霜金吹烈。',384,'全唐诗/poet.tang.25000.json','["前年別時秋九月，白露吹霜金吹烈。", "離鴻一別影初分，淚袖雙揮心哽咽。", "別來幾度得音書，南岳知□□□□。", "廬山峨峨倚天碧，捧排空崖千萬尺。", "社牓長題高士名，食堂每記雲山跡。", "我本開雲此山住，偶爲名利相縈誤。", "自負心機四十年，羞聞社客山中篇。", "憂時魂夢憶歸路，覺來疑在林中眠。", "昨日亭前烏鵲喜，果得今朝爾來此。", "吾吟行路五十篇，盡說江南數千里。", "自憐兄弟今五人，共縈儒素家尚貧。", "雖然廩餼各不一，就中總免拘常倫。", "長兄年少曾落托，拔劒沙場隨衛霍。", "口裏雖譚周孔文，懷中不舍孫吳略。", "次兄一生能苦節，夏聚流螢冬映雪。", "非論疾惡志如霜，更覺臨泉心似鐵。", "第三之兄更奇異，昂昂獨負青雲志。", "下看金玉不如泥，肯道王侯身可貴。", "却愁清逸不干時，高蹤大器無人知。", "倘逢感激許然諾，必能萬古留清規。", "念爾年來方二十，夙夜孜孜能獨立。", "卷中筆落星漢搖，洞裏丹靈鬼神泣。", "嗟余流浪心最狂，十年學劒逢時康。", "心中不解事拘束，世間談笑多相妨。"]'),
('8f00a135-544d-4360-9988-a8bea3fe943a','留別南溪二首 一','李渤','唐','唐诗','tang','','[]','常歎春泉去不回，我今此去更難來。',32,'全唐诗/poet.tang.25000.json','["常歎春泉去不回，我今此去更難來。", "欲知別後留情處，手種巖花次第開。"]'),
('10719e77-ef12-475d-9f69-be8809c12649','留別南溪二首 二','李渤','唐','唐诗','tang','','[]','如雲不厭蒼梧遠，似鴈逢春又北歸。',32,'全唐诗/poet.tang.25000.json','["如雲不厭蒼梧遠，似鴈逢春又北歸。", "惟有隱山溪上月，年年相望兩依依。"]'),
('770594bc-7922-4ac1-b7b6-38f972d20ae1','桂林歎鴈','李渤','唐','唐诗','tang','','[]','三朝四黜倦遐征，往復皆愁萬里程。',32,'全唐诗/poet.tang.25000.json','["三朝四黜倦遐征，往復皆愁萬里程。", "爾解分飛却回去，我方從此向南行。"]'),
('cc67ec48-0190-4d7b-8486-b1fca790b357','享惠昭太子廟樂章','孟簡','唐','唐诗','tang','','[]','喧喧金石容既缺，肅肅羽駕就行列。',32,'全唐诗/poet.tang.25000.json','["喧喧金石容既缺，肅肅羽駕就行列。", "緱山遺響昔所聞，廟庭進旅今攸設。"]'),
('20bd82ef-4cd6-4bb0-8729-cb29b5d04157','擬古','孟簡','唐','唐诗','tang','','[]','劒客不誇貌，主人知此心。',48,'全唐诗/poet.tang.25000.json','["劒客不誇貌，主人知此心。", "但營纖毫義，肯計千萬金。", "勇發看鷙擊，憤來聽虎吟。", "平生貴酬德，刃敵無幽深。"]'),
('3f780230-4ba7-484e-8614-400c6ca4e19d','詠歐陽行周事','孟簡','唐','唐诗','tang','','[]','有客西北逐，驅馬次太原。',288,'全唐诗/poet.tang.25000.json','["有客西北逐，驅馬次太原。", "太原有佳人，神豔照行雲。", "座上轉橫波，流光注夫君。", "夫君意蕩漾，即日相交歡。", "定情非一詞，結念誓青山。", "生死不變易，中誠無間言。", "此爲太學徒，彼屬北府官。", "中夜欲相從，嚴城限軍門。", "白日欲同居，君畏仁人聞。", "忽如隴頭水，坐作東西分。", "驚離腸千結，滴淚眼雙昏。", "本達京師迴，賀期相追攀。", "宿約始乖阻，彼憂已纏緜。", "高髻若黃鸝，危鬢如玉蟬。", "纖手自整理，剪刀斷其根。", "柔情託侍兒，爲我遺所歡。", "所歡使者來，侍兒因復前。", "抆淚取遺寄，深誠祈爲傳。", "封來贈君子，願言慰窮泉。", "使者迴復命，遲遲蓄悲酸。", "詹生喜言旋，倒屨走迎門。", "長跪聽未畢，驚傷涕漣漣。", "不飲亦不食，哀心百千端。", "襟情一夕空，精爽旦日殘。"]'),
('788adf7b-78dd-4750-81ad-cd59c871a18e','惜分陰','孟簡','唐','唐诗','tang','','[]','業廣因功苦，拳拳志士心。',72,'全唐诗/poet.tang.25000.json','["業廣因功苦，拳拳志士心。", "九流難酌挹，四海易消沉。", "對景嗟移晷，窺園詎改陰。", "三冬勞聚學，駟景重兼金。", "刺股情方勵，偷光思益深。", "再中如可冀，終嗣絕編音。"]'),
('5727b7ac-a026-4b83-bb4b-b8fe0706636d','嘉禾合穎','孟簡','唐','唐诗','tang','','[]','玉燭將成歲，封人亦自歌。',72,'全唐诗/poet.tang.25000.json','["玉燭將成歲，封人亦自歌。", "八方霑聖澤，異畝發嘉禾。", "共秀芳何遠，連莖瑞且多。", "穎低甘露滴，影亂惠風過。", "表稔由神化，爲祥識氣和。", "因知興嗣歲，王道舊無頗。"]'),
('f7f4ec54-5d81-4fd5-8eef-abf0908ed971','賦得亞父碎玉斗','孟簡','唐','唐诗','tang','','[]','獻謀既我違，積憤從心痗。',72,'全唐诗/poet.tang.25000.json','["獻謀既我違，積憤從心痗。", "鴻門入已迫，赤帝時潛退。", "寶位方苦競，玉斗何情愛。", "猶看虹氣凝，詎惜冰姿碎。", "而嗟大事返，當起千里悔。", "誰爲西楚王，坐見東城潰。"]'),
('a4c79c77-63ae-4bf2-9f93-5c7132301dd5','酬施先輩','孟簡','唐','唐诗','tang','','[]','襄陽才子得聲多，四海皆傳古鏡歌。',34,'全唐诗/poet.tang.25000.json','["襄陽才子得聲多，四海皆傳古鏡歌。", "樂府正聲三百首，[梨]園新入教青娥。"]'),
('66e31443-c3ec-4c2a-8c39-bdb2d589aa29','寄李十員外','王仲舒','唐','唐诗','tang','','[]','百丈懸泉舊臥龍，欲將肝膽佐時雍。',32,'全唐诗/poet.tang.25000.json','["百丈懸泉舊臥龍，欲將肝膽佐時雍。", "惟愁又入煙霞去，知在廬峰第幾重。"]'),
('162eb552-a496-4979-87e2-e441847d4e6f','訪羊尊師','孫革','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u7edd\u53e5", "\u5199\u4eba", "\u5bfb\u8bbf"]','松下問童子，言師採藥去。',24,'全唐诗/poet.tang.25000.json','["松下問童子，言師採藥去。", "只在此山中，雲深不知處。"]'),
('17508318-e5f7-487d-8087-88637ee17c96','晚眺','汪萬於','唐','唐诗','tang','','[]','杖策倚柴門，泉聲隔岸聞。',48,'全唐诗/poet.tang.25000.json','["杖策倚柴門，泉聲隔岸聞。", "夕陽諸嶺出，晴雪萬山分。", "靜對豺狼窟，幽觀鹿豕羣。", "今宵寒月近，東北埽浮雲。"]'),
('250fab5b-4a5c-47bd-8ef0-d9d82e14b16b','亞父碎玉斗','何儒亮','唐','唐诗','tang','','[]','嬴女昔解網，楚王有遺躅。',72,'全唐诗/poet.tang.25000.json','["嬴女昔解網，楚王有遺躅。", "破關既定秦，碎首聞獻玉。", "貞姿應刃散，清響因風續。", "匪狥切泥功，將明懷璧辱。", "莫量漢祖德，空受項君勗。", "事去見前心，千秋渭水綠。"]'),
('6adbaba6-15ae-4ed1-96b2-fd45c5d18d23','贈毛仙翁','李宗閔','唐','唐诗','tang','','[]','不知仙客占青春，肌骨纔教稱兩旬。',64,'全唐诗/poet.tang.25000.json','["不知仙客占青春，肌骨纔教稱兩旬。", "俗眼暫驚相見日，疑心未測幾時人。", "閑推甲子經何代，笑說浮生老此身。", "殘藥儻能沾朽質，願將霄漢永爲鄰。"]'),
('e4545449-1757-4265-96bb-8fb65870b953','池州夫子廟麟臺','韋表微','唐','唐诗','tang','','[]','二儀既閉，三象乃乖。',200,'全唐诗/poet.tang.25000.json','["二儀既閉，三象乃乖。", "聖道埋鬱，人心不開。", "上無文武，下有定哀。", "吁嗟麟兮，孰爲來哉。", "周雖不綱，孔實嗣聖。", "詩書既刪，禮樂大定。", "勸善懲惡，姦邪乃正。", "吁嗟麟兮，克昭符命。", "聖與時合，化行位尊。", "苟或乖戾，身窮道存。", "於昭魯邑，棲遲孔門。", "吁嗟麟兮，孰知其仁。", "運極數殘，德至時否。", "楚國寖廣，秦封益侈。", "牆仞迫阨，崎嶇闕里。", "吁嗟麟兮，靡有攸止。", "世治則麟，世亂則麕。", "出非其時，麋鹿同羣。", "孔不自聖，麟不自祥。", "吁嗟麟兮，天何所亡。"]'),
('79e46a04-dba5-4ecb-952f-416ed2cd527c','送馬向入蜀','徐凝','唐','唐诗','tang','','[]','遊子出咸京，巴山萬里程。',48,'全唐诗/poet.tang.25000.json','["遊子出咸京，巴山萬里程。", "白雲連鳥道，青壁遰猨聲。", "雨雪經泥坂，煙花望錦城。", "工文人共許，應紀蜀中行。"]'),
('991d5c5b-acb7-43c9-8389-24e4e32c1c05','送李補闕歸朝','徐凝','唐','唐诗','tang','','[]','駟馬歸咸秦，雙鳧出海門。',48,'全唐诗/poet.tang.25000.json','["駟馬歸咸秦，雙鳧出海門。", "還從清切禁，再沐聖明恩。", "禮樂中朝貴，文章大雅存。", "江湖多放逸，獻替欲誰論。"]'),
('c2c273aa-9617-4100-bbca-193f58f31d5f','送日本使還','徐凝','唐','唐诗','tang','','[]','絕國將無外，扶桑更有東。',72,'全唐诗/poet.tang.25000.json','["絕國將無外，扶桑更有東。", "來朝逢聖日，歸去及秋風。", "夜泛潮迴際，晨征蒼莽中。", "鯨波騰水府，蜃氣壯仙宮。", "天眷何期遠，王文久已同。", "相望杳不見，離恨托飛鴻。"]'),
('9baec9fe-04ce-4768-a180-4b89e4f877ae','題開元寺牡丹','徐凝','唐','唐诗','tang','','[]','此花南地知難種，慚愧僧閑用意栽。',64,'全唐诗/poet.tang.25000.json','["此花南地知難種，慚愧僧閑用意栽。", "海燕解憐頻睥睨，胡蜂未識更徘徊。", "虛生芍藥徒勞妒，羞殺玫瑰不敢開。", "惟有數苞紅蕚在，含芳只待舍人來。"]'),
('55d2348a-a37d-4823-924a-076e72e86451','香爐峰','徐凝','唐','唐诗','tang','','[]','香爐一峰絕，頂在寺門前。',24,'全唐诗/poet.tang.25000.json','["香爐一峰絕，頂在寺門前。", "盡是玲瓏石，時生旦暮煙。"]'),
('f17ef0a8-ab13-40ad-8372-77ca7ed74d98','白銅鞮','徐凝','唐','唐诗','tang','','[]','騕褭錦障泥，樓頭日又西。',24,'全唐诗/poet.tang.25000.json','["騕褭錦障泥，樓頭日又西。", "留歡住不住，素齒白銅鞮。"]'),
('b5ab2b31-9c18-457b-909b-17a6581d1fbd','楊叛兒','徐凝','唐','唐诗','tang','','[]','哀怨楊叛兒，駘蕩郎知否。',24,'全唐诗/poet.tang.25000.json','["哀怨楊叛兒，駘蕩郎知否。", "香死博山爐，煙生白門柳。"]'),
('f2b846b5-590c-4b5f-b207-b047060fe574','春寒','徐凝','唐','唐诗','tang','','[]','亂雪從教舞，回風任聽吹。',24,'全唐诗/poet.tang.25000.json','["亂雪從教舞，回風任聽吹。", "春寒能作底，已被柳條欺。"]'),
('d346c4dc-4c39-45bc-ac89-33f0a917781e','廬山獨夜','徐凝','唐','唐诗','tang','','["\u5e90\u5c71"]','寒空五老雪，斜月九江雲。',24,'全唐诗/poet.tang.25000.json','["寒空五老雪，斜月九江雲。", "鐘聲知何處，蒼蒼樹裏聞。"]'),
