('fa7bf5a7-cb56-4556-82d3-ec722530bb99','翫花五首 四','徐凝','唐','唐诗','tang','','[]','誰家躑躅青林裏，半見殷花燄燄枝。',32,'全唐诗/poet.tang.25000.json','["誰家躑躅青林裏，半見殷花燄燄枝。", "憶得倡樓人送客，深紅衫子影門時。"]'),
('566a30d5-2bb2-4cc4-95c0-babac12c7f99','翫花五首 五','徐凝','唐','唐诗','tang','','[]','花到薔薇明豔絕，燕支顆破麥風秋。',32,'全唐诗/poet.tang.25000.json','["花到薔薇明豔絕，燕支顆破麥風秋。", "一番弄色一番退，小婦輕妝大婦愁。"]'),
('37e22d3d-2784-4bc4-bcc9-6984dc6f668b','長慶春','徐凝','唐','唐诗','tang','','[]','山頭水色薄籠煙，久客新愁長慶年。',32,'全唐诗/poet.tang.25000.json','["山頭水色薄籠煙，久客新愁長慶年。", "身上五勞仍病酒，夭桃窗下背花眠。"]'),
('9ff3b293-afd6-4eef-ad94-aecea2746558','山鷓鴣詞','徐凝','唐','唐诗','tang','','[]','南越嶺頭山鷓鴣，傳是當時守貞女。',32,'全唐诗/poet.tang.25000.json','["南越嶺頭山鷓鴣，傳是當時守貞女。", "化爲飛鳥怨何人，猶有啼聲帶蠻語。"]'),
('9ff7772b-6089-422b-a982-2fc5a9a2508a','鄭女出參丈人詞','徐凝','唐','唐诗','tang','','[]','鳳釵翠翹雙宛轉，出見丈人梳洗晚。',32,'全唐诗/poet.tang.25000.json','["鳳釵翠翹雙宛轉，出見丈人梳洗晚。", "掣曳羅綃跪拜時，柳條無力花枝軟。"]'),
('149a5238-59ef-4501-8e84-eeea990d5962','春雨','徐凝','唐','唐诗','tang','','["\u5199\u96e8", "\u6625\u5929", "\u96e8"]','花時悶見聯綿雨，雲入人家水毀堤。',32,'全唐诗/poet.tang.25000.json','["花時悶見聯綿雨，雲入人家水毀堤。", "昨日春風源上路，可憐紅錦枉拋泥。"]'),
('19b40eb9-9bc0-4e38-861f-87c78dc2b1cc','和白使君木蘭花','徐凝','唐','唐诗','tang','','[]','枝枝轉勢雕弓動，片片搖光玉劍斜。',32,'全唐诗/poet.tang.25000.json','["枝枝轉勢雕弓動，片片搖光玉劍斜。", "見說木蘭征戍女，不知那作酒邊花。"]'),
('2c201a86-27e5-487d-b958-460347483b5f','正月十五夜呈幕中諸公','徐凝','唐','唐诗','tang','','[]','宵遊二萬七千人，獨坐重城圈一身。',32,'全唐诗/poet.tang.25000.json','["宵遊二萬七千人，獨坐重城圈一身。", "步月遊山俱不得，可憐辜負白頭春。"]'),
('16df4f91-7c43-4f97-91da-a45c9521b9ff','樂府新詩','徐凝','唐','唐诗','tang','','[]','一聲盧女十三弦，早嫁城西好少年。',32,'全唐诗/poet.tang.25000.json','["一聲盧女十三弦，早嫁城西好少年。", "不羨越溪歌者苦，采蓮歸去綠窗眠。"]'),
('c0d9fb55-eb6b-4c6a-99b9-1a36b1818155','春陪相公看花宴會二首 一','徐凝','唐','唐诗','tang','','[]','丞相邀歡事事同，玉簫金管咽東風。',32,'全唐诗/poet.tang.25000.json','["丞相邀歡事事同，玉簫金管咽東風。", "百分春酒莫辭醉，明日的無今日紅。"]'),
('485b786c-c2e9-4167-a5de-26b61e3c0aa5','春陪相公看花宴會二首 二','徐凝','唐','唐诗','tang','','[]','木蘭花謝可憐條，遠道音書轉寂寥。',32,'全唐诗/poet.tang.25000.json','["木蘭花謝可憐條，遠道音書轉寂寥。", "春去一年春又盡，幾回空上望江橋。"]'),
('d92a8b79-23d1-42ab-a105-ea4df0edf603','牡丹','徐凝','唐','唐诗','tang','','[]','何人不愛牡丹花，占斷城中好物華。',32,'全唐诗/poet.tang.25000.json','["何人不愛牡丹花，占斷城中好物華。", "疑是洛川神女作，千嬌萬態破朝霞。"]'),
