('60bc0251-0d8a-488b-858c-310f6559d0d0','金谷覽古','徐凝','唐','唐诗','tang','','[]','金谷園中數尺土，問人知是綠珠臺。',32,'全唐诗/poet.tang.25000.json','["金谷園中數尺土，問人知是綠珠臺。", "綠珠歌舞天下絕，唯與石家生禍胎。"]'),
('22362105-f266-4297-b3e9-d54b40adf8f0','上陽紅葉','徐凝','唐','唐诗','tang','','[]','洛下三分紅葉秋，二分翻作上陽愁。',32,'全唐诗/poet.tang.25000.json','["洛下三分紅葉秋，二分翻作上陽愁。", "千聲萬片御溝上，一片出宮何處流。"]'),
('9002272b-b17f-43bc-9b70-715b067e9395','洛城秋砧','徐凝','唐','唐诗','tang','','[]','三川水上秋砧發，五鳳樓前明月新。',32,'全唐诗/poet.tang.25000.json','["三川水上秋砧發，五鳳樓前明月新。", "誰爲秋砧明月夜，洛陽城裏更愁人。"]'),
('f9c40946-0b38-4853-960c-bbe5a15bf403','和川守侍郎緱山題仙廟','徐凝','唐','唐诗','tang','','[]','王子緱山石殿明，白家詩句詠吹笙。',32,'全唐诗/poet.tang.25000.json','["王子緱山石殿明，白家詩句詠吹笙。", "安知散席人間曲，不是寥天鶴上聲。"]'),
('21539a9f-7b53-40d1-a3dc-d37e59b8b9e2','和夜題玉泉寺','徐凝','唐','唐诗','tang','','[]','歲歲雲山玉泉寺，年年車馬洛陽塵。',32,'全唐诗/poet.tang.25000.json','["歲歲雲山玉泉寺，年年車馬洛陽塵。", "風清月冷水邊宿，詩好官高能幾人。"]'),
('08e23f47-af38-4d47-9b66-7fa46d94dca7','和秋遊洛陽','徐凝','唐','唐诗','tang','','[]','洛陽自古多才子，唯愛春風爛漫游。',32,'全唐诗/poet.tang.25000.json','["洛陽自古多才子，唯愛春風爛漫游。", "今到白家詩句出，無人不詠洛陽秋。"]'),
('669c4f14-37d8-4a29-ab94-f560ae8cb25c','和嘲春風','徐凝','唐','唐诗','tang','','[]','源上拂桃燒水發，江邊吹杏暗園開。',32,'全唐诗/poet.tang.25000.json','["源上拂桃燒水發，江邊吹杏暗園開。", "可憐半死龍門樹，懊惱春風作底來。"]'),
('d3e952ab-2299-4e42-a5a8-2f82a8fca5ef','侍郎宅泛池','徐凝','唐','唐诗','tang','','[]','蓮子花邊回竹岸，雞頭葉上盪蘭舟。',32,'全唐诗/poet.tang.25000.json','["蓮子花邊回竹岸，雞頭葉上盪蘭舟。", "誰知洛北朱門裏，便到江南綠水遊。"]'),
('8859a946-777d-439c-a1ac-3af35c59450d','和侍郎邀宿不至','徐凝','唐','唐诗','tang','','[]','蟾蜍有色門應鎖，街鼓無聲夜自深。',32,'全唐诗/poet.tang.25000.json','["蟾蜍有色門應鎖，街鼓無聲夜自深。", "料得白家詩思苦，一篇詩了一彈琴。"]'),
