('d67b0d35-6222-4e56-8dae-63a60504b650','蠻入西川後','徐凝','唐','唐诗','tang','','[]','守隘一夫何處在，長橋萬里只堪傷。',32,'全唐诗/poet.tang.25000.json','["守隘一夫何處在，長橋萬里只堪傷。", "紛紛塞外烏蠻賊，驅盡江頭濯錦娘。"]'),
('277caaef-adac-43db-a554-c183d97cb795','憶紫溪','徐凝','唐','唐诗','tang','','[]','長憶紫溪春欲盡，千巖交映水回斜。',32,'全唐诗/poet.tang.25000.json','["長憶紫溪春欲盡，千巖交映水回斜。", "巖空水滿溪自紫，水態更籠南燭花。"]'),
('0426d884-3f0f-41ca-9b4f-7c7f4cf484fe','誇紅槿','徐凝','唐','唐诗','tang','','[]','誰道槿花生感促，可憐相計半年紅。',32,'全唐诗/poet.tang.25000.json','["誰道槿花生感促，可憐相計半年紅。", "何如桃李無多少，併打千枝一夜風。"]'),
('c5c2c891-798e-4c88-8fad-175f525eb389','題縉雲山鼎池二首 一','徐凝','唐','唐诗','tang','','[]','黃帝旌旗去不回，空餘片石碧崔嵬。',32,'全唐诗/poet.tang.25000.json','["黃帝旌旗去不回，空餘片石碧崔嵬。", "有時風卷鼎湖浪，散作晴天雨點來。"]'),
('df8e3b6a-70d8-4df8-ad83-a44cc7c24069','題縉雲山鼎池二首 二','徐凝','唐','唐诗','tang','','[]','天地茫茫成古今，仙都凡有幾人尋。',32,'全唐诗/poet.tang.25000.json','["天地茫茫成古今，仙都凡有幾人尋。", "到來唯見山高下，只是不知湖淺深。"]'),
('4d73b24b-e146-42ff-b054-a36690c29a0c','宿冽上人房','徐凝','唐','唐诗','tang','','[]','浮生不定若蓬飄，林下真僧偶見招。',32,'全唐诗/poet.tang.25000.json','["浮生不定若蓬飄，林下真僧偶見招。", "覺後始知身是夢，更聞寒雨滴芭蕉。"]'),
('8dfd661e-00e1-4cef-b3bc-923559cf6c66','汴河覽古','徐凝','唐','唐诗','tang','','[]','煬帝龍舟向此行，三千宮女采橈輕。',32,'全唐诗/poet.tang.25000.json','["煬帝龍舟向此行，三千宮女采橈輕。", "渡河不似如今唱，爲是楊家怨思聲。"]'),
('1da1fa92-587f-4cf1-aecb-efe1ed5b1dff','柬白丈人','徐凝','唐','唐诗','tang','','[]','昔時丈人鬢髮白，千年松下鋤茯苓。',32,'全唐诗/poet.tang.25000.json','["昔時丈人鬢髮白，千年松下鋤茯苓。", "今來見此松樹死，丈人斬新鬢髮青。"]'),
('0c56b37d-8d80-45f4-a649-0ae760b624cf','覽鏡詞','徐凝','唐','唐诗','tang','','[]','寶鏡磨來寒水清，青衣把就綠窗明。',32,'全唐诗/poet.tang.25000.json','["寶鏡磨來寒水清，青衣把就綠窗明。", "潘郎懊惱新秋髮，拔却一莖生兩莖。"]'),
('16da5308-d23a-40e5-8ac8-c8d2ac0fdb80','寄玄陽先生','徐凝','唐','唐诗','tang','','[]','不能相見見人傳，{山瞿}岸山中岱岸邊。',35,'全唐诗/poet.tang.25000.json','["不能相見見人傳，{山瞿}岸山中岱岸邊。", "顏貌只如三二十，道年三百亦藏年。"]'),
('d5bb6dd4-c1d1-4aad-8b69-c2dfc3fa774f','白人','徐凝','唐','唐诗','tang','','[]','煖風入煙花漠漠，白人梳洗尋常薄。',32,'全唐诗/poet.tang.25000.json','["煖風入煙花漠漠，白人梳洗尋常薄。", "泥郎爲插瓏璁釵，爭教一朵牙雲落。"]'),
('234a70e6-2a97-4e0d-95e8-ef22717d66dd','奉酬元相公上元','徐凝','唐','唐诗','tang','','[]','出擁樓船千萬人，入爲台輔九霄身。',32,'全唐诗/poet.tang.25000.json','["出擁樓船千萬人，入爲台輔九霄身。", "如何更羨看燈夜，曾見宮花拂面春。"]'),
('faf3eb3d-1190-4660-86e7-590795636a93','奉和鸚鵡','徐凝','唐','唐诗','tang','','[]','毛羽曾經翦處殘，學人言語道暄寒。',32,'全唐诗/poet.tang.25000.json','["毛羽曾經翦處殘，學人言語道暄寒。", "任饒長被金籠闔，也免栖飛雨雪難。"]'),
('ecbc2667-468b-4189-9f75-5f622d8ebb73','將至妙喜寺','徐凝','唐','唐诗','tang','','[]','清風嫋嫋越水陂，遠樹蒼蒼妙喜寺。',32,'全唐诗/poet.tang.25000.json','["清風嫋嫋越水陂，遠樹蒼蒼妙喜寺。", "自有車輪與馬蹄，未曾到此波心地。"]'),
('2c8d2d77-b702-4179-bcdc-1245c3be8b00','紅蕉','徐凝','唐','唐诗','tang','','[]','紅蕉曾到嶺南看，校小芭蕉幾一般。',32,'全唐诗/poet.tang.25000.json','["紅蕉曾到嶺南看，校小芭蕉幾一般。", "差是斜刀翦紅絹，卷來開去葉中安。"]'),
('603f9c15-b1eb-48c0-b0e2-f04a2b1ca3ff','見少室','徐凝','唐','唐诗','tang','','[]','適我一簞孤客性，問人三十六峰名。',32,'全唐诗/poet.tang.25000.json','["適我一簞孤客性，問人三十六峰名。", "青雲無忘白雲在，便可嵩陽老此生。"]'),
('ad1855d5-fe8f-4ff7-980c-4e0cfe1e9424','語兒見新月','徐凝','唐','唐诗','tang','','[]','幾處天邊見新月，經過草市憶西施。',32,'全唐诗/poet.tang.25000.json','["幾處天邊見新月，經過草市憶西施。", "娟娟水宿初三夜，曾伴愁蛾到語兒。"]'),
('4ef4711a-4f03-4edb-abbd-0ce9534db931','回施先輩見寄新詩二首 一','徐凝','唐','唐诗','tang','','[]','九幽仙子西山卷，讀了絛繩繫又開。',32,'全唐诗/poet.tang.25000.json','["九幽仙子西山卷，讀了絛繩繫又開。", "此卷玉清宮裏少，曾尋真誥讀詩來。"]'),
('402fc29f-0cf9-43b2-8d03-7961e8327110','回施先輩見寄新詩二首 二','徐凝','唐','唐诗','tang','','[]','紫河車裏丹成也，皁莢枝頭早晚飛。',34,'全唐诗/poet.tang.25000.json','["紫河車裏丹成也，皁莢枝頭早晚飛。", "料得仙宮列仙[籍]，如君進士出身稀。"]'),
('27c2fa43-3722-428f-a7ac-0ac960801c08','送沈亞之赴郢掾','徐凝','唐','唐诗','tang','','[]','千萬乘驄沈司戶，不須惆悵郢中遊。',32,'全唐诗/poet.tang.25000.json','["千萬乘驄沈司戶，不須惆悵郢中遊。", "幾年白雪無人唱，今日唯君上雪樓。"]'),
('824804d2-ec32-44ac-9f21-94dcbdb6023b','答白公','徐凝','唐','唐诗','tang','','[]','高景爭來草木頭，一生心事酒前休。',32,'全唐诗/poet.tang.25000.json','["高景爭來草木頭，一生心事酒前休。", "山公自是仙人侶，攜手醉登城上樓。"]'),
('a91e04b7-d45c-4a8c-9305-6ddb40a840eb','句','徐凝','唐','唐诗','tang','','[]','青山舊路在，白首醉還鄉。',60,'全唐诗/poet.tang.25000.json','["青山舊路在，白首醉還鄉。", "試到第三橋，便入千頃花。", "亂後見淮水，歸心忽迢遙。", "乍疑鯨噴浪，忽似鷁凌風。", "呀呷汀洲動，喧闐里巷空。"]'),
('e7484e6e-8708-4236-824f-717093e5f953','奉和聖製南郊禮畢詩','李德裕','唐','唐诗','tang','','[]','磬管歌大呂，冕裘旅天神。',72,'全唐诗/poet.tang.25000.json','["磬管歌大呂，冕裘旅天神。", "燒蕭闢閶闔，祈穀爲蒸人。", "羽旗灑輕雪，麥隴含陽春。", "昌運歲今會，王猷從此新。", "三臣皆就日，萬國望如雲。", "仁壽信非遠，羣生方在鈞。"]'),
('7ac67f4d-49cf-4ccc-9bfe-d34d96095800','郊壇回輿中書二相公蒙聖慈召至御馬前仰感恩遇輒書是詩兼呈二相公','李德裕','唐','唐诗','tang','','[]','七萃和鑾動，三條葆吹回。',48,'全唐诗/poet.tang.25000.json','["七萃和鑾動，三條葆吹回。", "相星環日道，蒼馬近龍媒。", "咫尺天顏接，光華喜氣來。", "自慙衰且病，無以效涓埃。"]'),
('14fc8546-d18f-401c-833d-39f1a9943348','寒食日三殿侍宴奉進詩一首','李德裕','唐','唐诗','tang','','[]','宛轉龍歌節，參差燕羽高。',240,'全唐诗/poet.tang.25000.json','["宛轉龍歌節，參差燕羽高。", "風光搖禁柳，霽色暖宮桃。", "春露明仙掌，晨霞照御袍。", "雪凝陳組練，林植聳干旄。", "廣樂初蹌鳳，神山欲抃鼇。", "鳴笳朱鷺起，疊鼓紫騂豪。", "象舞嚴金鎧，豐歌耀寶刀。", "不勞孫子法，自得太公韜。", "分席羅玄冕，行觴舉綠醪。", "彀中時落羽，橦末乍升猱。", "瑞景開陰翳，薰風散鬱陶。", "天顏歡益醉，臣節勁尤高。", "楛矢方來貢，雕弓已載櫜。", "英威揚絕漠，神算盡臨洮。", "赤縣陽和布，蒼生雨露膏。", "野平惟有麥，田闢久無蒿。", "祿秩榮三事，功勳乏一毫。", "寢謀慙汲黯，秉羽貴孫敖。", "煥若遊玄圃，歡如享太牢。", "輕生何以報，祗自比鴻毛。"]'),
('3c3ce12a-2949-4b1a-b272-a128db95d641','雨中自秘書省訪王三侍御知早入朝便入集賢侍御任集賢校書及升柏臺又與秘閣相對同院張學士亦余特厚故以詩贈之','李德裕','唐','唐诗','tang','','[]','共憐獨鶴青霞姿，瀛洲故山歸已遲。',144,'全唐诗/poet.tang.25000.json','["共憐獨鶴青霞姿，瀛洲故山歸已遲。", "仁者焉能效鷙鶚，飛舞自合追長離。", "梧桐迥齊鳷鵲觀，煙雨屢拂蛟龍旗。", "鴻鴈衝颷去不盡，寒聲晚下天泉池。", "顧我蓬萊靜無事，玉版寶書藏衆瑞。", "青編盡以汲冢來，科斗皆從魯室至。", "金門待詔何逍遙，名儒早問張子僑。", "王褒軼材晚始入，宮女已能傳洞簫。", "應令栢臺長對戶，別來相望獨寥寥。"]'),
('d00f372a-c0a8-400f-b0a5-31ec29404d91','奉和太原張尚書山亭書懷','李德裕','唐','唐诗','tang','','[]','巖石在朱戶，風泉當翠樓。',48,'全唐诗/poet.tang.25000.json','["巖石在朱戶，風泉當翠樓。", "始知峴亭賞，難與清暉留。", "餘景淡將夕，凝嵐輕欲收。", "東山有歸志，方接赤松遊。"]'),
('f835c483-7870-4846-b4c7-138ec4af57d1','奉和韋侍御陪相公遊開義五言六韻','李德裕','唐','唐诗','tang','','[]','羊公追勝概，茲地暫逍遙。',72,'全唐诗/poet.tang.25000.json','["羊公追勝概，茲地暫逍遙。", "風景同南峴，丹青見北朝。", "石渠清夏氣，高樹激鮮飆。", "念法珍禽集，聞輕醉象調。", "偶分甘露味，偏覺衆香饒。", "爲問毘城內，餘薰幾日銷。"]'),
('c7bd2528-bf9f-42c9-b2c8-ffc62fbb28b1','贈圓明上人','李德裕','唐','唐诗','tang','','[]','遠公說易長松下，龍樹雙輕海藏中。',32,'全唐诗/poet.tang.25000.json','["遠公說易長松下，龍樹雙輕海藏中。", "今日導師聞佛慧，始知前路化成空。"]'),
('7be95130-83a9-468e-8ae0-358cacda75c7','贈奉律上人','李德裕','唐','唐诗','tang','','[]','知君學地厭多聞，廣渡羣生出世氛。',32,'全唐诗/poet.tang.25000.json','["知君學地厭多聞，廣渡羣生出世氛。", "飯色不應殊寶器，樹香皆遣入禪薰。"]'),
('6b226b9c-55ba-4bac-ba7c-cd98fea6401e','戲贈慎微寺主道安上座三僧正','李德裕','唐','唐诗','tang','','[]','甘露灑空惟一味，旃檀移植自成薰。',32,'全唐诗/poet.tang.25000.json','["甘露灑空惟一味，旃檀移植自成薰。", "遙知暢獻分南北，應用調柔致六羣。"]'),
('e0bfe51e-dd19-4028-adb7-fc4cf72a6c51','長安秋夜','李德裕','唐','唐诗','tang','','["\u53d9\u4e8b", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','內宮傳詔問戎機，載筆金鑾夜始歸。',32,'全唐诗/poet.tang.25000.json','["內宮傳詔問戎機，載筆金鑾夜始歸。", "萬戶千門皆寂寂，月中清露點朝衣。"]'),
('3ec5456d-2dea-4968-9411-4c27429e5126','清冷池懷古','李德裕','唐','唐诗','tang','','[]','區囿三百里，常聞駟馬來。',96,'全唐诗/poet.tang.25000.json','["區囿三百里，常聞駟馬來。", "旌旗朝甬道，簫鼓燕平臺。", "追昔賦文雅，從容遊上才。", "竹園秋水淨，風苑雪煙開。", "牛禍釁將發，羊孫謀始回。", "袁絲徒伏劒，長孺欲成灰。", "興廢由所感，湮淪斯可哀。", "空留故池鴈，刷羽尚徘徊。"]'),
('8b41c002-e220-45f6-b816-c8f499e39622','述夢詩四十韻','李德裕','唐','唐诗','tang','','[]','賦命誠非薄，良時幸已遭。',299,'全唐诗/poet.tang.25000.json','["賦命誠非薄，良時幸已遭。", "君當堯舜日，官接鳳皇曹。", "目睇煙霄闊，心驚羽翼高。", "椅梧連鶴禁，壀堄接龍韜。", "我后憐詞客，吾僚並雋髦。", "著書同陸賈，待詔比王褒。", "重價連懸璧，英詞淬寶刀。", "泉流初落澗，露滴更濡毫。", "赤豹欣來獻，彤弓喜暫櫜非煙含瑞氣，馴雉潔霜毛。", "靜室便幽獨，虛樓散鬱陶。", "花光晨豔豔，松韻晚騷騷。", "畫壁看飛鶴，仙圖見巨鼇。", "倚簷陰藥樹，落格蔓蒲桃。", "荷靜蓬池鱠，冰寒郢水醪。", "荔枝來自遠，盧橘賜仍叨。", "麝氣隨蘭澤，霜華入杏膏。", "恩光惟覺重，攜挈未爲勞。", "夕閱梨園騎，宵聞禁杖獒。", "扇回交彩翟，鵰起颺銀絛。", "轡待袁絲攬，書期蜀客操。", "盡規常謇謇，退食尚忉忉。", "龜顧垂金鈕，鸞飛曳錦袍。", "御溝楊柳弱，天廐驌驦豪。", "屢換青春直，閑隨上苑遨。"]'),
('2f3433fb-a4d9-4cf4-b96c-ba047505806c','招隱山觀玉蘂樹戲書即事奉寄江西沈大夫閣老','李德裕','唐','唐诗','tang','','[]','玉蘂天中樹，金閨昔共窺。',47,'全唐诗/poet.tang.25000.json','["玉蘂天中樹，金閨昔共窺。", "落英閑舞雪，密葉乍低帷舊賞煙霄遠，前歡歲月移。", "今來想顏色，還似憶瓊枝。"]'),
('e5fa2d70-5a7a-453f-9edf-b05b686c70de','寄題惠林李侍郎舊館','李德裕','唐','唐诗','tang','','[]','棟宇非吾室，煙山是我鄰。',48,'全唐诗/poet.tang.25000.json','["棟宇非吾室，煙山是我鄰。", "百齡惟待盡，一世樂長貧。", "半壁懸秋日，空林滿夕塵。", "祗應雙鶴弔，松路更無人。"]'),
('27bf86f8-7963-49d9-ac77-d2b4eee63446','寄茅山孫鍊師','李德裕','唐','唐诗','tang','','[]','何地最翛然，華陽第八天。',48,'全唐诗/poet.tang.25000.json','["何地最翛然，華陽第八天。", "松風清有露，蘿月淨無煙。", "乍警瑤壇鶴，時嘶玉樹蟬。", "欲馳千里戀，惟有鳳門泉。"]'),
('1775f8d0-16e3-4beb-841a-385547a9666b','又二絕 一','李德裕','唐','唐诗','tang','','[]','石上谿蓀發紫茸，碧山幽藹水溶溶。',32,'全唐诗/poet.tang.25000.json','["石上谿蓀發紫茸，碧山幽藹水溶溶。", "菖花定是無人見，春日惟應羽客逢。"]'),
('5fca3e65-4f5f-4e3f-a169-28c74a442701','又二絕 二','李德裕','唐','唐诗','tang','','[]','獨尋蘭渚翫遲暉，閑倚松窗望翠微。',32,'全唐诗/poet.tang.25000.json','["獨尋蘭渚翫遲暉，閑倚松窗望翠微。", "遙想春山明月曙，玉壇清磬步虛歸。"]'),
('e289d837-64ea-4881-9667-fca32ca4a161','題奇石','李德裕','唐','唐诗','tang','','[]','蘊玉抱清輝，閑庭日瀟灑。',24,'全唐诗/poet.tang.25000.json','["蘊玉抱清輝，閑庭日瀟灑。", "塊然天地間，自是孤生者。"]'),
('e6a6ad0f-3a83-4774-a906-ebb43f7ac5cf','送張中丞入臺從事','李德裕','唐','唐诗','tang','','[]','驛騎朝天去，江城睠闕深。',48,'全唐诗/poet.tang.25000.json','["驛騎朝天去，江城睠闕深。", "夜珠先去握，芳桂乍辭陰。", "澤國三千里，羈孤萬感心。", "自嗟文廢久，此曲爲盧諶。"]'),
('4531cf45-2116-4c73-8bae-16f6413418d7','懷京國','李德裕','唐','唐诗','tang','','[]','海上東風犯雪來，臘前先折鏡湖梅。',32,'全唐诗/poet.tang.25000.json','["海上東風犯雪來，臘前先折鏡湖梅。", "遙思禁苑青春夜，坐待宮人畫詔迴。"]'),
('70faba81-1c92-4ffc-84bc-f354c0326aff','追和太師顏公同清遠道士遊虎丘寺','李德裕','唐','唐诗','tang','','[]','茂苑有靈峰，嗟余未遊觀。',168,'全唐诗/poet.tang.25000.json','["茂苑有靈峰，嗟余未遊觀。", "藏山半平陸，壞谷爲高岸。", "岡繞數仞牆，巖潛千丈幹。", "乃知造化意，回斡資奇玩。", "鏐騰昔虎踞，劒沒嘗龍煥。", "潭黛入海底，崟岑聳霄半。", "層巒未升日，哀狖寧知旦。", "綠篠夏凝陰，碧林秋不換。", "冥搜既窈窕，回望何蕭散。", "川晴嵐氣收，江春雜英亂。", "逸人綴清藻，前哲留篇翰。", "共扣哀玉音，皆舒文繡段。", "難追彥回賞，徒起興公歎。", "一夕如再升，含毫星斗爛。"]'),
('00eca35e-b0b6-432a-a14e-2d28ca08e3ca','東郡懷古二首 王京兆','李德裕','唐','唐诗','tang','','[]','河水昔將決，衝波溢川潯。',120,'全唐诗/poet.tang.25000.json','["河水昔將決，衝波溢川潯。", "崢嶸金堤下，噴薄風雷音。", "投馬災未弭，爲魚歎方深。", "惟公執珪璧，誓與身俱沈。", "誠信不虛發，神明宜爾臨。", "湍流自此回，咫尺焉能侵。", "逮我守東郡，悽然懷所欽。", "雖非識君面，自謂知君心。", "意氣苟相合，神明無古今。", "登城見遺廟，日夕空悲吟。"]'),
('c3870f0a-f269-4fe8-a0ce-ea9f78147651','東郡懷古二首 陽給事','李德裕','唐','唐诗','tang','','[]','宋氏遠家左，豺狼滿中州。',120,'全唐诗/poet.tang.25000.json','["宋氏遠家左，豺狼滿中州。", "陽君守滑臺，終古垂英猷。", "數仞城既毀，萬夫心莫留。", "跳身入飛鏃，免胄臨霜矛。", "畢命在旗下，僵尸橫道周。", "義風激河汴，壯氣淪山丘。", "嗟爾抱忠烈，古來誰與儔。", "就烹感漢使，握節悲陽秋。", "顏子綴清藻，鏗然如素璆。", "徘徊望故壘，尚想精魂遊。"]'),
('4cd6914d-7644-4e9e-b758-09def40c83c0','秋日登郡樓望贊皇山感而成詠','李德裕','唐','唐诗','tang','','[]','昔人懷井邑，爲有挂冠期。',48,'全唐诗/poet.tang.25000.json','["昔人懷井邑，爲有挂冠期。", "顧我飄蓬者，長隨泛梗移。", "越吟因病感，潘鬢入秋悲。", "北指邯鄲道，應無歸去期。"]'),
('6e8e68b8-2bc4-4ec7-aa42-bb030326e72a','雨後淨望河西連山愴然成詠','李德裕','唐','唐诗','tang','','[]','宿雨初收晚吹繁，秋光極目自銷魂。',64,'全唐诗/poet.tang.25000.json','["宿雨初收晚吹繁，秋光極目自銷魂。", "煙山北下歸遼海，鴻鴈南飛出薊門。", "只恨無功書史籍，豈悲臨老事戎軒。", "唯懷藥餌蠲衰病，爲惜餘年報主恩。"]'),
('a3af5d50-130f-4e9d-89ef-4538f1ac3fce','秋日美晴郡樓閑眺寄荆南張書記','李德裕','唐','唐诗','tang','','[]','高檻涼風起，清川旭景開。',48,'全唐诗/poet.tang.25000.json','["高檻涼風起，清川旭景開。", "秋聲向野去，爽氣自山來。", "霄外鴻初返，簷間燕已歸。", "不因煙雨夕，何處夢陽臺。"]'),
('3f8f27c5-2e3f-42e7-8238-4be04f1e2849','故人寄茶','李德裕','唐','唐诗','tang','','[]','劒外九華英，緘題下玉京。',72,'全唐诗/poet.tang.25000.json','["劒外九華英，緘題下玉京。", "開時微月上，碾處亂泉聲。", "半夜邀僧至，孤吟對竹烹。", "碧流霞脚碎，香泛乳花輕。", "六腑睡神去，數朝詩思清。", "其餘不敢費，留伴讀書行。"]'),
('2effbb1c-0785-47f0-8440-43e4c1c893ec','奉送相公十八丈鎮楊州','李德裕','唐','唐诗','tang','','[]','千騎風生大斾舒，春江重到武侯廬。',64,'全唐诗/poet.tang.25000.json','["千騎風生大斾舒，春江重到武侯廬。", "共懸龜印銜新綬，同憶鱣庭訪舊居。", "取履橋邊啼鳥換，釣璜溪畔落花初。", "今來却笑臨邛客，入蜀空馳使者車。"]'),
('b129f88c-34e3-4845-83ab-f077c4adc4c9','題劒門','李德裕','唐','唐诗','tang','','[]','奇峰百仞懸，清眺出嵐煙。',48,'全唐诗/poet.tang.25000.json','["奇峰百仞懸，清眺出嵐煙。", "迥若戈回日，高疑劒倚天。", "參差霞壁聳，合沓翠屏連。", "想是三刀夢，森然在目前。"]');
